-- Schema for Domain: weather | Business: Agriculture | Version: v1_ecm
-- Generated on: 2026-05-01 16:23:40

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`weather` COMMENT 'Captures meteorological and climate data critical to agricultural decision-making including historical and forecast weather station data, precipitation, temperature, humidity, wind, evapotranspiration (ET) calculations, frost/freeze alerts, growing degree day (GDD) accumulations, and climate risk indicators. Integrates with IoT field sensors, DTN weather feeds, WASDE reports, and Climate FieldView. Supports irrigation scheduling, planting windows, spray windows, pest pressure prediction, and crop insurance documentation.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`station` (
    `station_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the weather station master record. Primary key for all downstream observation, forecast, and derived weather product references.',
    `employee_id` BIGINT COMMENT 'Reference to the SAP SuccessFactors employee record of the technician or agronomist responsible for this stations maintenance, calibration scheduling, and data quality oversight.',
    `farm_unit_id` BIGINT COMMENT 'Reference to the farm or agricultural production unit with which this station is primarily associated. Enables linkage of meteorological observations to crop plans, irrigation events, and yield records within the Granular Farm Management and John Deere Operations Center systems.',
    `field_id` BIGINT COMMENT 'Reference to the specific field or land parcel most closely associated with this station. Supports field-level weather data attribution for planting windows, spray windows, and pest pressure prediction in Trimble Ag Software and Climate FieldView.',
    `station_network_id` BIGINT COMMENT 'Identifier assigned by the external data provider network (e.g., DTN network node ID, Climate FieldView station UUID, NOAA COOP network ID). Used for data feed reconciliation and provider-side traceability.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: A weather station belongs to one geographic weather zone; a zone contains many stations. This FK normalizes the zone membership of each station and enables zone-level aggregation of station data. weat',
    `anemometer_height_m` DECIMAL(18,2) COMMENT 'Height above ground level in meters at which the wind speed sensor (anemometer) is mounted. Required for FAO-56 Penman-Monteith reference evapotranspiration (ET) calculations and wind speed standardization to the 2-meter reference height used in irrigation scheduling.',
    `calibration_method` STRING COMMENT 'Method used during the most recent calibration event. Determines the level of measurement traceability and acceptability for regulatory and insurance documentation. NIST-traceable calibration is required for USDA crop insurance documentation.. Valid values are `field_comparison|laboratory|manufacturer_certified|nist_traceable|automated_self_check`',
    `calibration_technician` STRING COMMENT 'Name or identifier of the technician or certified service provider who performed the most recent calibration. Required for audit trail and regulatory documentation under FSMA and USDA crop insurance standards.',
    `calibration_tolerance_pct` DECIMAL(18,2) COMMENT 'Acceptable measurement tolerance threshold expressed as a percentage of full-scale reading, as defined in the stations calibration specification. Used to evaluate pass/fail status during calibration and set the out_of_tolerance_flag.',
    `communication_protocol` STRING COMMENT 'Data transmission protocol used by the station to relay observations to the central data platform. Determines data latency, reliability SLA, and applicable IoT integration configuration in the FMIS. [ENUM-REF-CANDIDATE: cellular_4g|cellular_5g|lora_wan|wifi|satellite|rf_radio|ethernet — promote to reference product]',
    `data_provider` STRING COMMENT 'Organization or platform supplying meteorological data for this station. Determines data licensing, feed format, latency SLA, and applicable data quality standards. Key for WASDE and DTN market data integration traceability. [ENUM-REF-CANDIDATE: dtn|climate_fieldview|on_farm_iot|trimble|granular|noaa|private — promote to reference product]',
    `data_quality_rating` STRING COMMENT 'Enterprise data quality tier assigned to this station based on calibration history, uptime percentage, sensor completeness, and data gap frequency. Gold-rated stations are used for regulatory and insurance submissions; Silver for operational decisions; Bronze for supplemental reference only.. Valid values are `gold|silver|bronze|unrated`',
    `data_transmission_interval_min` STRING COMMENT 'Configured frequency in minutes at which the station transmits observation data to the central platform. Drives data freshness expectations for real-time irrigation scheduling, spray window alerts, and frost/freeze notifications.',
    `decommission_date` DATE COMMENT 'Calendar date on which the weather station was permanently taken out of service. Null for active stations. Used to bound the valid observation record window for historical analysis and regulatory documentation.',
    `elevation_m` DECIMAL(18,2) COMMENT 'Station elevation above mean sea level in meters. Critical for barometric pressure correction, evapotranspiration (ET) calculations, frost/freeze risk modeling, and accurate temperature lapse-rate adjustments in crop protection and irrigation scheduling.',
    `installation_date` DATE COMMENT 'Calendar date on which the weather station was physically installed and commissioned at its current location. Defines the start of the stations valid observation record for historical data analysis and crop insurance documentation.',
    `insurance_eligible_flag` BOOLEAN COMMENT 'Indicates whether this station meets USDA Risk Management Agency (RMA) requirements for use as an approved weather data source in crop insurance loss documentation. Requires current calibration, gold data quality rating, and WMO or NOAA network registration.',
    `iot_device_serial` STRING COMMENT 'Manufacturer serial number of the IoT sensor node hardware for on-farm stations. Used for warranty tracking, firmware update management, and hardware replacement traceability. Null for DTN reference and cooperative network stations.',
    `last_calibration_date` DATE COMMENT 'Date of the most recent completed calibration of the stations primary sensors. Critical for data quality assurance, regulatory documentation under FSMA, and crop insurance measurement accuracy attestation.',
    `last_maintenance_date` DATE COMMENT 'Date of the most recent preventive or corrective maintenance activity performed on the station. Used to schedule next maintenance in SAP PM and assess station reliability for data quality rating.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude of the station in decimal degrees (WGS84 datum), captured via GPS/RTK positioning. Used for GIS spatial analysis in Esri ArcGIS, field-to-station proximity matching, and precision agriculture variable rate application (VRA) zone assignment.',
    `leaf_wetness_sensor_flag` BOOLEAN COMMENT 'Indicates whether this station is equipped with a leaf wetness sensor. Critical for spray window determination (REI compliance), fungal disease pressure modeling under IPM programs, and GLOBALG.A.P. crop protection documentation.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude of the station in decimal degrees (WGS84 datum), captured via GPS/RTK positioning. Used for GIS spatial analysis, field mapping in John Deere Operations Center, and spatial interpolation of weather data across farm units.',
    `manufacturer` STRING COMMENT 'Name of the hardware manufacturer of the weather station or IoT sensor node (e.g., Davis Instruments, Campbell Scientific, Onset HOBO, Pessl Instruments). Used for maintenance scheduling, parts procurement, and calibration procedure selection.',
    `model_number` STRING COMMENT 'Manufacturer model designation of the weather station hardware. Determines applicable calibration procedures, sensor specifications, and maintenance SOPs referenced in SAP PM.',
    `next_calibration_date` DATE COMMENT 'Scheduled date for the next calibration of the stations sensors. Used to trigger maintenance work orders in SAP PM and ensure continuous data quality compliance for regulatory and insurance documentation.',
    `notes` STRING COMMENT 'Free-text field for operational notes, site-specific observations, known data anomalies, or special instructions relevant to this stations operation and data interpretation. Used by field agronomists and data quality teams.',
    `operational_status` STRING COMMENT 'Current lifecycle state of the weather station. Drives data quality flags on all downstream observation records and determines whether the station is included in active irrigation scheduling, spray window, and GDD accumulation calculations.. Valid values are `active|inactive|maintenance|decommissioned|pending_install`',
    `out_of_tolerance_flag` BOOLEAN COMMENT 'Indicates whether the most recent calibration found one or more sensors outside the acceptable tolerance range. When True, downstream observation records from this station are flagged for data quality review and excluded from regulatory and insurance submissions until recalibration is completed.',
    `power_source` STRING COMMENT 'Primary power supply type for the weather station. Determines maintenance requirements, uptime risk profile, and applicable preventive maintenance schedule in SAP PM. Solar and battery stations require periodic battery health checks.. Valid values are `solar|battery|grid|solar_battery_hybrid|wind_solar_hybrid`',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this weather station master record was first created in the enterprise data platform. Supports data lineage, audit trail, and Silver layer ingestion traceability.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this weather station master record. Used for change data capture (CDC) in the Databricks Silver layer pipeline and audit trail compliance.',
    `sensor_inventory` STRING COMMENT 'Comma-separated list of sensor types installed on this station (e.g., temperature,humidity,precipitation,wind_speed,wind_direction,solar_radiation,soil_moisture,leaf_wetness). Defines which observation parameters are available from this station for ET, GDD, and IPM calculations.',
    `soil_moisture_sensor_flag` BOOLEAN COMMENT 'Indicates whether this station includes in-ground soil moisture sensors. Enables direct soil water content measurement for irrigation scheduling decisions and supports NDVI-correlated crop stress analysis.',
    `solar_radiation_sensor_flag` BOOLEAN COMMENT 'Indicates whether this station is equipped with a pyranometer or solar radiation sensor. Required for FAO-56 Penman-Monteith ET calculations; stations without this sensor must use estimated solar radiation from sunshine hours or cloud cover data.',
    `station_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the station, used in field operations, DTN data feeds, Climate FieldView integrations, and regulatory/insurance documentation. Unique across the enterprise station network.. Valid values are `^[A-Z0-9_-]{3,20}$`',
    `station_name` STRING COMMENT 'Human-readable descriptive name for the weather station, typically referencing the associated farm unit, field block, or geographic landmark (e.g., North Creek Field Station - Block 4). Used in reporting, dashboards, and operator interfaces.',
    `station_type` STRING COMMENT 'Classification of the station by its physical deployment and data-provider category. Drives data ingestion pipeline routing and quality thresholds. [ENUM-REF-CANDIDATE: fixed_field|portable_iot|dtn_reference|climate_fieldview|cooperative|airport — promote to reference product if additional types emerge]. Valid values are `fixed_field|portable_iot|dtn_reference|climate_fieldview|cooperative|airport`',
    `temperature_sensor_height_m` DECIMAL(18,2) COMMENT 'Height above ground level in meters at which the temperature and humidity sensors are mounted. Standard WMO siting requires 1.25–2.0 m. Deviations affect GDD accumulation accuracy and frost/freeze alert thresholds.',
    `wmo_station_number` STRING COMMENT 'Official WMO-assigned 5 or 6-digit station identifier for stations registered with the global meteorological network. Null for private on-farm IoT nodes not registered with WMO. Required for NOAA and DTN data feed cross-referencing.. Valid values are `^[0-9]{5,6}$`',
    CONSTRAINT pk_station PRIMARY KEY(`station_id`)
) COMMENT 'Master record for meteorological observation stations including fixed field stations, portable IoT sensor nodes, and DTN network reference points. Stores station identity, GPS/GIS coordinates, elevation, installation date, operational status, data provider (DTN, Climate FieldView, on-farm IoT), associated field or farm unit linkage, and complete sensor/instrument inventory with calibration history (sensor identifier, calibration date, method, pre/post calibration readings, acceptable tolerance range, calibration technician, next scheduled calibration date, out-of-tolerance flag). SSOT for station identity, instrument health, sensor calibration traceability, and data quality assurance referenced by all observation, forecast, and derived weather products. Supports regulatory and insurance documentation of measurement accuracy.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`observation` (
    `observation_id` BIGINT COMMENT 'Unique system-generated identifier for each meteorological observation record. Primary key for the weather observation time-series table in the Silver Layer lakehouse.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or land parcel associated with this observation, enabling field-level weather correlation for irrigation scheduling, spray window determination, and crop insurance documentation.',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor that captured this observation. Links to the station master record for location, calibration, and ownership metadata.',
    `weather_station_id` BIGINT COMMENT 'FK to weather.weather_station.weather_station_id — Every weather observation is captured at a specific station. Without this FK, weather data cannot be attributed to a location — breaking all spatial weather queries and field-level weather correlation',
    `barometric_pressure_hpa` DECIMAL(18,2) COMMENT 'Atmospheric pressure measured during the observation interval, in hectopascals (hPa). Used for weather front detection, storm prediction, and calibration of altitude-adjusted ET calculations. Supports short-term weather forecasting for field operations planning.',
    `created_at` TIMESTAMP COMMENT 'Timestamp when this observation record was first ingested and created in the Silver Layer lakehouse. Used for audit trail, data freshness monitoring, and SLA compliance tracking for weather data feeds.',
    `data_source` STRING COMMENT 'Identifies the originating system or feed that provided this observation record. Supports data lineage, quality weighting, and source reconciliation across IoT field sensors, DTN weather feeds, Climate FieldView integrations, and manual entries.. Valid values are `iot_sensor|weather_station|dtn_feed|climate_fieldview|manual_entry`',
    `dew_point_c` DECIMAL(18,2) COMMENT 'Dew point temperature in degrees Celsius, representing the temperature at which air becomes saturated with moisture. Used for frost risk prediction, fungal disease pressure modeling (e.g., gray mold, downy mildew), and spray window determination under IPM frameworks.',
    `et_mm` DECIMAL(18,2) COMMENT 'Reference evapotranspiration (ET₀) calculated for the observation interval using the FAO-56 Penman-Monteith method, in millimeters. SSOT for irrigation scheduling, water balance modeling, and crop water use estimation. Integrates with Climate FieldView and Granular Farm Management irrigation modules.',
    `frost_alert` BOOLEAN COMMENT 'Boolean flag indicating whether this observation triggered a frost or freeze alert condition (temperature at or below 0°C). Drives automated notifications for frost protection actions (e.g., wind machine activation, irrigation frost protection), crop insurance event documentation, and PHI compliance tracking.',
    `gdd_base10_c` DECIMAL(18,2) COMMENT 'Growing Degree Day (GDD) accumulation for the observation interval using a base temperature of 10°C, calculated as max(0, (temp_max_c + temp_min_c)/2 - 10). Used for crop phenology tracking, pest emergence prediction, and harvest timing optimization. Standard base for corn and many broadacre crops.',
    `interval` STRING COMMENT 'Configured measurement interval for this observation record. Determines the temporal resolution of the time-series data. Supported intervals: 5-minute, 15-minute, hourly, and daily aggregations. Drives GDD and ET calculation granularity.. Valid values are `5min|15min|hourly|daily`',
    `leaf_wetness_hours` DECIMAL(18,2) COMMENT 'Duration of leaf surface wetness during the observation interval, in hours. Critical input for fungal and bacterial disease pressure models under IPM frameworks (e.g., fire blight, late blight, botrytis). Drives spray timing recommendations and PHI (Pre-Harvest Interval) compliance tracking.',
    `observation_status` STRING COMMENT 'Quality lifecycle status of the observation record. Raw records are ingested as-is; validated records have passed QC checks; flagged records have anomalies under review; corrected records have been adjusted; rejected records are excluded from downstream calculations.. Valid values are `raw|validated|flagged|corrected|rejected`',
    `observation_type` STRING COMMENT 'Classifies whether the record represents an instantaneous point reading, an interval average, a daily summary aggregation, or a forecast value ingested from DTN or WASDE feeds. Drives downstream processing logic for GDD and ET calculations.. Valid values are `instantaneous|interval_avg|daily_summary|forecast`',
    `observed_at` TIMESTAMP COMMENT 'ISO 8601 timestamp of when the meteorological measurement was captured at the sensor or station. This is the principal real-world event time used for time-series analysis, GDD accumulation, ET computation, and crop insurance documentation. Stored in yyyy-MM-ddTHH:mm:ss.SSSXXX format.',
    `precipitation_mm` DECIMAL(18,2) COMMENT 'Total liquid precipitation (rainfall) accumulated during the observation interval, in millimeters. Core input for irrigation scheduling, water balance calculations, crop insurance loss documentation, and FSMA water quality compliance tracking.',
    `qc_notes` STRING COMMENT 'Free-text notes from the automated QC process or manual data reviewer describing the reason for a suspect, fail, or estimated quality flag. Supports audit trail requirements for crop insurance documentation and FSMA traceability.',
    `quality_flag` STRING COMMENT 'WMO-aligned quality control flag for the observation record. Pass = all values within expected range; Suspect = one or more values outside climatological bounds but not definitively erroneous; Fail = confirmed erroneous values; Missing = one or more required measurements absent; Estimated = gap-filled using interpolation or neighboring station data.. Valid values are `pass|suspect|fail|missing|estimated`',
    `relative_humidity_pct` DECIMAL(18,2) COMMENT 'Relative humidity as a percentage (0–100%) measured during the observation interval. Critical input for spray window determination (REI compliance), fungal disease pressure modeling under IPM frameworks, and ET calculation via the Penman-Monteith method.',
    `sensor_depth_cm` DECIMAL(18,2) COMMENT 'Depth below the soil surface at which soil temperature and soil moisture readings were captured, in centimeters. Required for multi-depth sensor arrays to correctly attribute readings to the appropriate soil horizon. Null for atmospheric measurements.',
    `sensor_height_m` DECIMAL(18,2) COMMENT 'Height above ground level at which atmospheric measurements (temperature, humidity, wind) were captured, in meters. Standard WMO height is 2m for temperature/humidity and 10m for wind. Required for ET calculation height corrections and data quality validation.',
    `snowfall_mm` DECIMAL(18,2) COMMENT 'Snowfall accumulation during the observation interval expressed as millimeters of water equivalent. Used for spring soil moisture forecasting, field access planning, and crop insurance documentation in winter crop regions.',
    `soil_moisture_pct` DECIMAL(18,2) COMMENT 'Volumetric soil moisture content as a percentage of field capacity, measured at the sensor depth. Core input for irrigation scheduling decisions, drought stress monitoring, and VRA (Variable Rate Application) prescription generation. Integrates with John Deere Operations Center and Trimble Ag Software.',
    `soil_temperature_c` DECIMAL(18,2) COMMENT 'Soil temperature measured at the sensor depth during the observation interval, in degrees Celsius. Used for planting window determination (germination threshold monitoring), soil microbial activity modeling, and fertilizer application timing optimization.',
    `solar_radiation_wm2` DECIMAL(18,2) COMMENT 'Incoming solar radiation (shortwave) measured during the observation interval, in watts per square meter (W/m²). Primary driver of ET (Evapotranspiration) calculations via the Penman-Monteith method and NDVI-based crop growth modeling. Also used for solar energy resource assessment on farm.',
    `source_record_code` STRING COMMENT 'Original record identifier from the upstream source system (e.g., DTN feed message ID, Climate FieldView observation UUID, John Deere Operations Center telemetry record ID). Enables end-to-end data lineage tracing from raw ingestion to Silver Layer.',
    `spray_window_open` BOOLEAN COMMENT 'Boolean flag indicating whether current meteorological conditions (wind speed, temperature, relative humidity, precipitation) meet the criteria for a safe and compliant pesticide or fertilizer application window. Derived from EPA label requirements and IPM BMP thresholds. Supports REI and PHI compliance.',
    `temperature_avg_c` DECIMAL(18,2) COMMENT 'Mean air temperature for the observation interval, in degrees Celsius. Computed as (max + min) / 2 for daily intervals or as a true average for sub-daily intervals. Primary input for ET (Evapotranspiration) calculations and irrigation scheduling models.',
    `temperature_max_c` DECIMAL(18,2) COMMENT 'Maximum air temperature recorded during the observation interval, in degrees Celsius. Used for GDD (Growing Degree Day) accumulation calculations, heat stress threshold monitoring, and crop insurance documentation. Paired with temperature_min_c for daily range analysis.',
    `temperature_min_c` DECIMAL(18,2) COMMENT 'Minimum air temperature recorded during the observation interval, in degrees Celsius. Critical for frost/freeze alert generation, GDD base temperature calculations, chilling hour accumulation, and crop protection decision support.',
    `updated_at` TIMESTAMP COMMENT 'Timestamp when this observation record was last modified in the Silver Layer, such as after QC correction, status change, or data enrichment. Supports audit trail and change data capture (CDC) for downstream consumers.',
    `wind_direction_deg` DECIMAL(18,2) COMMENT 'Prevailing wind direction during the observation interval, expressed in meteorological degrees (0–360°, where 0/360 = North). Used for spray drift modeling, pesticide application compliance, and field-level wind exposure analysis.',
    `wind_gust_ms` DECIMAL(18,2) COMMENT 'Maximum instantaneous wind gust speed recorded during the observation interval, in meters per second. Used for equipment safety alerts, spray application go/no-go decisions, and crop lodging risk assessment.',
    `wind_speed_ms` DECIMAL(18,2) COMMENT 'Average wind speed during the observation interval, in meters per second. Used for spray window determination (drift risk assessment), ET calculation, and wind damage risk alerts. EPA pesticide label compliance requires wind speed checks before application.',
    CONSTRAINT pk_observation PRIMARY KEY(`observation_id`)
) COMMENT 'Time-series transactional record of actual meteorological measurements captured at a weather station or IoT field sensor. Stores instantaneous or interval readings for temperature (min/max/avg in °F/°C), precipitation (rainfall/snowfall in inches/mm), relative humidity (%), wind speed (mph) and direction, barometric pressure (inHg/hPa), solar radiation (W/m²), dew point, and leaf wetness duration (hours). Timestamped to ISO 8601 with configurable interval (5-min, 15-min, hourly, daily). SSOT for all raw weather measurements; feeds GDD calculation, ET computation, irrigation scheduling, spray window determination, and crop insurance documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`forecast` (
    `forecast_id` BIGINT COMMENT 'Unique system-generated identifier for each meteorological forecast record in the agricultural weather domain.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field polygon for which this forecast is generated, enabling field-level planting window and spray window decisions. Sourced from Esri ArcGIS field mapping or Climate FieldView.',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor from which this forecast is anchored or associated. Links to the weather station master record.',
    `cloud_cover_pct` DECIMAL(18,2) COMMENT 'Forecast percentage of sky covered by clouds for the valid period. Influences solar radiation estimates used in ET evapotranspiration calculations and NDVI Normalized Difference Vegetation Index interpretation.',
    `confidence_interval_pct` DECIMAL(18,2) COMMENT 'Quantitative confidence interval expressed as a percentage (e.g., 90 for a 90% confidence interval) associated with the forecast values. Supports probabilistic risk assessment for crop insurance documentation and WASDE-aligned seasonal outlooks.',
    `confidence_level` STRING COMMENT 'Qualitative confidence level assigned by the forecast provider indicating the reliability of this forecast record. High confidence forecasts are used for firm operational commitments; low confidence forecasts trigger contingency planning.. Valid values are `high|medium|low`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this forecast record was first ingested into the agricultural data lakehouse. Supports data lineage, audit trail, and Silver Layer processing compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `dew_point_c` DECIMAL(18,2) COMMENT 'Forecast dew point temperature in degrees Celsius for the valid period. Used in disease pressure models (e.g., fungal blight risk) and to assess condensation risk on crops and equipment.',
    `elevation_m` DECIMAL(18,2) COMMENT 'Elevation of the forecast location above mean sea level in meters. Influences temperature lapse rate adjustments, frost risk calculations, and ET evapotranspiration estimates for high-altitude agricultural fields.',
    `et_forecast_mm` DECIMAL(18,2) COMMENT 'Forecast reference evapotranspiration (ET) in millimeters for the valid period, calculated using the FAO Penman-Monteith method. Primary input for irrigation scheduling decisions and water resource management in Climate FieldView and Trimble Ag Software.',
    `external_forecast_ref` STRING COMMENT 'Externally assigned identifier or reference code from the source forecast provider (e.g., NOAA NWS product ID, DTN forecast package ID, Climate FieldView forecast run ID). Enables traceability back to the originating provider record for dispute resolution and data quality audits.',
    `forecast_status` STRING COMMENT 'Current lifecycle state of the forecast record. Active forecasts are in use for operational decisions; superseded forecasts have been replaced by a newer issue; expired forecasts have passed their valid period; cancelled forecasts were withdrawn by the provider.. Valid values are `active|superseded|expired|cancelled`',
    `forecast_type` STRING COMMENT 'Temporal resolution and horizon of the forecast record. Hourly forecasts support spray window scheduling; daily and 7-day support planting window decisions; seasonal forecasts align with WASDE outlooks and crop insurance documentation.. Valid values are `hourly|daily|7_day|seasonal`',
    `freeze_risk` BOOLEAN COMMENT 'Boolean flag indicating whether forecast minimum temperature is at or below -2.2°C (28°F), triggering a hard freeze alert. Distinguishes from frost risk for crop damage severity classification and crop insurance loss event documentation.',
    `frost_risk` BOOLEAN COMMENT 'Boolean flag indicating whether forecast minimum temperature is at or below 0°C, triggering a frost alert. Supports frost protection decisions including irrigation-based frost protection, smudge pot activation, and harvest acceleration.',
    `gdd_base_temp_c` DECIMAL(18,2) COMMENT 'Base temperature in degrees Celsius used in the GDD growing degree day calculation for this forecast record. Varies by crop species (e.g., 10°C for corn, 4.4°C for wheat). Ensures GDD values are interpreted correctly for the target crop.',
    `gdd_forecast` DECIMAL(18,2) COMMENT 'Forecast growing degree day accumulation for the valid period, calculated from forecast max and min temperatures relative to a crop-specific base temperature. Supports crop development stage prediction, pest emergence timing, and planting window optimization.',
    `horizon_hours` STRING COMMENT 'Number of hours from the issued timestamp to the end of the forecast valid period. Indicates how far into the future the forecast extends, supporting confidence assessment and operational planning lead time.',
    `humidity_pct` DECIMAL(18,2) COMMENT 'Forecast relative humidity as a percentage for the valid period. Influences fungal disease pressure prediction, spray efficacy windows, and ET evapotranspiration calculations for irrigation scheduling.',
    `issued_timestamp` TIMESTAMP COMMENT 'Date and time when the forecast was officially issued or published by the source provider. Used to determine forecast freshness and to sequence superseding forecast versions. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `latitude` DECIMAL(18,2) COMMENT 'Decimal latitude coordinate of the forecast location or field polygon centroid. Used for spatial alignment with GIS field maps and IoT sensor networks. Expressed in decimal degrees (WGS84).',
    `longitude` DECIMAL(18,2) COMMENT 'Decimal longitude coordinate of the forecast location or field polygon centroid. Used for spatial alignment with GIS field maps and IoT sensor networks. Expressed in decimal degrees (WGS84).',
    `model_version` STRING COMMENT 'Version identifier of the numerical weather prediction model used to generate this forecast (e.g., GFS 16.3.0, NAM 4.1, ECMWF CY47R3). Enables traceability and reproducibility of forecast-driven agricultural decisions for audit and compliance purposes.',
    `precip_amount_mm` DECIMAL(18,2) COMMENT 'Forecast total precipitation amount in millimeters for the valid period. Used for irrigation scheduling decisions, soil moisture modeling, and crop insurance documentation under USDA Risk Management Agency guidelines.',
    `precip_probability_pct` DECIMAL(18,2) COMMENT 'Forecast probability of measurable precipitation occurring during the valid period, expressed as a percentage (0–100). Key input for spray window scheduling — high probability suppresses pesticide application recommendations per IPM Integrated Pest Management protocols.',
    `precip_type` STRING COMMENT 'Forecast type of precipitation expected during the valid period. Distinguishes rain from snow, hail, or freezing rain, which have different implications for field operations, equipment deployment, and crop damage risk assessment.. Valid values are `rain|snow|sleet|freezing_rain|hail|none`',
    `solar_radiation_mj_m2` DECIMAL(18,2) COMMENT 'Forecast incoming solar radiation in megajoules per square meter for the valid period. Direct input to the FAO Penman-Monteith ET calculation and photosynthetically active radiation (PAR) models for crop growth simulation.',
    `source_system` STRING COMMENT 'Originating data provider or system for this forecast record. Identifies whether the forecast was sourced from DTN Data Transmission Network, NOAA National Weather Service, Climate FieldView, custom IoT field sensors, or WASDE World Agricultural Supply and Demand Estimates seasonal outlook.. Valid values are `DTN|NOAA_NWS|Climate_FieldView|Custom_IoT|WASDE`',
    `spray_window_open` BOOLEAN COMMENT 'Boolean flag indicating whether forecast conditions (wind speed, precipitation probability, temperature, humidity) meet the criteria for a safe and effective pesticide or herbicide application window. Derived from EPA application guidelines and IPM Integrated Pest Management protocols.',
    `temp_avg_c` DECIMAL(18,2) COMMENT 'Forecast mean air temperature in degrees Celsius for the valid period. Used as the base input for GDD growing degree day accumulation calculations and pest pressure prediction models.',
    `temp_max_c` DECIMAL(18,2) COMMENT 'Forecast maximum air temperature in degrees Celsius for the valid period. Used in growing degree day (GDD) accumulation calculations, heat stress assessments, and crop development stage modeling.',
    `temp_min_c` DECIMAL(18,2) COMMENT 'Forecast minimum air temperature in degrees Celsius for the valid period. Critical for frost and freeze alert generation, PHI pre-harvest interval compliance, and cold stress risk assessment for crops.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this forecast record was last modified or refreshed in the data lakehouse, such as when a forecast is superseded or corrected by the provider. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `wind_direction_deg` DECIMAL(18,2) COMMENT 'Forecast prevailing wind direction in meteorological degrees (0–360, where 0/360 = North). Used in spray drift modeling to protect adjacent fields, buffer zones, and sensitive areas per EPA and GLOBALG.A.P. requirements.',
    `wind_gust_kmh` DECIMAL(18,2) COMMENT 'Forecast maximum wind gust speed in kilometers per hour for the valid period. Used to assess equipment safety thresholds for aerial application and tall crop operations.',
    `wind_speed_kmh` DECIMAL(18,2) COMMENT 'Forecast average wind speed in kilometers per hour for the valid period. Critical for spray window determination — wind speeds above threshold trigger spray application restrictions per EPA and REI Restricted Entry Interval guidelines.',
    `valid_from` TIMESTAMP COMMENT 'Start of the period for which this forecast is valid. For hourly forecasts this is the start of the forecast hour; for daily forecasts it is the start of the forecast day. Used to align forecast data with field operation scheduling windows.',
    `valid_to` TIMESTAMP COMMENT 'End of the period for which this forecast is valid. Defines the forecast window boundary for planting, spraying, and irrigation scheduling decisions.',
    CONSTRAINT pk_forecast PRIMARY KEY(`forecast_id`)
) COMMENT 'Meteorological forecast record sourced from DTN, NOAA NWS, or Climate FieldView for a specific geographic location or field polygon. Captures forecast horizon (hourly, daily, 7-day, seasonal), predicted temperature range, precipitation probability and amount, wind speed/direction, humidity, ET forecast, and confidence interval. Supports planting window decisions, spray window scheduling, and WASDE-aligned seasonal outlooks.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`growing_degree_day` (
    `growing_degree_day_id` BIGINT COMMENT 'Primary key for growing_degree_day',
    `climate_normal_id` BIGINT COMMENT 'Foreign key linking to weather.climate_normal. Business justification: GDD accumulation records compare actual heat unit accumulation against historical averages. growing_degree_day has historical_avg_gdd and gdd_deviation — these reference historical normal values. Link',
    `field_crop_plan_id` BIGINT COMMENT 'Reference to the field crop plan governing the crop variety and management practices for which GDD accumulation is being tracked.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field for which GDD accumulation is being tracked. Links to the field/land parcel master record.',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season during which GDD accumulation is recorded. Aligns with crop planning and seasonal crop management cycles.',
    `planting_event_id` BIGINT COMMENT 'Foreign key linking to crop.planting_event. Business justification: GDD accumulation is anchored to the actual planting date from the planting event. Linking growing_degree_day to planting_event provides the precise planting date anchor for GDD calculations, replacing',
    `seed_variety_id` BIGINT COMMENT 'Foreign key linking to product.seed_variety. Business justification: GDD accumulation thresholds (gdd_to_emergence, gdd_to_silking, gdd_to_maturity) and predicted_maturity_date are seed-variety-specific parameters. Agronomic yield forecasting and harvest scheduling req',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor providing the temperature data used to calculate daily GDD values.',
    `accumulation_status` STRING COMMENT 'Current lifecycle status of the GDD accumulation record for this crop and field. active indicates ongoing accumulation; paused indicates temporary suspension (e.g., dormancy period); terminated indicates season ended by frost or crop failure; completed indicates crop reached maturity.. Valid values are `active|paused|terminated|completed`',
    `base_temperature_c` DECIMAL(18,2) COMMENT 'Crop-specific minimum threshold temperature in degrees Celsius below which crop development does not occur. For corn this is typically 10°C (50°F); for wheat 0°C (32°F). Used as the lower bound in GDD calculation.',
    `calculation_method` STRING COMMENT 'The mathematical method used to calculate daily GDD values. standard uses simple average of min/max temperature minus base; modified applies upper threshold cap; baskerville_emin uses sine curve interpolation for more accurate results.. Valid values are `standard|modified|baskerville_emin`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this GDD accumulation record was first created in the system. Used for data lineage, audit trail, and Silver layer processing tracking.',
    `crop_type` STRING COMMENT 'The type of crop for which GDD accumulation is being tracked (e.g., corn, soybeans, wheat, cotton). Determines the applicable base and upper threshold temperatures. [ENUM-REF-CANDIDATE: corn|soybeans|wheat|cotton|sorghum|sunflower|barley|canola|rice|alfalfa — promote to reference product]',
    `cumulative_gdd` DECIMAL(18,2) COMMENT 'Running total of heat units accumulated from the planting date or season start date through the record date. Used to predict crop development stage and estimate time to maturity.',
    `current_growth_stage` STRING COMMENT 'Estimated crop development stage derived from cumulative GDD accumulation (e.g., VE, V6, VT, R1, R6 for corn; VC, V1, R1, R7, R8 for soybeans). Used for agronomic decision-making, spray window compliance, and PHI tracking. [ENUM-REF-CANDIDATE: VE|V1|V2|V3|V4|V5|V6|VT|R1|R2|R3|R4|R5|R6|R7|R8 — promote to reference product]',
    `daily_gdd` DECIMAL(18,2) COMMENT 'Heat units accumulated on the record date, calculated as the average of adjusted min/max temperatures minus the base temperature. Negative values are set to zero. Expressed in degree-days (°C-days or °F-days per calculation method).',
    `data_quality_flag` STRING COMMENT 'Quality control indicator for the temperature observations used in GDD calculation. good indicates validated sensor data; estimated indicates gap-filled or interpolated values; suspect indicates values outside expected range pending review; missing indicates no data available; corrected indicates post-processing adjustment applied.. Valid values are `good|estimated|suspect|missing|corrected`',
    `data_source` STRING COMMENT 'Origin of the temperature data used to calculate the daily GDD value. Indicates whether data came from a physical weather station, IoT field sensor, DTN commercial weather feed, Climate FieldView platform, manual entry, or spatial interpolation.. Valid values are `weather_station|iot_sensor|dtn_feed|climate_fieldview|manual_entry|interpolated`',
    `forecast_gdd_30day` DECIMAL(18,2) COMMENT 'Projected GDD accumulation over the next 30 calendar days based on extended weather forecast data. Used for medium-term harvest planning, logistics coordination, and crop insurance monitoring.',
    `forecast_gdd_7day` DECIMAL(18,2) COMMENT 'Projected GDD accumulation over the next 7 calendar days based on weather forecast data from DTN or Climate FieldView. Used for short-term irrigation scheduling, spray window planning, and harvest timing decisions.',
    `frost_event_flag` BOOLEAN COMMENT 'Indicates whether a frost or freeze event occurred on the record date (minimum temperature at or below 0°C / 32°F). Critical for crop damage assessment, insurance claims, and replanting decisions.',
    `gdd_deviation` DECIMAL(18,2) COMMENT 'Difference between the current cumulative GDD and the historical average cumulative GDD for the same date and location. Positive values indicate above-normal heat accumulation; negative values indicate below-normal accumulation. Critical for crop insurance documentation and yield forecasting.',
    `gdd_percentile_rank` DECIMAL(18,2) COMMENT 'Percentile rank of the current cumulative GDD relative to the historical distribution for the same crop, location, and calendar date. A value of 90 means the current season is warmer than 90% of historical seasons. Supports climate risk assessment and crop insurance documentation.',
    `gdd_to_emergence` DECIMAL(18,2) COMMENT 'Crop-specific cumulative GDD milestone required to reach the emergence (VE) growth stage. Used to predict emergence date and validate actual emergence observations against heat unit accumulation.',
    `gdd_to_maturity` DECIMAL(18,2) COMMENT 'Crop-specific cumulative GDD milestone required to reach physiological maturity (black layer for corn, R8 for soybeans). Used for harvest timing decisions, crop insurance documentation, and logistics planning.',
    `gdd_to_silking` DECIMAL(18,2) COMMENT 'Crop-specific cumulative GDD milestone required to reach the silking (R1) or equivalent flowering growth stage. Critical for pollination timing, spray window management, and PHI compliance planning.',
    `historical_avg_gdd` DECIMAL(18,2) COMMENT 'Long-term historical average cumulative GDD for the same crop, field location, and calendar date, typically based on a 30-year climate normal. Used as the baseline for deviation analysis and climate risk assessment.',
    `killing_frost_flag` BOOLEAN COMMENT 'Indicates whether a killing frost event occurred on the record date (minimum temperature at or below -2.2°C / 28°F for a sustained period). A killing frost terminates the growing season and stops GDD accumulation. Triggers crop insurance documentation requirements.',
    `phi_compliance_stage_reached` BOOLEAN COMMENT 'Indicates whether the crop has reached the growth stage at which Pre-Harvest Interval (PHI) restrictions for applied agrochemicals become active, as determined by cumulative GDD. Critical for food safety compliance and EPA/FDA regulatory adherence.',
    `predicted_maturity_date` DATE COMMENT 'Estimated calendar date when the crop will reach physiological maturity based on current cumulative GDD and historical or forecast temperature trends. Supports harvest scheduling and supply chain planning.',
    `record_date` DATE COMMENT 'Calendar date for which the daily Growing Degree Day (GDD) value is calculated. Represents the specific day of temperature observation.',
    `season_start_date` DATE COMMENT 'The date from which cumulative GDD accumulation begins for this crop and field. Typically the planting date or a standardized calendar date (e.g., January 1 for winter crops). Defines the accumulation window.',
    `spray_window_open` BOOLEAN COMMENT 'Indicates whether the current crop growth stage (as determined by cumulative GDD) is within an approved spray application window for pesticides or fungicides. Derived from GDD-based growth stage and PHI/REI compliance rules.',
    `temperature_avg_c` DECIMAL(18,2) COMMENT 'Mean daily air temperature in degrees Celsius, calculated as the average of the minimum and maximum temperatures for the record date. Intermediate value used in standard GDD calculation.',
    `temperature_max_c` DECIMAL(18,2) COMMENT 'Observed maximum air temperature in degrees Celsius recorded at the weather station or field sensor for the record date. Used as the upper bound in daily GDD calculation.',
    `temperature_min_c` DECIMAL(18,2) COMMENT 'Observed minimum air temperature in degrees Celsius recorded at the weather station or field sensor for the record date. Used as the lower bound in daily GDD calculation.',
    `temperature_unit` STRING COMMENT 'Unit of measure used for all temperature values and GDD calculations in this record. celsius for metric (°C-days); fahrenheit for imperial (°F-days). Ensures consistent interpretation across systems and regions.. Valid values are `celsius|fahrenheit`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this GDD accumulation record was last modified, such as when temperature data was corrected, quality flags were updated, or forecast values were refreshed.',
    `upper_threshold_temperature_c` DECIMAL(18,2) COMMENT 'Crop-specific maximum temperature ceiling in degrees Celsius above which additional heat does not accelerate crop development. For corn this is typically 30°C (86°F). Temperatures above this are capped at this value in modified GDD calculations.',
    CONSTRAINT pk_growing_degree_day PRIMARY KEY(`growing_degree_day_id`)
) COMMENT 'Growing Degree Day (GDD) accumulation record tracking heat unit accumulation for a specific crop, field, and growing season. Stores daily GDD calculated from min/max temperature against crop-specific base and upper threshold temperatures, cumulative GDD to date, target GDD milestones (emergence, silking, maturity), and deviation from historical norms. Critical for crop development stage prediction, PHI compliance, and harvest timing decisions.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`evapotranspiration` (
    `evapotranspiration_id` BIGINT COMMENT 'Primary key for evapotranspiration',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or irrigation zone for which this ET calculation was performed. Links to the field master record in the land and soil domain.',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season during which this ET calculation applies, enabling seasonal water balance tracking and crop coefficient (Kc) stage alignment.',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor that provided the meteorological inputs used in this ET calculation. May be a physical station or a virtual grid-point from DTN weather feeds.',
    `calculation_date` DATE COMMENT 'The calendar date for which this evapotranspiration calculation was computed. Represents the real-world observation or forecast date, not the record creation date. Used for daily water balance tracking and irrigation scheduling.',
    `calculation_method` STRING COMMENT 'The scientific method used to compute reference evapotranspiration (ETo). Penman-Monteith (FAO-56) is the USDA and FAO standard; Hargreaves is used when solar radiation data is unavailable. Drives traceability and comparability of ET values.. Valid values are `Penman-Monteith|Hargreaves|Priestley-Taylor|Blaney-Criddle|FAO-56`',
    `calculation_status` STRING COMMENT 'Lifecycle status of this ET calculation record. computed indicates automated calculation; validated indicates agronomist review; superseded indicates a newer recalculation replaced this record; error indicates a failed computation requiring review.. Valid values are `draft|computed|validated|superseded|error`',
    `calculation_timestamp` TIMESTAMP COMMENT 'Precise timestamp when this ET calculation record was computed or ingested into the system. Supports audit trail and distinguishes multiple intraday recalculations for the same date.',
    `crop_coefficient` DECIMAL(18,2) COMMENT 'Dimensionless crop coefficient (Kc) applied to reference ET to derive crop-specific ET. Value varies by crop growth stage (initial, mid-season, late-season) per FAO-56 tables. Sourced from crop plan or agronomist input.',
    `crop_et_mm` DECIMAL(18,2) COMMENT 'Crop evapotranspiration (ETc) in millimetres, calculated as ETo × Kc. Represents the actual water demand of the specific crop at its current growth stage. Primary input to irrigation scheduling and water balance calculations.',
    `crop_growth_stage` STRING COMMENT 'The phenological growth stage of the crop at the time of this ET calculation, used to select the appropriate crop coefficient (Kc) from FAO-56 tables. Stage progression drives changes in water demand throughout the season.. Valid values are `initial|development|mid_season|late_season|harvest`',
    `cumulative_et_season_mm` DECIMAL(18,2) COMMENT 'Running cumulative crop ET (ETc) in millimetres from the start of the growing season to the calculation date. Used for seasonal water budget tracking, crop insurance documentation, and water use compliance reporting.',
    `cumulative_irrigation_season_mm` DECIMAL(18,2) COMMENT 'Running cumulative irrigation water applied in millimetres from the start of the growing season to the calculation date. Compared against cumulative ET to assess irrigation efficiency and water use compliance.',
    `data_quality_score` DECIMAL(18,2) COMMENT 'Numeric quality score (0–100) reflecting the completeness and reliability of the weather input data used in this ET calculation. Lower scores indicate missing inputs (e.g., estimated solar radiation, gap-filled humidity) that reduce confidence in the ET result.',
    `data_source_type` STRING COMMENT 'Indicates whether the weather inputs used in this ET calculation were derived from observed station data, weather forecast models, spatially interpolated grid data, or satellite-derived estimates. Affects confidence in irrigation recommendations.. Valid values are `observed|forecast|interpolated|satellite`',
    `effective_precipitation_mm` DECIMAL(18,2) COMMENT 'The portion of total precipitation credited toward meeting crop ET demand after accounting for runoff, deep percolation, and interception losses. Calculated per USDA SCS method. Reduces the net irrigation requirement.',
    `et_deficit_mm` DECIMAL(18,2) COMMENT 'Daily ET deficit in millimetres, calculated as ETc minus effective precipitation. Represents the net water demand that must be met by irrigation for the calculation date. Negative values indicate precipitation surplus.',
    `frost_risk_flag` BOOLEAN COMMENT 'Boolean flag indicating whether minimum temperature conditions on the calculation date meet or fall below the frost threshold for the crop type. Triggers frost/freeze alerts in irrigation scheduling systems and supports crop insurance documentation.',
    `irrigation_method` STRING COMMENT 'The irrigation delivery method applicable to this field and ET recommendation. Determines application efficiency factors and scheduling logic. Drip and subsurface drip have higher application efficiency than flood or sprinkler systems.. Valid values are `drip|center_pivot|flood|sprinkler|subsurface_drip`',
    `max_temperature_c` DECIMAL(18,2) COMMENT 'Maximum daily air temperature in degrees Celsius used as a weather input to the ET calculation. Required by both Penman-Monteith and Hargreaves methods. Sourced from weather station or DTN feed.',
    `mean_temperature_c` DECIMAL(18,2) COMMENT 'Mean daily air temperature in degrees Celsius, calculated as the average of maximum and minimum temperatures. Used in Hargreaves ET method and growing degree day (GDD) accumulation calculations.',
    `min_temperature_c` DECIMAL(18,2) COMMENT 'Minimum daily air temperature in degrees Celsius used as a weather input to the ET calculation. Required by both Penman-Monteith and Hargreaves methods. Also used for frost risk assessment.',
    `notes` STRING COMMENT 'Free-text agronomist or system notes associated with this ET calculation record, capturing manual overrides, data quality observations, or irrigation scheduling decisions that deviate from the automated recommendation.',
    `precipitation_mm` DECIMAL(18,2) COMMENT 'Total precipitation (rainfall) recorded or forecast for the calculation date in millimetres. Used as a credit against crop ET demand in the daily water balance calculation.',
    `recommended_irrigation_acre_in` DECIMAL(18,2) COMMENT 'Weather-driven irrigation recommendation expressed in acre-inches per acre, derived from the ET deficit and soil water deficit. Primary output consumed by John Deere Operations Center and Trimble Ag VRA for irrigation scheduling and variable rate application prescriptions.',
    `recommended_irrigation_mm` DECIMAL(18,2) COMMENT 'Weather-driven irrigation recommendation expressed in millimetres, the SI unit equivalent of the acre-inch recommendation. Used for international reporting, water resource compliance, and integration with metric-based irrigation controllers.',
    `reference_et_mm` DECIMAL(18,2) COMMENT 'Reference evapotranspiration (ETo) in millimetres for the calculation date, representing the ET demand of a standardised reference crop (short grass or alfalfa). The foundational output of the Penman-Monteith or Hargreaves equation. Used as the basis for crop-specific ET adjustment.',
    `relative_humidity_pct` DECIMAL(18,2) COMMENT 'Mean daily relative humidity as a percentage, used in the Penman-Monteith ET calculation to determine vapour pressure deficit. High humidity reduces ET demand; low humidity increases it.',
    `scheduled_irrigation_date` DATE COMMENT 'The recommended calendar date on which irrigation should be applied based on the ET-driven water balance calculation. Populated when weather-driven scheduling is active. Null when no irrigation is currently recommended.',
    `scheduled_irrigation_timestamp` TIMESTAMP COMMENT 'Precise scheduled start date and time for the recommended irrigation event, used when automated irrigation controllers require time-of-day scheduling. Null when only date-level scheduling is active.',
    `soil_moisture_target_pct` DECIMAL(18,2) COMMENT 'Target soil moisture level as a percentage of field capacity for this field and crop stage. Used as the trigger threshold for irrigation scheduling. Typically set between 50–70% of available water capacity depending on crop stress tolerance.',
    `soil_water_deficit_mm` DECIMAL(18,2) COMMENT 'Cumulative soil water deficit in millimetres representing the difference between field capacity and current soil moisture content. Positive values indicate irrigation need. Updated daily using the FAO-56 water balance model.',
    `solar_radiation_mj_m2` DECIMAL(18,2) COMMENT 'Daily incoming solar radiation in megajoules per square metre (MJ/m²), a primary driver of ET demand in the Penman-Monteith equation. Sourced from weather station pyranometer or estimated from sunshine hours and cloud cover.',
    `spray_window_suitable` BOOLEAN COMMENT 'Boolean flag indicating whether weather conditions on the calculation date are suitable for pesticide or fertilizer spray application, based on wind speed, temperature, humidity, and precipitation thresholds. Supports Integrated Pest Management (IPM) and EPA/REI compliance.',
    `vapour_pressure_deficit_kpa` DECIMAL(18,2) COMMENT 'Vapour pressure deficit (VPD) in kilopascals, representing the difference between saturated and actual vapour pressure. A key intermediate variable in the Penman-Monteith ET calculation and an indicator of atmospheric drying demand on crops.',
    `water_stress_index` DECIMAL(18,2) COMMENT 'Dimensionless water stress coefficient (Ks) ranging from 0 to 1, representing the degree of crop water stress due to soil moisture deficit. A value of 1 indicates no stress; values below 1 indicate stress-adjusted ET. Used in FAO-56 dual crop coefficient approach.',
    `wind_speed_ms` DECIMAL(18,2) COMMENT 'Mean daily wind speed at 2-metre height in metres per second, a required input to the Penman-Monteith ET equation. Higher wind speeds increase ET demand by enhancing vapour transport from the crop canopy.',
    CONSTRAINT pk_evapotranspiration PRIMARY KEY(`evapotranspiration_id`)
) COMMENT 'Evapotranspiration (ET) calculation and weather-driven water balance record for a field or irrigation zone. Computed using the Penman-Monteith or Hargreaves method from observed or forecast weather inputs. Stores reference ET (ETo), crop ET (ETc) adjusted by crop coefficient (Kc), soil water deficit, ET deficit, soil moisture target, precipitation credit applied, recommended irrigation volume (acre-inches), irrigation method suitability (drip, pivot, flood), and scheduled irrigation date/time when weather-driven scheduling is active. SSOT for weather-derived water balance calculations and ET-based irrigation recommendations that feed irrigation scheduling systems (John Deere Operations Center, Trimble Ag VRA) and water resource management compliance reporting.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`frost_alert` (
    `frost_alert_id` BIGINT COMMENT 'Unique system-generated identifier for each frost or freeze alert record. Primary key for the frost_alert data product in the weather domain.',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: A frost alert is a specialized type of weather alert. When NWS or DTN issues a broader weather alert that includes frost/freeze conditions, the frost_alert record should reference the parent weather_a',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Frost alert response is a named crew-level operational process: when a frost alert fires, the field crew responsible for frost protection (irrigation activation, row cover deployment) must be identifi',
    `crop_enterprise_budget_id` BIGINT COMMENT 'Foreign key linking to finance.crop_enterprise_budget. Business justification: Frost events directly cause yield loss and revenue shortfalls requiring crop enterprise budget variance analysis and revision. Farm financial analysts must trace frost alerts to the affected budget to',
    `field_id` BIGINT COMMENT 'Reference to the specific agricultural field or management zone affected by the frost alert. Enables field-level crop protection decision-making and insurance loss documentation per FSMA traceability requirements.',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: Frost alerts are issued for specific crop growth stages within a growing season. Linking frost_alert to growing_season supports season-level frost risk tracking, insurance claim relevance determinatio',
    `seed_variety_id` BIGINT COMMENT 'Foreign key linking to product.seed_variety. Business justification: Frost protection decisions and estimated crop loss calculations depend on the specific seed varietys cold tolerance rating and growth stage vulnerability. RMA crop insurance loss adjustment requires ',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor that observed or forecast the frost/freeze condition. Links to the weather station master record for geographic and instrument metadata.',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to weather.forecast. Business justification: Frost alerts are generated when forecast temperatures fall below crop-critical thresholds. Linking frost_alert to the triggering forecast record provides full traceability from alert back to the sourc',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Frost alerts can be triggered by observed (actual) temperatures falling below critical thresholds, not just forecast data. frost_alert has observed_low_temp_c which is an observed value. Linking to th',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: NWS and DTN frost alerts are issued at the geographic zone level. frost_alert has geographic_zone_code (STRING) which is a denormalized reference to weather_zone.zone_code. Adding weather_zone_id FK n',
    `acknowledged_by` STRING COMMENT 'Name or identifier of the farm manager, agronomist, or operations staff member who acknowledged the frost alert. Supports accountability tracking and FSMA food safety plan documentation.',
    `acknowledgement_timestamp` TIMESTAMP COMMENT 'Date and time when a farm manager or agronomist acknowledged receipt of the frost alert. Used for operational response time tracking and compliance documentation under FSMA food safety planning requirements.',
    `affected_area_ha` DECIMAL(18,2) COMMENT 'Total agricultural area affected by the frost event, expressed in hectares. Used for insurance loss quantification, resource allocation for protective actions, and USDA reporting.',
    `alert_end_timestamp` TIMESTAMP COMMENT 'Forecast or observed end date and time of the frost or freeze event window. Marks when temperatures are expected to rise above the critical threshold. Used for operational planning and insurance documentation.',
    `alert_notes` STRING COMMENT 'Free-text field for agronomist or farm manager observations, supplementary meteorological context, protective action outcomes, or post-event damage assessment notes associated with the frost alert.',
    `alert_source` STRING COMMENT 'Originating system or data provider that generated the frost alert. DTN (Data Transmission Network) and NWS (National Weather Service) are primary external sources; Climate FieldView and IoT sensors provide field-level triggers; Manual indicates agronomist-entered alerts.. Valid values are `DTN|NWS|Climate_FieldView|IoT_Sensor|Manual`',
    `alert_start_timestamp` TIMESTAMP COMMENT 'Forecast or observed start date and time of the frost or freeze event window. Used for spray window planning, irrigation frost protection scheduling, and field crew deployment timing.',
    `alert_status` STRING COMMENT 'Current lifecycle state of the frost alert. active indicates the alert is in effect; acknowledged means a farm manager has confirmed receipt; expired means the alert window has passed; cancelled means the threat did not materialize; superseded means a newer alert replaced this one.. Valid values are `active|acknowledged|expired|cancelled|superseded`',
    `alert_type` STRING COMMENT 'Classification of the frost or freeze alert severity following NWS conventions. advisory indicates frost possible; watch indicates conditions favorable for frost/freeze; warning indicates frost/freeze imminent or occurring; freeze_warning indicates temperatures at or below 28°F for 2+ hours.. Valid values are `advisory|watch|warning|freeze_warning`',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when the frost alert record was first ingested and persisted in the data lakehouse. Used for data lineage, SLA monitoring, and audit trail compliance.',
    `critical_threshold_temp_c` DECIMAL(18,2) COMMENT 'Crop-specific critical temperature threshold in degrees Celsius below which significant crop damage is expected. Derived from crop type and growth stage; used to determine alert severity and trigger protective actions.',
    `crop_vulnerability_rating` STRING COMMENT 'Assessed vulnerability of the affected crop to the forecast frost event, combining crop type, growth stage, and forecast temperature. Drives urgency of protective action recommendations and insurance claim pre-notification.. Valid values are `low|moderate|high|critical`',
    `dew_point_temp_c` DECIMAL(18,2) COMMENT 'Forecast or observed dew point temperature in degrees Celsius. When dew point falls below 0°C, frost deposition on plant surfaces is likely. Critical input for frost type determination and crop damage assessment.',
    `estimated_crop_loss_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of crop yield loss attributable to the frost event, assessed post-event by agronomists or automated damage models. Used for insurance claim quantification and WASDE impact reporting. Null until post-event assessment is completed.',
    `forecast_low_temp_c` DECIMAL(18,2) COMMENT 'Predicted minimum air temperature in degrees Celsius for the alert period. This is the principal quantitative measurement driving the frost alert. Used to assess crop vulnerability and determine protective action thresholds.',
    `frost_duration_hours` DECIMAL(18,2) COMMENT 'Expected or observed duration of sub-threshold temperatures in hours. Critical for assessing cumulative crop damage exposure; freeze warnings typically require 2+ hours below 28°F for severe damage classification.',
    `frost_probability_pct` DECIMAL(18,2) COMMENT 'Probabilistic forecast of frost occurrence expressed as a percentage (0.00–100.00). Sourced from DTN or NWS ensemble forecast models. Used to calibrate alert urgency and protective action decisions.',
    `frost_type` STRING COMMENT 'Classification of the frost event mechanism. radiation frost occurs on calm, clear nights due to radiative cooling; advection frost results from cold air mass movement; evaporation frost occurs due to rapid moisture evaporation. Determines appropriate protective measures.. Valid values are `radiation|advection|evaporation|unknown`',
    `gdd_impact_estimate` DECIMAL(18,2) COMMENT 'Estimated reduction in Growing Degree Day (GDD) accumulation attributable to the frost event. GDD accumulation drives crop phenology and maturity timing; frost-induced GDD loss affects harvest scheduling and yield forecasting in Climate FieldView.',
    `insurance_claim_relevant` BOOLEAN COMMENT 'Indicates whether this frost alert event is relevant for crop insurance loss documentation. When True, the alert record is flagged for retention and inclusion in USDA Risk Management Agency (RMA) crop insurance claim packages.',
    `irrigation_frost_protection` BOOLEAN COMMENT 'Indicates whether overhead irrigation frost protection has been recommended or activated for this alert. Irrigation frost protection uses latent heat of freezing water to protect crops; relevant to irrigation scheduling systems.',
    `issued_timestamp` TIMESTAMP COMMENT 'The date and time when the frost alert was officially issued by the source system or meteorological authority. This is the principal real-world event time for the alert, distinct from the record creation audit timestamp.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate (decimal degrees, WGS84) of the alert centroid or affected field center. Supports GIS-based spatial analysis and precision agriculture mapping in Esri ArcGIS.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate (decimal degrees, WGS84) of the alert centroid or affected field center. Supports GIS-based spatial analysis and precision agriculture mapping in Esri ArcGIS.',
    `nws_event_code` STRING COMMENT 'External reference identifier assigned by the National Weather Service (NWS) to the corresponding official frost or freeze advisory, watch, or warning. Enables cross-referencing with NWS public alert records for regulatory and insurance documentation.',
    `observed_low_temp_c` DECIMAL(18,2) COMMENT 'Actual recorded minimum air temperature in degrees Celsius as measured by the weather station or IoT sensor during the frost event. Populated post-event; used for insurance loss documentation and model validation.',
    `recommended_action` STRING COMMENT 'Primary recommended protective action for the affected field or zone based on alert severity and crop vulnerability. Examples include frost cloth application, overhead irrigation frost protection, wind machine activation, smudge pot deployment, or harvest acceleration. [ENUM-REF-CANDIDATE: frost_cloth|overhead_irrigation|wind_machine|smudge_pot|harvest_acceleration|no_action|monitor — promote to reference product]',
    `relative_humidity_pct` DECIMAL(18,2) COMMENT 'Forecast or observed relative humidity percentage at the time of the frost event. Low humidity combined with low temperatures increases frost severity; used in dew point and frost point calculations.',
    `sky_condition` STRING COMMENT 'Forecast or observed sky cover condition at the time of the frost event. Clear skies promote radiative cooling and increase frost severity; overcast conditions reduce frost risk by trapping longwave radiation.. Valid values are `clear|partly_cloudy|mostly_cloudy|overcast`',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when the frost alert record was last modified, such as when status changes, forecast updates are received, or protective action outcomes are recorded.',
    `wind_speed_ms` DECIMAL(18,2) COMMENT 'Forecast or observed wind speed in meters per second at the time of the frost event. Low wind speeds (calm conditions) increase radiation frost risk; used in frost type classification (radiation vs. advection frost).',
    CONSTRAINT pk_frost_alert PRIMARY KEY(`frost_alert_id`)
) COMMENT 'Frost and freeze event alert record generated when forecast or observed temperatures fall below crop-specific critical thresholds. Captures alert type (advisory/watch/warning), predicted low temperature, frost probability, affected field or geographic zone, crop vulnerability rating, recommended protective actions (frost cloth, irrigation frost protection), and alert source (DTN, NWS). Supports crop protection decision-making and insurance loss documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`precipitation_event` (
    `precipitation_event_id` BIGINT COMMENT 'Unique system-generated identifier for each discrete severe weather precipitation event record. Primary key for the precipitation_event data product.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or land parcel where this precipitation event was observed or estimated. Used for field-level irrigation adjustment and crop damage assessment.',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: Precipitation events (hail, flooding) are assessed for crop loss impact within a specific growing season for insurance claim trigger evaluation and USDA disaster reporting. crop_type and crop_growth_s',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor that recorded this precipitation event. Links to the station master record for location and calibration metadata.',
    `affected_acreage` DECIMAL(18,2) COMMENT 'Estimated total acreage impacted by this precipitation event. Used for USDA disaster reporting, crop insurance claim quantification, and field-level damage assessment prioritization.',
    `beaufort_scale` STRING COMMENT 'Beaufort wind force scale classification (0–12) derived from sustained wind speed. Provides standardized wind severity classification for spray window invalidation, equipment operation decisions, and insurance documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this precipitation event record was first created in the system. Used for audit trail, data lineage, and SLA compliance tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `crop_damage_severity` STRING COMMENT 'Categorical assessment of estimated crop damage severity resulting from this precipitation event. Used for USDA disaster reporting, crop insurance claim documentation, and yield loss forecasting. Severity is assessed based on storm type, hail size, wind speed, and affected crop growth stage.. Valid values are `none|light|moderate|severe`',
    `crop_lodging_risk` BOOLEAN COMMENT 'Indicates whether wind speed and precipitation conditions during this event meet or exceed thresholds associated with crop lodging (stem breakage or root displacement). True triggers agronomic review and potential yield loss assessment.',
    `data_source` STRING COMMENT 'Identifies the originating data source system for this precipitation event record. Used for data lineage tracking, quality weighting, and source reconciliation. [ENUM-REF-CANDIDATE: iot_sensor|dtn_feed|climate_fieldview|manual_entry|noaa_api|nws_api — promote to reference product]. Valid values are `iot_sensor|dtn_feed|climate_fieldview|manual_entry|noaa_api|nws_api`',
    `event_end_timestamp` TIMESTAMP COMMENT 'Date and time when the precipitation or severe weather event concluded at the recorded location. Used to calculate event duration and determine trafficability and re-entry windows. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `event_reference_number` STRING COMMENT 'Externally-known alphanumeric identifier for this precipitation event, used for cross-referencing with USDA disaster reports, insurance claim documentation, and DTN weather feed records. Format: EVT-YYYYMMDD-NNNN.',
    `event_start_timestamp` TIMESTAMP COMMENT 'Date and time when the precipitation or severe weather event began at the recorded location. Principal real-world event time used for spray window invalidation, irrigation scheduling, and insurance claim trigger documentation. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `event_status` STRING COMMENT 'Current lifecycle status of the precipitation event record. active indicates the event is ongoing; completed indicates the event has ended and data is finalized; cancelled indicates a false alarm or data retraction; under_review indicates the record is pending quality validation.. Valid values are `active|completed|cancelled|under_review`',
    `external_event_ref` STRING COMMENT 'External system identifier for this event as assigned by the source system (e.g., DTN event ID, NWS storm report number, Climate FieldView event key). Used for cross-system reconciliation and audit traceability.',
    `hail_density_stones_sqft` DECIMAL(18,2) COMMENT 'Estimated number of hail stones per square foot observed during the event. Combined with hail stone size to determine crop damage severity and insurance claim trigger eligibility. Null when precip_type is not hail or mixed.',
    `hail_stone_size_in` DECIMAL(18,2) COMMENT 'Maximum observed hail stone diameter in inches during the event. Used to assess structural damage risk to crops, equipment, and infrastructure. Null when precip_type is not hail or mixed.',
    `insurance_claim_trigger` BOOLEAN COMMENT 'Indicates whether this precipitation event meets the threshold criteria to trigger a crop insurance claim under the applicable USDA RMA policy. True initiates the insurance claim documentation workflow and notifies the risk management team.',
    `irrigation_adjustment_required` BOOLEAN COMMENT 'Indicates whether this precipitation event requires adjustment to the active irrigation schedule. True triggers review of ET (Evapotranspiration) balance and irrigation prescription update in the FMIS (Farm Management Information System).',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate (WGS84 decimal degrees) of the primary observation point for this precipitation event. Used for spatial analysis, GIS mapping, and cross-referencing with field boundaries in Esri ArcGIS.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate (WGS84 decimal degrees) of the primary observation point for this precipitation event. Used for spatial analysis, GIS mapping, and cross-referencing with field boundaries in Esri ArcGIS.',
    `precip_intensity_peak_mm_hr` DECIMAL(18,2) COMMENT 'Maximum instantaneous precipitation rate in millimeters per hour recorded during the event. High peak intensity values indicate elevated runoff risk, soil erosion potential, and spray drift invalidation conditions.',
    `precip_total_mm` DECIMAL(18,2) COMMENT 'Total accumulated precipitation depth in millimeters recorded during the event. Primary quantitative outcome used for irrigation scheduling adjustments, runoff estimation, soil saturation assessment, and USDA disaster reporting thresholds.',
    `precip_type` STRING COMMENT 'Classification of the form of precipitation observed during the event. Determines downstream impact on crop damage assessment, trafficability, and equipment operation windows.. Valid values are `rain|snow|sleet|freezing_rain|hail|mixed`',
    `runoff_estimate_mm` DECIMAL(18,2) COMMENT 'Estimated surface water runoff depth in millimeters generated by this precipitation event, calculated using USDA NRCS curve number methodology. Used for soil erosion assessment, nutrient loss estimation, and BMP (Best Management Practices) compliance reporting.',
    `soil_saturation_index` DECIMAL(18,2) COMMENT 'Dimensionless index (0.00–1.00) representing estimated soil water saturation level following this precipitation event. Values approaching 1.00 indicate near-full saturation, triggering trafficability restrictions and irrigation suspension. Derived from precipitation total, soil type, and antecedent moisture conditions.',
    `spray_drift_risk_level` STRING COMMENT 'Categorical assessment of spray drift risk based on wind speed, wind direction, and precipitation conditions during the event. Used to invalidate spray windows and ensure compliance with EPA pesticide application restrictions and REI (Restricted Entry Interval) requirements.. Valid values are `none|low|moderate|high|extreme`',
    `spray_window_invalidated` BOOLEAN COMMENT 'Indicates whether this precipitation event has invalidated one or more planned spray application windows. True triggers re-scheduling of pesticide or fertilizer applications and PHI (Pre-Harvest Interval) recalculation.',
    `storm_track_path` STRING COMMENT 'GIS-encoded storm track path as a WKT (Well-Known Text) LineString representing the movement trajectory of the storm system across the geographic area. Used for spatial analysis of multi-field impact assessment in Esri ArcGIS.',
    `storm_type` STRING COMMENT 'Meteorological classification of the storm system producing the precipitation event. Convective storms are associated with thunderstorms and rapid intensity; frontal storms are associated with weather front passages; orographic storms result from terrain-forced uplift. Used for pest pressure prediction and crop insurance documentation. [ENUM-REF-CANDIDATE: convective|frontal|orographic|tropical|extratropical|monsoonal — promote to reference product]. Valid values are `convective|frontal|orographic|tropical|extratropical|monsoonal`',
    `structural_damage_risk` BOOLEAN COMMENT 'Indicates whether the combination of wind gust speed, hail size, and precipitation intensity during this event poses a risk of structural damage to farm buildings, grain storage, irrigation infrastructure, or equipment. True triggers facility inspection workflow.',
    `trafficability_restricted` BOOLEAN COMMENT 'Indicates whether field trafficability is restricted following this precipitation event due to soil saturation or standing water conditions. True prevents heavy equipment entry and triggers field access hold in the John Deere Operations Center fleet management workflow.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this precipitation event record was last modified. Used for change tracking, data quality monitoring, and incremental data pipeline processing. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `usda_disaster_reportable` BOOLEAN COMMENT 'Indicates whether this precipitation event qualifies for USDA disaster program reporting under FSA emergency programs. True triggers submission to the USDA Farm Service Agency disaster reporting workflow.',
    `wind_direction_deg` DECIMAL(18,2) COMMENT 'Prevailing wind direction in degrees from true north (0–360) during the event. Used for spray drift risk assessment, storm track path analysis, and field-level impact modeling.',
    `wind_gust_peak_mph` DECIMAL(18,2) COMMENT 'Maximum instantaneous wind gust speed in miles per hour recorded during the event. Used to assess crop lodging risk, spray drift risk, structural damage risk, and Beaufort scale classification.',
    `wind_speed_sustained_mph` DECIMAL(18,2) COMMENT 'Average sustained wind speed in miles per hour over the event duration. Used alongside peak gust for Beaufort classification, spray window assessment, and crop lodging risk evaluation.',
    CONSTRAINT pk_precipitation_event PRIMARY KEY(`precipitation_event_id`)
) COMMENT 'Discrete severe weather event record capturing precipitation, hail, and high-wind episodes at field or station level. Stores event start/end timestamps, total precipitation amount, peak intensity, storm type (convective, frontal, orographic), hail stone size (inches) and density (stones/sq ft), peak wind gust speed (mph), sustained wind speed, wind direction, Beaufort scale classification, crop lodging risk flag, spray drift risk level, structural damage risk indicator, runoff estimate, soil saturation index, estimated crop damage severity (none/light/moderate/severe), affected acreage, storm track path, and insurance claim trigger flag. SSOT for all field-level severe weather event documentation including precipitation, hail, and wind damage. Used for irrigation adjustments, trafficability assessment, spray window invalidation, crop insurance documentation, USDA disaster reporting, and FSIS compliance.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`spray_window` (
    `spray_window_id` BIGINT COMMENT 'Unique system-generated identifier for the spray window record. Primary key for the spray_window data product in the weather domain.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: Spray window compliance validation requires the specific agrochemical product being applied — rei_compliant, rei_hours, phi_days, epa_drift_constraint, and label_compliant on spray_window must be vali',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Spray windows are operationally assigned to specific pesticide application crews. Linking spray_window to crew enforces WPS REI compliance, verifies crew pesticide applicator certification, and drives',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field for which this spray window is calculated. Links to the field master record in the crop management domain.',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to weather.forecast. Business justification: Spray windows are calculated using weather forecast data (wind speed, temperature, humidity, precipitation probability). Linking spray_window to the specific forecast record used during window calcula',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Spray windows can be calculated from real-time meteorological observations (current wind speed, temperature, humidity, delta-T). Linking spray_window to the specific observation record used during win',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor providing the meteorological data used to calculate this spray window. May reference a physical station or a virtual grid point from DTN weather feeds.',
    `application_method` STRING COMMENT 'Planned or applicable pesticide/fertilizer application method for this spray window. Different methods have different wind speed, temperature, and drift constraints under EPA and state regulations. [ENUM-REF-CANDIDATE: ground_boom|aerial|airblast|chemigation|drone|hand_application|fertigation — promote to reference product]. Valid values are `ground_boom|aerial|airblast|chemigation|drone`',
    `buffer_zone_m` DECIMAL(18,2) COMMENT 'Required no-spray buffer zone distance in metres from field edge to sensitive areas, as determined by product label, EPA registration, and state regulations for this spray window. Operationally enforced during application.',
    `confidence_level` STRING COMMENT 'Qualitative confidence level of the spray window calculation based on forecast model accuracy, data source reliability, and forecast horizon. Used by agronomists to prioritise scheduling decisions.. Valid values are `high|medium|low`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this spray window record was first created in the system. Supports audit trail, data lineage, and regulatory documentation requirements.',
    `delta_t_value` DECIMAL(18,2) COMMENT 'Delta-T (ΔT) is the difference between dry-bulb and wet-bulb temperatures in degrees Celsius, used as the primary indicator of spray droplet evaporation rate and application suitability. Optimal Delta-T range is typically 2–8°C; values outside this range indicate poor spray conditions.',
    `dew_point_c` DECIMAL(18,2) COMMENT 'Dew point temperature in degrees Celsius during the spray window. Used alongside Delta-T and humidity to assess spray droplet evaporation conditions and risk of leaf wetness that may affect product uptake.',
    `epa_drift_constraint` BOOLEAN COMMENT 'Indicates whether EPA drift reduction regulatory constraints are active for this spray window, based on proximity to sensitive areas (water bodies, schools, residential zones) and product-specific drift management requirements under EPA 40 CFR Part 170.',
    `et_mm` DECIMAL(18,2) COMMENT 'Evapotranspiration (ET) in millimetres during the spray window period. High ET rates indicate conditions that accelerate spray droplet evaporation, reducing efficacy and increasing fine-droplet drift risk.',
    `external_window_ref` STRING COMMENT 'Reference identifier from the originating external system (Climate FieldView, DTN, Trimble Ag Software) for this spray window record. Supports data lineage, reconciliation, and audit traceability back to the source system.',
    `forecast_horizon_hours` STRING COMMENT 'Number of hours ahead from the calculation timestamp that this spray window is forecast for. Shorter horizons indicate higher confidence; longer horizons are used for advance planning. Null for observation-based windows.',
    `gdd_base_temp_c` DECIMAL(18,2) COMMENT 'Base temperature in degrees Celsius used for Growing Degree Day (GDD) accumulation calculations associated with this spray window. GDD thresholds trigger pest pressure predictions and optimal application timing for certain products.',
    `humidity_max_pct` DECIMAL(18,2) COMMENT 'Maximum relative humidity percentage during the spray window. Excessively high humidity can reduce product efficacy for certain fungicides and herbicides and may indicate inversion risk conditions.',
    `humidity_min_pct` DECIMAL(18,2) COMMENT 'Minimum relative humidity percentage during the spray window. Low humidity increases evaporation of spray droplets, reducing efficacy and increasing drift risk. Label compliance thresholds typically specify minimum humidity levels.',
    `inversion_risk` BOOLEAN COMMENT 'Indicates whether atmospheric temperature inversion conditions are present or forecast during the spray window. Temperature inversions trap spray droplets near the ground and cause unpredictable drift; most regulatory bodies and labels prohibit spraying during inversion conditions.',
    `ipm_pest_pressure` STRING COMMENT 'Integrated Pest Management (IPM) pest pressure classification at the time of the spray window, used to determine application urgency and prioritise scheduling within available windows. Derived from scouting observations and GDD-based pest models.. Valid values are `low|moderate|high|critical`',
    `label_compliant` BOOLEAN COMMENT 'Indicates whether all meteorological conditions within this spray window satisfy the agrochemical product label requirements for application (wind speed, temperature, humidity, Delta-T, precipitation-free period). Master compliance flag for regulatory audit purposes.',
    `phi_days` STRING COMMENT 'The Pre-Harvest Interval (PHI) in days for the planned agrochemical product, representing the minimum number of days that must elapse between the last application and crop harvest. Ensures Maximum Residue Limits (MRL) are not exceeded at harvest.',
    `precip_free_hours` DECIMAL(18,2) COMMENT 'Minimum number of hours without precipitation required after application for the planned agrochemical product to achieve label-specified efficacy. Sourced from product label requirements and used to validate window suitability.',
    `precip_probability_pct` DECIMAL(18,2) COMMENT 'Forecast probability of precipitation (%) during or immediately following the spray window. High precipitation probability risks product wash-off, reducing efficacy and potentially causing runoff into water bodies. Most labels specify minimum dry periods post-application.',
    `rei_compliant` BOOLEAN COMMENT 'Indicates whether the spray window timing satisfies the Restricted Entry Interval (REI) requirements for the planned agrochemical product, ensuring workers cannot re-enter treated areas before the REI expires. Derived from window_end plus the product-specific REI duration.',
    `rei_hours` DECIMAL(18,2) COMMENT 'The Restricted Entry Interval (REI) duration in hours applicable to the planned agrochemical product for this spray window. Defines the minimum time workers must stay out of treated areas after application. Sourced from the product label and EPA registration.',
    `sensitive_area_proximity_m` DECIMAL(18,2) COMMENT 'Distance in metres from the field boundary to the nearest sensitive area (water body, school, residential zone, organic buffer zone). Used to apply appropriate buffer zone restrictions and drift management requirements.',
    `solar_radiation_mj_m2` DECIMAL(18,2) COMMENT 'Solar radiation in megajoules per square metre during the spray window period. High solar radiation increases volatilisation risk for certain herbicides and affects photodegradation rates of active ingredients.',
    `state_drift_constraint` BOOLEAN COMMENT 'Indicates whether state-level pesticide drift regulations impose additional constraints on this spray window beyond federal EPA requirements. State regulations may be more restrictive than federal standards.',
    `temp_max_c` DECIMAL(18,2) COMMENT 'Maximum air temperature in degrees Celsius during the spray window period. High temperatures increase volatilisation and drift risk; many labels specify maximum temperature limits for application.',
    `temp_min_c` DECIMAL(18,2) COMMENT 'Minimum air temperature in degrees Celsius during the spray window period. Temperature thresholds affect pesticide efficacy, volatilisation risk, and label compliance for temperature-sensitive products.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this spray window record was last modified. Tracks recalculations triggered by updated forecast data or manual overrides. Supports audit trail and data quality monitoring.',
    `wind_direction_deg` DECIMAL(18,2) COMMENT 'Prevailing wind direction in degrees (0–360, meteorological convention) during the spray window. Used to assess drift trajectory relative to sensitive areas, water bodies, and neighbouring fields.',
    `wind_speed_max_kmh` DECIMAL(18,2) COMMENT 'Maximum observed or forecast wind speed in kilometres per hour during the spray window period. Exceeding label-specified maximum wind speed thresholds triggers window closure to prevent off-target drift.',
    `wind_speed_min_kmh` DECIMAL(18,2) COMMENT 'Minimum observed or forecast wind speed in kilometres per hour during the spray window period. Used to assess drift risk and label compliance; most pesticide labels require a minimum wind speed to ensure adequate air movement.',
    `window_duration_min` STRING COMMENT 'Calculated duration of the spray window in minutes, derived from window_start and window_end. Stored for operational scheduling and equipment dispatch planning without requiring runtime calculation.',
    `window_end` TIMESTAMP COMMENT 'The datetime marking the close of the meteorologically permissible application window. Spray operations must cease by this time to remain within label-compliant and regulatory-compliant conditions.',
    `window_reference_code` STRING COMMENT 'Externally-known business identifier for this spray window record, used in crop protection planning workflows, application scheduling, and audit documentation. Format: SW- followed by alphanumeric characters.. Valid values are `^SW-[A-Z0-9]{4,20}$`',
    `window_source` STRING COMMENT 'Indicates whether this spray window was calculated from forecast weather data, actual observed data, manually entered conditions, or a blended model output. Affects confidence level and audit trail for regulatory documentation.. Valid values are `forecast|observation|manual|model`',
    `window_start` TIMESTAMP COMMENT 'The principal business event timestamp marking the beginning of the meteorologically permissible application window. Represents the earliest datetime at which spray operations may commence under current conditions.',
    `window_status` STRING COMMENT 'Current lifecycle status of the spray window record. open indicates meteorological conditions are permissible for application; closed indicates conditions are not met; pending indicates evaluation in progress; expired indicates the window datetime has passed; cancelled indicates the window was voided.. Valid values are `open|closed|pending|expired|cancelled`',
    `window_type` STRING COMMENT 'Classification of the agrochemical application type for which this spray window is calculated. Determines applicable regulatory constraints, label requirements, and drift risk thresholds. [ENUM-REF-CANDIDATE: pesticide|herbicide|fungicide|insecticide|fertilizer|growth_regulator|adjuvant|micronutrient — promote to reference product]. Valid values are `pesticide|herbicide|fungicide|insecticide|fertilizer|growth_regulator`',
    CONSTRAINT pk_spray_window PRIMARY KEY(`spray_window_id`)
) COMMENT 'Calculated time window record defining meteorologically permissible periods for pesticide, herbicide, or fertilizer application at field level. Stores window start/end datetime, wind speed range, temperature range, humidity range, inversion risk flag, delta-T value, REI (Restricted Entry Interval) compliance status, and EPA/state drift regulation constraint flags. Weather domain SSOT for application-window meteorological feasibility; integrates with crop protection planning workflows for label-compliant scheduling.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`planting_window` (
    `planting_window_id` BIGINT COMMENT 'Unique system-generated identifier for the planting window record.',
    `crop_enterprise_budget_id` BIGINT COMMENT 'Foreign key linking to finance.crop_enterprise_budget. Business justification: Approved planting windows determine the crop calendar that anchors enterprise budget revenue recognition timing and planting cost scheduling. Budget planners use final planting dates from planting win',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field for which this planting window is calculated. Links to the field master record containing geographic boundaries, soil type, and historical yield data.',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to weather.forecast. Business justification: Planting windows are calculated using weather forecast data (temperature forecasts, precipitation probability, ET forecast, GDD outlook). Linking planting_window to the specific forecast record used d',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season within which this planting window falls, enabling seasonal aggregation and year-over-year comparison of planting window analytics.',
    `seed_variety_id` BIGINT COMMENT 'Foreign key linking to product.seed_variety. Business justification: Planting window suitability assessments are variety-specific — soil_temp thresholds, GDD outlook, and frost_risk_probability must be evaluated against the seed varietys recommended_planting_regions, ',
    `soil_profile_id` BIGINT COMMENT 'Foreign key linking to land.soil_profile. Business justification: Planting window calculations depend on soil drainage class, texture, and bulk density to assess trafficability and soil warming rates. Linking planting_window to land.soil_profile allows agronomists t',
    `soil_temperature_id` BIGINT COMMENT 'Foreign key linking to weather.soil_temperature. Business justification: Planting window calculations are critically dependent on soil temperature (minimum soil temp thresholds for germination vary by crop). planting_window has soil_temp_2in_c and soil_temp_4in_c — these a',
    `station_id` BIGINT COMMENT 'Reference to the primary weather station providing meteorological data inputs for this planting window calculation, including temperature, precipitation, and evapotranspiration (ET) readings.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Planting windows are calculated for geographic zones as well as individual fields. planting_window has geographic_zone_code (STRING) which is a denormalized reference to weather_zone.zone_code. Adding',
    `agronomist_approved` BOOLEAN COMMENT 'Indicates whether a certified agronomist has reviewed and approved this planting window recommendation before it is used for operational planting decisions. Required for compliance with GLOBALG.A.P. and internal Good Agricultural Practices (GAP) protocols.',
    `air_temp_max_forecast_c` DECIMAL(18,2) COMMENT 'Forecast maximum air temperature in degrees Celsius for the planting window period. Used to assess heat stress risk and optimal growing degree day (GDD) accumulation potential during early crop establishment.',
    `air_temp_min_forecast_c` DECIMAL(18,2) COMMENT 'Forecast minimum air temperature in degrees Celsius for the planting window period. Used to assess frost risk and cold stress potential for newly planted seeds and emerging seedlings.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the agronomist or authorized user approved this planting window record for operational use. Null if agronomist_approved is False.',
    `calculated_timestamp` TIMESTAMP COMMENT 'The date and time when this planting window record was first calculated and created in the system. Serves as the principal business event timestamp for the planting window lifecycle.',
    `calculation_method` STRING COMMENT 'Method used to derive the planting window. Algorithmic uses rule-based thresholds; model_based uses predictive weather models; manual indicates agronomist override; hybrid combines automated calculation with manual adjustment.. Valid values are `algorithmic|model_based|manual|hybrid`',
    `confidence_level` STRING COMMENT 'Qualitative confidence level of the planting window calculation based on the reliability of input weather forecast data and soil sensor readings. High confidence indicates short-range forecasts with high-quality sensor data; low confidence indicates extended-range forecasts or missing sensor inputs.. Valid values are `high|medium|low`',
    `data_source` STRING COMMENT 'Primary data source system used to generate the planting window calculation. Identifies the originating system for data lineage, quality auditing, and source reconciliation purposes. [ENUM-REF-CANDIDATE: climate_fieldview|dtn|noaa|iot_sensor|trimble|manual|granular — promote to reference product]',
    `et_forecast_mm` DECIMAL(18,2) COMMENT 'Forecast evapotranspiration (ET) in millimeters for the planting window period, representing estimated water loss from soil evaporation and plant transpiration. Used for irrigation scheduling and water balance calculations during early crop establishment.',
    `field_area_ha` DECIMAL(18,2) COMMENT 'Total plantable area of the field in hectares applicable to this planting window. Used for seed quantity calculations, equipment scheduling, and labor resource planning.',
    `final_planting_date` DATE COMMENT 'The USDA Risk Management Agency (RMA) designated final planting date for the primary crop type in this geographic area. Planting after this date may result in reduced crop insurance coverage or late-planting payment reductions.',
    `forecast_horizon_days` STRING COMMENT 'Number of days ahead from the calculation timestamp that the weather forecast data covers. Shorter horizons (1–7 days) yield higher confidence planting windows; longer horizons (8–14+ days) are used for preliminary planning.',
    `frost_risk_probability_pct` DECIMAL(18,2) COMMENT 'Estimated probability (0–100%) of a frost event occurring during the planting window period. Derived from forecast minimum temperatures and historical climatological data. High frost risk may delay planting of frost-sensitive crops.',
    `gdd_base_temp_c` DECIMAL(18,2) COMMENT 'Base temperature in degrees Celsius used in the Growing Degree Day (GDD) calculation for this planting window. Varies by crop type (e.g., 10°C for corn, 7.2°C for wheat). Ensures GDD outlook values are crop-specific and agronomically meaningful.',
    `gdd_outlook` DECIMAL(18,2) COMMENT 'Forecast accumulated Growing Degree Days (GDD) expected during the planting window period, calculated using the standard base temperature method. Supports crop maturity scheduling and hybrid/variety selection decisions.',
    `insurance_relevant` BOOLEAN COMMENT 'Indicates whether this planting window record is relevant for crop insurance documentation purposes, such as establishing the planted-within-final-planting-date compliance required by USDA Risk Management Agency (RMA) crop insurance policies.',
    `irrigation_required` BOOLEAN COMMENT 'Indicates whether supplemental irrigation is recommended prior to or during the planting window to achieve adequate soil moisture for seed germination. Derived from soil moisture levels and evapotranspiration (ET) forecast.',
    `notes` STRING COMMENT 'Free-text field for agronomist or field manager observations, special conditions, or operational notes associated with this planting window, such as localized drainage issues, equipment availability constraints, or crop variety-specific considerations.',
    `precip_forecast_mm` DECIMAL(18,2) COMMENT 'Total forecast precipitation in millimeters expected during the planting window period. Excessive precipitation may delay planting operations and increase disease pressure; insufficient precipitation may require supplemental irrigation scheduling.',
    `precip_probability_pct` DECIMAL(18,2) COMMENT 'Forecast probability of precipitation occurrence (0–100%) during the planting window period. Used in conjunction with precipitation amount forecast to assess planting operation scheduling risk.',
    `recommended_crop_types` STRING COMMENT 'Comma-separated list of crop types agronomically recommended for planting during this window based on soil temperature, moisture, and forecast conditions (e.g., corn,soybean,wheat). Supports crop planning and seed procurement decisions.',
    `soil_moisture_pct` DECIMAL(18,2) COMMENT 'Volumetric soil moisture content expressed as a percentage at the time of window calculation. Used to assess field trafficability and seed-to-soil contact conditions. Values above field capacity indicate risk of compaction and poor germination.',
    `soil_temp_2in_c` DECIMAL(18,2) COMMENT 'Measured or forecast soil temperature at 2-inch (5 cm) depth in degrees Celsius at the time of window calculation. Critical threshold indicator for seed germination viability, particularly for corn (minimum 10°C) and soybean (minimum 12°C).',
    `soil_temp_4in_c` DECIMAL(18,2) COMMENT 'Measured or forecast soil temperature at 4-inch (10 cm) depth in degrees Celsius at the time of window calculation. Provides a more stable and agronomically representative temperature reading for seed placement depth decisions.',
    `spray_window_open` BOOLEAN COMMENT 'Indicates whether conditions during the planting window are also suitable for pre-plant herbicide or pesticide application. True when wind speed, temperature, and precipitation conditions meet EPA and label requirements for safe and effective chemical application.',
    `trafficability_score` DECIMAL(18,2) COMMENT 'Composite score (0.00–10.00) representing the ability of the field to support heavy planting equipment without causing soil compaction or rutting. Derived from soil moisture, soil texture, and recent precipitation data. Scores below 5.0 indicate high compaction risk.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this planting window record was last modified, such as when forecast data was refreshed, agronomist adjustments were applied, or status was changed.',
    `window_duration_days` STRING COMMENT 'Total number of calendar days in the planting window from start date to end date inclusive. Used for scheduling labor, equipment, and seed delivery logistics.',
    `window_end_date` DATE COMMENT 'The last date of the calculated optimal planting window, representing the latest date on which planting is agronomically recommended before yield penalties or crop development risks increase significantly.',
    `window_number` STRING COMMENT 'Externally-known business identifier for the planting window, used in Farm Management Information System (FMIS) references and field operations documentation. Format: PW-{YEAR}-{SEQUENCE}.. Valid values are `^PW-[0-9]{4}-[0-9]{6}$`',
    `window_start_date` DATE COMMENT 'The first date of the calculated optimal planting window, representing the earliest date on which field conditions meet all agronomic thresholds for planting operations to commence.',
    `window_status` STRING COMMENT 'Current lifecycle state of the planting window record, indicating whether it is in draft calculation, open for scheduling, actively being used for planting operations, closed after the window has passed, or cancelled due to adverse conditions.. Valid values are `draft|open|active|closed|cancelled`',
    `window_type` STRING COMMENT 'Classification of the planting window quality tier. Optimal windows meet all agronomic thresholds; acceptable windows meet minimum thresholds with minor risk; marginal windows carry elevated yield risk; emergency windows are used only when seasonal deadlines force planting under suboptimal conditions.. Valid values are `optimal|acceptable|marginal|emergency`',
    CONSTRAINT pk_planting_window PRIMARY KEY(`planting_window_id`)
) COMMENT 'Calculated time window record identifying optimal periods for field planting operations based on soil temperature thresholds, soil moisture levels, air temperature forecasts, and precipitation outlook. Stores window start/end dates, soil temperature at 2-inch and 4-inch depth, field trafficability score, frost risk probability, GDD accumulation outlook, and recommended crop types for the window.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`climate_risk_indicator` (
    `climate_risk_indicator_id` BIGINT COMMENT 'Unique surrogate identifier for the climate risk indicator record. Primary key for the climate_risk_indicator data product in the weather domain.',
    `climate_normal_id` BIGINT COMMENT 'Foreign key linking to weather.climate_normal. Business justification: Seasonal and long-range climate risk assessments are evaluated against historical climate normals (30-year baselines). climate_risk_indicator has precip_anomaly_pct, temp_anomaly_c, gdd_deviation — th',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Climate risk indicators drive commodity supply forecasting and WASDE outlook alignment — wasde_outlook_alignment on climate_risk_indicator directly references commodity-level supply projections. Estim',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Climate risk indicators drive field-level crop insurance decisions, precision ag interventions, and adaptation planning. climate_risk_indicator currently only links to farm_unit; field-level risk asse',
    `station_id` BIGINT COMMENT 'Reference to the primary weather station providing meteorological data underpinning this climate risk assessment. Sourced from DTN weather feeds and IoT field sensor networks.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Seasonal and long-range climate risk assessments are performed at the geographic zone level. climate_risk_indicator has geographic_zone_code (STRING) which is a denormalized reference to weather_zone.',
    `adaptation_action_required` BOOLEAN COMMENT 'Indicates whether this climate risk assessment has triggered a recommended capital planning or operational adaptation action (e.g., irrigation infrastructure investment, cover crop adoption, drainage improvement).',
    `affected_area_ha` DECIMAL(18,2) COMMENT 'Estimated or actual area in hectares within the geographic zone or farm unit that is exposed to the assessed climate risk. Supports crop insurance documentation and loss estimation.',
    `assessment_date` DATE COMMENT 'The calendar date on which this climate risk assessment was generated or last formally evaluated. Used for temporal alignment with WASDE seasonal outlooks and crop insurance documentation.',
    `assessment_horizon` STRING COMMENT 'Time horizon classification for this climate risk assessment, indicating whether it covers a single season, annual, multi-year, or long-range planning period. Supports capital planning and crop insurance alignment.. Valid values are `seasonal|annual|multi_year|long_range`',
    `confidence_level` STRING COMMENT 'Qualitative confidence level assigned to this climate risk assessment, reflecting data quality, model certainty, and forecast skill. Supports risk management decision-making and insurance underwriting.. Valid values are `high|medium|low`',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code for the country in which the assessed geographic zone is located. Supports COOL (Country of Origin Labeling) compliance and international regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this climate risk indicator record was first created in the Databricks Lakehouse Silver Layer. Supports data lineage, audit trail, and SOX financial reporting controls.',
    `data_source` STRING COMMENT 'Identifies the primary data source or feed from which the climate risk assessment data was derived. Supports data lineage, quality assurance, and audit trail requirements.. Valid values are `dtn|climate_fieldview|noaa|iot_sensor|wasde|manual`',
    `drought_index_value` DECIMAL(18,2) COMMENT 'Standardized drought index value (e.g., Palmer Drought Severity Index or PDSI) for the assessment zone and period. Applicable when risk_type is drought; null otherwise. Supports irrigation scheduling and crop insurance documentation.',
    `enso_phase` STRING COMMENT 'Current El Niño–Southern Oscillation (ENSO) phase influencing the climate risk assessment. ENSO phase is a primary driver of seasonal precipitation and temperature anomalies affecting agricultural production.. Valid values are `el_nino|la_nina|neutral`',
    `estimated_yield_impact_pct` DECIMAL(18,2) COMMENT 'Estimated percentage reduction in crop yield attributable to the assessed climate risk event, based on historical loss data and agronomic models. Supports crop insurance underwriting and enterprise risk management.',
    `et_deficit_mm` DECIMAL(18,2) COMMENT 'Estimated Evapotranspiration (ET) deficit in millimeters for the assessment zone and period, representing the gap between crop water demand and available supply. Supports irrigation scheduling and drought risk assessment.',
    `frost_risk_days` STRING COMMENT 'Number of days within the assessment window with a forecast or historical probability of frost occurrence. Applicable when risk_type is late_frost; supports planting window decisions and crop insurance documentation.',
    `gdd_deviation` DECIMAL(18,2) COMMENT 'Deviation of accumulated Growing Degree Days (GDD) from the historical average for the assessment period. Supports planting window decisions, crop maturity forecasting, and pest pressure prediction.',
    `hail_risk_index` DECIMAL(18,2) COMMENT 'Composite index score quantifying hail risk for the assessment zone and period, derived from historical hail frequency and storm climatology data. Applicable when risk_type is hail; supports crop insurance underwriting.',
    `historical_frequency_years` DECIMAL(18,2) COMMENT 'Average recurrence interval in years for this risk type at this geographic zone, derived from historical climate records. Supports long-term capital planning and crop insurance actuarial analysis.',
    `indicator_code` STRING COMMENT 'Externally-known business identifier code for this climate risk indicator record, used for cross-system reference in FMIS, Granular Farm Management, and crop insurance underwriting workflows.. Valid values are `^CRI-[A-Z0-9]{4,12}$`',
    `insurance_relevant` BOOLEAN COMMENT 'Indicates whether this climate risk indicator is relevant for crop insurance claim documentation or underwriting purposes under USDA Risk Management Agency programs.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude in decimal degrees of the centroid of the assessed geographic zone or farm unit. Supports GIS spatial analysis in Esri ArcGIS and precision agriculture workflows.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude in decimal degrees of the centroid of the assessed geographic zone or farm unit. Supports GIS spatial analysis in Esri ArcGIS and precision agriculture workflows.',
    `model_version` STRING COMMENT 'Version identifier of the climate risk assessment model or algorithm used to generate this indicator record. Supports reproducibility, model governance, and AI/ML lineage tracking.. Valid values are `^[A-Za-z0-9._-]{1,30}$`',
    `occurrence_probability_pct` DECIMAL(18,2) COMMENT 'Estimated probability (0.00–100.00%) that the assessed climate risk event will occur within the valid assessment window. Used in crop insurance underwriting and actuarial modeling.',
    `precip_anomaly_pct` DECIMAL(18,2) COMMENT 'Percentage deviation of observed or forecast precipitation from the long-term historical average for the assessment period and zone. Positive values indicate excess; negative values indicate deficit. Supports flood and drought risk quantification.',
    `recommended_action` STRING COMMENT 'Free-text description of the recommended agronomic or capital investment action to mitigate or adapt to the assessed climate risk. Supports Best Management Practices (BMP) documentation and SOP compliance.',
    `risk_notes` STRING COMMENT 'Free-text field for additional context, qualifications, or observations related to this climate risk indicator record. Supports analyst commentary and audit documentation.',
    `risk_severity_index` DECIMAL(18,2) COMMENT 'Quantitative index score representing the severity of the assessed climate risk, typically on a normalized scale (e.g., 0.00–100.00). Drives prioritization in enterprise risk management and capital planning for climate adaptation.',
    `risk_status` STRING COMMENT 'Current lifecycle status of this climate risk indicator record, indicating whether the risk is actively being monitored, elevated to alert level, resolved, or archived for historical reference.. Valid values are `active|monitoring|elevated|resolved|archived`',
    `risk_type` STRING COMMENT 'Classification of the primary climate risk event type being assessed. Drives crop insurance underwriting, enterprise risk management, and capital planning for climate adaptation investments.. Valid values are `drought|flood|heat_stress|late_frost|hail|excessive_wind`',
    `temp_anomaly_c` DECIMAL(18,2) COMMENT 'Deviation of observed or forecast temperature in degrees Celsius from the long-term historical average for the assessment period and zone. Supports heat stress and late frost risk quantification.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this climate risk indicator record was last modified in the Databricks Lakehouse Silver Layer. Supports change tracking, data quality monitoring, and audit trail requirements.',
    `wasde_outlook_alignment` STRING COMMENT 'Alignment of this climate risk assessment with the USDA World Agricultural Supply and Demand Estimates (WASDE) seasonal outlook for precipitation or temperature. Supports enterprise risk management and long-range planning.. Valid values are `above_normal|normal|below_normal|not_assessed`',
    `wind_risk_index` DECIMAL(18,2) COMMENT 'Composite index score quantifying excessive wind risk for the assessment zone and period. Applicable when risk_type is excessive_wind; supports crop insurance underwriting and spray window planning.',
    `valid_from` DATE COMMENT 'Start date of the period for which this climate risk indicator is considered valid and applicable. Defines the seasonal or long-range assessment window.',
    `valid_to` DATE COMMENT 'End date of the period for which this climate risk indicator is considered valid. Nullable for open-ended long-range assessments. Supports crop insurance policy period alignment.',
    CONSTRAINT pk_climate_risk_indicator PRIMARY KEY(`climate_risk_indicator_id`)
) COMMENT 'Seasonal and long-range climate risk assessment record for a geographic zone or farm unit. Captures risk type (drought, flood, heat stress, late frost, hail, excessive wind), risk severity index, probability of occurrence, affected crop types, historical frequency, ENSO phase influence, and WASDE seasonal outlook alignment. Supports crop insurance underwriting, enterprise risk management, and long-term capital planning for climate adaptation investments.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`drought_index` (
    `drought_index_id` BIGINT COMMENT 'Unique surrogate identifier for each drought index monitoring record in the silver layer lakehouse.',
    `climate_normal_id` BIGINT COMMENT 'Foreign key linking to weather.climate_normal. Business justification: Drought indices (SPI, PDSI, CMI) are calculated by comparing actual precipitation and temperature against long-term climate normals. drought_index has precip_normal_mm — this is a denormalized value f',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or management zone for which this drought index record applies. Supports field-level irrigation scheduling and crop insurance documentation.',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor that provided the meteorological observations underpinning this drought index calculation.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Drought monitoring indices are tracked at the geographic zone level (USDA drought monitor uses zone-based reporting). drought_index has geographic_zone_code (STRING) which is a denormalized reference ',
    `affected_area_ha` DECIMAL(18,2) COMMENT 'Total land area in hectares affected by the drought condition represented in this record. Used for crop insurance claim quantification, USDA disaster designation documentation, and irrigation resource planning.',
    `cmi_value` DECIMAL(18,2) COMMENT 'Crop Moisture Index value measuring short-term moisture conditions critical to crop development. Negative values indicate moisture stress affecting crop growth. Published weekly by USDA and used to assess in-season crop moisture adequacy for irrigation scheduling.',
    `consecutive_dry_days` STRING COMMENT 'Number of consecutive days with precipitation below the dry-day threshold (typically < 1 mm/day). A key indicator of agricultural drought onset and persistence. Used to trigger irrigation scheduling recommendations and crop insurance claim documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this drought index record was first created in the silver layer lakehouse. Supports audit trail, data lineage, and compliance documentation requirements.',
    `data_source` STRING COMMENT 'Originating data source system or feed for this drought index record. DTN = DTN Weather Data Network; NOAA = National Oceanic and Atmospheric Administration; USDA_NASS = USDA National Agricultural Statistics Service; CLIMATE_FIELDVIEW = Climate FieldView platform; IOT_SENSOR = IoT field sensor network; USDM = US Drought Monitor; MANUAL = manually entered record. [ENUM-REF-CANDIDATE: DTN|NOAA|USDA_NASS|CLIMATE_FIELDVIEW|IOT_SENSOR|USDM|MANUAL — 7 candidates stripped; promote to reference product]',
    `drought_category` STRING COMMENT 'US Drought Monitor (USDM) drought category classification: None = No drought; D0 = Abnormally Dry; D1 = Moderate Drought; D2 = Severe Drought; D3 = Extreme Drought; D4 = Exceptional Drought. Used for USDA disaster designation documentation and federal crop insurance eligibility.. Valid values are `None|D0|D1|D2|D3|D4`',
    `drought_status` STRING COMMENT 'Current operational status of the drought condition for this record. Indicates whether drought conditions are active, trending toward improvement or deterioration, or have been resolved. Drives alert notifications and irrigation scheduling decisions.. Valid values are `active|improving|deteriorating|resolved|watch|warning`',
    `estimated_yield_loss_pct` DECIMAL(18,2) COMMENT 'Estimated percentage reduction in crop yield attributable to drought stress conditions represented by this index record. Used for crop insurance claim documentation, USDA disaster designation support, and financial loss estimation in Granular Farm Management.',
    `et_actual_mm` DECIMAL(18,2) COMMENT 'Actual evapotranspiration in millimeters for the index period, representing the combined water loss from soil evaporation and plant transpiration. Used in soil moisture deficit calculations and drought severity assessments. Sourced from IoT field sensors or DTN weather feeds.',
    `index_date` DATE COMMENT 'Calendar date for which this drought index record is valid. Represents the observation or reporting date used for drought severity assessment and USDA disaster designation documentation.',
    `index_type` STRING COMMENT 'Classification of the drought index methodology used for this record. PDSI = Palmer Drought Severity Index; SPI = Standardized Precipitation Index; CMI = Crop Moisture Index; NDVI_STRESS = Normalized Difference Vegetation Index-derived vegetation stress; SPEI = Standardized Precipitation Evapotranspiration Index; EDDI = Evaporative Demand Drought Index.. Valid values are `PDSI|SPI|CMI|NDVI_STRESS|SPEI|EDDI`',
    `index_value` DECIMAL(18,2) COMMENT 'Computed numeric value of the drought index for the specified index_type. For PDSI, ranges approximately -10 (extreme drought) to +10 (extreme wet). For SPI, standardized z-score. For CMI, inches of moisture deficit or surplus. Feeds irrigation scheduling algorithms and crop insurance claim triggers.',
    `insurance_claim_relevant` BOOLEAN COMMENT 'Indicates whether this drought index record meets the threshold criteria to support a crop insurance claim under USDA Risk Management Agency (RMA) policies. True = record qualifies as supporting evidence for an insurance claim filing.',
    `irrigation_deficit_mm` DECIMAL(18,2) COMMENT 'Recommended irrigation application amount in millimeters to address the current soil moisture deficit. Computed from the soil moisture deficit adjusted for irrigation efficiency. Used to generate variable rate application (VRA) prescriptions.',
    `irrigation_recommended` BOOLEAN COMMENT 'Indicates whether irrigation is recommended based on the current drought index values and soil moisture deficit. True = irrigation action recommended. Drives automated irrigation scheduling workflows in Trimble Ag Software and John Deere Operations Center.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude in decimal degrees (WGS84) of the centroid or representative point for this drought index record. Supports spatial analysis in Esri ArcGIS and integration with USDM drought polygon overlays.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude in decimal degrees (WGS84) of the centroid or representative point for this drought index record. Supports spatial analysis in Esri ArcGIS and integration with USDM drought polygon overlays.',
    `ndvi_stress_index` DECIMAL(18,2) COMMENT 'NDVI-derived vegetation stress indicator computed from satellite or drone imagery. Values range from -1 to +1; lower values indicate greater vegetation stress due to moisture deficit. Integrates with Climate FieldView and Esri ArcGIS for spatial drought impact mapping.',
    `pdsi_value` DECIMAL(18,2) COMMENT 'Palmer Drought Severity Index value for this record period. Ranges from approximately -10 (extreme drought) to +10 (extreme wet conditions). Negative values indicate moisture deficit. Used for USDA disaster designation and crop insurance documentation.',
    `precip_actual_mm` DECIMAL(18,2) COMMENT 'Observed precipitation in millimeters accumulated over the index period. Used as the primary input for SPI and CMI calculations and for comparison against normal precipitation to quantify drought severity.',
    `precip_departure_pct` DECIMAL(18,2) COMMENT 'Percentage departure of actual precipitation from the climatological normal for the index period. Negative values indicate below-normal precipitation contributing to drought conditions. Key metric for USDA disaster designation documentation.',
    `quality_flag` STRING COMMENT 'Quality control flag indicating the reliability and completeness of the drought index data in this record. Good = passed all QC checks; Suspect = potential data quality issue requiring review; Missing = one or more input values absent; Estimated = value gap-filled or interpolated; Corrected = value was adjusted post-QC.. Valid values are `good|suspect|missing|estimated|corrected`',
    `soil_moisture_deficit_mm` DECIMAL(18,2) COMMENT 'Estimated soil moisture deficit in millimeters representing the amount of water needed to bring soil to field capacity. Derived from water balance calculations incorporating precipitation, evapotranspiration (ET), and runoff. Directly drives variable rate irrigation prescriptions.',
    `source_record_code` STRING COMMENT 'External identifier or reference number from the originating source system (e.g., USDM polygon ID, DTN record ID, Climate FieldView observation ID). Supports data lineage traceability and reconciliation with upstream systems.',
    `spi_time_scale_months` STRING COMMENT 'Accumulation period in months over which the SPI value was calculated (e.g., 1, 3, 6, 12, 24 months). Short time scales reflect agricultural drought; longer scales reflect hydrological drought. Required for correct interpretation of the SPI value.',
    `spi_value` DECIMAL(18,2) COMMENT 'Standardized Precipitation Index value representing precipitation deficit or surplus as a standardized z-score relative to the historical distribution. Negative values indicate below-normal precipitation. Computed for the SPI time scale specified in spi_time_scale_months.',
    `spray_window_open` BOOLEAN COMMENT 'Indicates whether current drought and weather conditions support an open spray application window for pesticide or fertilizer application. Drought conditions may affect spray efficacy and drift risk. Integrates with IPM protocols and EPA REI compliance.',
    `temp_avg_c` DECIMAL(18,2) COMMENT 'Mean air temperature in degrees Celsius for the index period. Elevated temperatures accelerate evapotranspiration and exacerbate drought conditions. Used in PDSI and SPEI calculations and for heat stress assessment in conjunction with drought monitoring.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this drought index record was last modified in the silver layer lakehouse. Used for incremental data processing, change detection, and audit trail maintenance.',
    `usda_disaster_designation` BOOLEAN COMMENT 'Indicates whether the geographic area covered by this drought index record has received or is being considered for a USDA Secretarial Disaster Designation. True = disaster designation active or pending. Enables eligibility tracking for USDA emergency loan programs and FSA assistance.',
    CONSTRAINT pk_drought_index PRIMARY KEY(`drought_index_id`)
) COMMENT 'Drought monitoring index record tracking soil moisture deficit and drought severity for a field or geographic region. Stores Palmer Drought Severity Index (PDSI), Standardized Precipitation Index (SPI), Crop Moisture Index (CMI), NDVI-derived vegetation stress indicator, drought category (D0–D4 per USDM), and consecutive dry days count. Feeds irrigation scheduling, crop insurance claims, and USDA disaster designation documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`soil_temperature` (
    `soil_temperature_id` BIGINT COMMENT 'Primary key for soil_temperature',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or management zone where the soil temperature sensor is installed. Supports field-level agronomic analysis and planting window determination.',
    `sensor_id` BIGINT COMMENT 'Reference to the specific IoT soil temperature sensor device that produced this reading. Enables per-device calibration tracking and fault isolation.',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor node that captured this soil temperature reading. Links to the station master record.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Soil temperature readings are associated with geographic zones for regional agronomic analysis. soil_temperature has geographic_zone_code (STRING) which is a denormalized reference to weather_zone.zon',
    `ambient_air_temp_c` DECIMAL(18,2) COMMENT 'Concurrent ambient air temperature in degrees Celsius recorded at the same station at the time of the soil temperature reading. Provides context for soil-air temperature differential analysis and frost risk assessment.',
    `calibration_status` STRING COMMENT 'Current calibration status of the sensor at the time of this reading. calibrated = within valid calibration window; due = calibration scheduled; overdue = calibration window exceeded; failed = last calibration check failed; unknown = calibration record unavailable. Affects data trust level for agronomic decisions.. Valid values are `calibrated|due|overdue|failed|unknown`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this soil temperature reading record was first ingested into the silver layer lakehouse. Audit trail field for data governance and lineage tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `crop_type` STRING COMMENT 'The crop species or type associated with this soil temperature reading context (e.g., corn, soybeans, wheat, cotton). Used to apply crop-specific germination thresholds, GDD base temperatures, and planting window criteria. Null if the field has no active crop assignment.',
    `data_source` STRING COMMENT 'Originating system or method that produced this soil temperature reading. Supports data lineage, source reconciliation, and trust-level differentiation between automated sensor feeds and manual entries. [ENUM-REF-CANDIDATE: IoT_field_sensor|weather_station_probe|DTN_feed|manual_entry|Climate_FieldView|Trimble_Ag|FMIS|other — promote to reference product]. Valid values are `IoT_field_sensor|weather_station_probe|DTN_feed|manual_entry|Climate_FieldView|Trimble_Ag`',
    `depth_cm` DECIMAL(18,2) COMMENT 'Depth below soil surface at which the temperature measurement was taken, expressed in centimetres. Standard agricultural depths include 5 cm (2-inch), 10 cm (4-inch), 15 cm (6-inch), and 30 cm (12-inch). Critical for seed germination prediction and soil biological activity assessment.',
    `depth_inches` DECIMAL(18,2) COMMENT 'Depth below soil surface at which the temperature measurement was taken, expressed in inches (US customary). Common agricultural reference depths: 2-inch, 4-inch, 6-inch, 12-inch. Stored alongside cm value to support both US and metric reporting.',
    `ec_reading_ds_m` DECIMAL(18,2) COMMENT 'Electrical Conductivity (EC) co-reading captured simultaneously with the soil temperature measurement, expressed in deciSiemens per metre (dS/m). Available on multi-parameter sensors. EC indicates soil salinity and moisture levels, complementing temperature data for soil health assessment and irrigation scheduling.',
    `elevation_m` DECIMAL(18,2) COMMENT 'Elevation above mean sea level of the sensor location in metres. Influences soil temperature patterns and microclimate conditions. Used for topographic correction in spatial interpolation models.',
    `frost_risk_flag` BOOLEAN COMMENT 'Indicates whether this soil temperature reading falls at or below the frost threshold (typically 0°C / 32°F at the relevant depth), triggering frost risk conditions. Used for frost alert generation, crop protection decisions, and crop insurance documentation.',
    `gdd_base_temp_c` DECIMAL(18,2) COMMENT 'Base temperature in degrees Celsius used for the GDD contribution calculation for this reading. Varies by crop species (e.g., 10°C for corn, 4.4°C for wheat). Stored per reading to support multi-crop field analysis.',
    `gdd_contribution` DECIMAL(18,2) COMMENT 'Growing Degree Day (GDD) contribution calculated from this soil temperature reading relative to the configured base temperature. Supports cumulative GDD accumulation tracking for crop development stage prediction and planting window determination.',
    `insurance_relevant` BOOLEAN COMMENT 'Indicates whether this soil temperature reading is relevant for crop insurance documentation purposes (e.g., frost damage claims, planting date verification). When True, the record is retained in the insurance evidence dataset.',
    `last_calibration_date` DATE COMMENT 'Date on which the soil temperature sensor was most recently calibrated. Used to assess reading reliability and trigger maintenance workflows when calibration intervals are exceeded.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the soil temperature sensor location in decimal degrees (WGS84). Supports GIS-based spatial analysis, precision agriculture mapping, and integration with Esri ArcGIS.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the soil temperature sensor location in decimal degrees (WGS84). Supports GIS-based spatial analysis, precision agriculture mapping, and integration with Esri ArcGIS.',
    `measurement_interval_min` STRING COMMENT 'Configured interval in minutes between successive soil temperature readings from this sensor. Common values: 15, 30, 60 minutes. Used to identify gaps in the time series and validate reading frequency against sensor configuration.',
    `next_calibration_date` DATE COMMENT 'Scheduled date for the next sensor calibration. Supports preventive maintenance scheduling and ensures data quality compliance for crop insurance documentation and regulatory reporting.',
    `planting_window_suitable` BOOLEAN COMMENT 'Indicates whether the soil temperature at this reading meets the minimum threshold for planting the associated crop type. Derived from crop-specific germination temperature requirements. Supports planting window determination and field operations scheduling.',
    `qc_notes` STRING COMMENT 'Free-text notes added by automated QC processes or data stewards explaining quality flags, anomalies, or manual corrections applied to this reading. Supports audit trail and data governance review.',
    `quality_flag` STRING COMMENT 'Automated quality control flag applied during silver layer processing. PASS = no issues detected; RANGE_FAIL = value outside physically plausible range; SPIKE = sudden implausible change; FROZEN = sensor reporting constant value; DRIFT = gradual sensor degradation detected; MANUAL_OVERRIDE = value corrected by data steward.. Valid values are `PASS|RANGE_FAIL|SPIKE|FROZEN|DRIFT|MANUAL_OVERRIDE`',
    `reading_date` DATE COMMENT 'Calendar date of the soil temperature reading (yyyy-MM-dd). Used for daily aggregation, GDD accumulation calculations, and planting window reporting without requiring timestamp precision.',
    `reading_status` STRING COMMENT 'Quality status of the soil temperature reading indicating whether the value is usable for agronomic decisions. valid = passed all QC checks; suspect = flagged for review; invalid = failed QC; missing = no data received; estimated = gap-filled or interpolated value.. Valid values are `valid|suspect|invalid|missing|estimated`',
    `reading_timestamp` TIMESTAMP COMMENT 'The exact date and time (UTC) when the soil temperature measurement was recorded by the sensor or probe. Principal event timestamp for this observation. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `sensor_type` STRING COMMENT 'Technology type of the soil temperature sensor. Determines measurement accuracy characteristics and calibration requirements. Common types: thermistor (most common in agricultural IoT), thermocouple, RTD (Resistance Temperature Detector), infrared, fiber optic.. Valid values are `thermistor|thermocouple|RTD|infrared|fiber_optic`',
    `soil_moisture_pct` DECIMAL(18,2) COMMENT 'Volumetric soil moisture content (%) captured as a co-reading from multi-parameter sensors at the same depth and timestamp. Contextualises soil temperature readings for irrigation scheduling and germination prediction. Null when sensor does not support moisture measurement.',
    `soil_type_code` STRING COMMENT 'USDA soil texture classification code for the measurement location (e.g., SaL = Sandy Loam, SiCL = Silty Clay Loam). Soil type affects thermal conductivity and temperature dynamics. Supports soil-adjusted agronomic modelling.',
    `source_record_code` STRING COMMENT 'Original record identifier from the upstream source system (e.g., Climate FieldView reading UUID, DTN feed record ID, John Deere Operations Center telemetry ID). Supports data lineage tracing and deduplication in the silver layer.',
    `temperature_c` DECIMAL(18,2) COMMENT 'Measured soil temperature in degrees Celsius at the recorded depth. Principal quantitative measurement for this record. Used for GDD accumulation, seed germination thresholds, and soil biological activity assessment.',
    `temperature_f` DECIMAL(18,2) COMMENT 'Measured soil temperature in degrees Fahrenheit at the recorded depth. Stored alongside Celsius value to support US agronomic reporting, crop insurance documentation, and FMIS integrations that operate in Fahrenheit.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this soil temperature reading record was most recently modified in the silver layer (e.g., after QC correction or manual override). Audit trail field for data governance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_soil_temperature PRIMARY KEY(`soil_temperature_id`)
) COMMENT 'Soil temperature measurement record captured at defined depths (2-inch, 4-inch, 6-inch, 12-inch) from in-field IoT sensors or weather station probes. Stores reading timestamp, depth (inches/cm), temperature (°F/°C), sensor calibration status, and EC (Electrical Conductivity) co-reading where available. Critical for planting window determination, seed germination prediction, and soil biological activity assessment.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`zone` (
    `zone_id` BIGINT COMMENT 'Unique surrogate identifier for the weather zone record. Primary key for the weather_zone master resource in the Silver Layer lakehouse.',
    `arcgis_layer_code` STRING COMMENT 'Esri ArcGIS feature layer identifier for the polygon boundary of this weather zone. Enables direct linkage to the authoritative GIS boundary layer in the enterprise ArcGIS environment for spatial analysis, map rendering, and field-to-zone assignment workflows.',
    `area_ha` DECIMAL(18,2) COMMENT 'Total geographic area of the weather zone in hectares. Used for scaling ET water balance calculations, estimating total irrigation water demand, and proportional allocation of weather risk exposure across the farm portfolio.',
    `avg_annual_et_mm` DECIMAL(18,2) COMMENT 'Long-term average annual reference evapotranspiration (ET₀) for the weather zone in millimeters, based on historical climate normals. Foundational input for irrigation district water allocation planning and seasonal crop water demand estimation.',
    `avg_annual_precip_mm` DECIMAL(18,2) COMMENT 'Long-term average annual precipitation for the weather zone in millimeters, derived from historical climate normals (typically 30-year NOAA Climate Normals). Used as a baseline for irrigation planning, water budget modeling, and crop insurance actuarial calculations.',
    `avg_first_fall_frost_date` DATE COMMENT 'Average calendar date of the first fall frost event (MM-DD format) for this weather zone based on historical climate normals. Defines the end of the effective growing season and is used for harvest scheduling, crop insurance documentation, and GDD accumulation period calculations.',
    `avg_last_spring_frost_date` DATE COMMENT 'Average calendar date of the last spring frost event (MM-DD format) for this weather zone based on historical climate normals. Used to define the earliest safe planting window for frost-sensitive crops and to configure frost alert thresholds in the weather monitoring system.',
    `avg_temp_annual_c` DECIMAL(18,2) COMMENT 'Long-term average annual air temperature for the weather zone in degrees Celsius, based on NOAA 30-year climate normals. Used for climate classification validation, crop suitability analysis, and baseline calibration of GDD accumulation models.',
    `avg_temp_summer_c` DECIMAL(18,2) COMMENT 'Long-term average summer (June–August for Northern Hemisphere) air temperature for the weather zone in degrees Celsius. Used for heat stress risk assessment, irrigation demand forecasting, and crop variety heat tolerance matching.',
    `avg_temp_winter_c` DECIMAL(18,2) COMMENT 'Long-term average winter (December–February for Northern Hemisphere) air temperature for the weather zone in degrees Celsius. Used for winter crop survival modeling, livestock housing planning, and freeze risk baseline calibration.',
    `centroid_latitude` DECIMAL(18,2) COMMENT 'Decimal degrees latitude of the geographic centroid of the weather zone polygon (WGS84 datum). Used for ET calculations, solar radiation modeling, and GIS proximity analysis in Esri ArcGIS and Climate FieldView integrations.',
    `centroid_longitude` DECIMAL(18,2) COMMENT 'Decimal degrees longitude of the geographic centroid of the weather zone polygon (WGS84 datum). Used alongside centroid_latitude for spatial joins, weather station proximity matching, and GIS-based agronomic analysis.',
    `climate_fieldview_zone_ref` STRING COMMENT 'External zone reference identifier used in the Climate FieldView platform to associate this master weather zone with FieldView field-level weather analytics, planting data, and spray window recommendations. Supports bi-directional data synchronization.',
    `climate_normal_base_period` STRING COMMENT 'The 30-year NOAA Climate Normal base period used to derive the long-term averages stored in this weather zone record (e.g., 1991-2020). Ensures transparency in climate baseline data provenance for agronomic modeling and regulatory reporting.. Valid values are `1981-2010|1991-2020|2001-2030`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country in which this weather zone is located (e.g., USA, CAN, BRA). Supports international operations and GLOBALG.A.P. geographic traceability requirements.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this weather zone record was first created in the Silver Layer lakehouse. Supports audit trail requirements, data lineage tracking, and SCD management for the master zone definition.',
    `data_source` STRING COMMENT 'Originating system or authoritative data source from which this weather zone definition was ingested or created. Used for data lineage tracking, quality assurance, and source system reconciliation in the Silver Layer lakehouse. [ENUM-REF-CANDIDATE: noaa_nws|usda_nrcs|esri_arcgis|dtn|climate_fieldview|manual|trimble_ag — 7 candidates stripped; promote to reference product]',
    `drought_risk_class` STRING COMMENT 'Categorical drought risk classification for this weather zone based on historical precipitation variability, soil water holding capacity, and USDA drought monitor data. Used for crop insurance risk rating, irrigation infrastructure investment prioritization, and USDA FSA disaster program eligibility assessment.. Valid values are `low|moderate|high|extreme`',
    `dtn_zone_code` STRING COMMENT 'DTN (Data Transmission Network) weather zone identifier used to subscribe to and ingest DTN commercial weather data feeds for this zone. Enables automated linkage between the master zone record and real-time DTN market and weather data services used in agricultural decision support.',
    `effective_from` DATE COMMENT 'Date from which this weather zone definition became operationally effective. Supports slowly changing dimension (SCD) management in the Silver Layer, ensuring historical weather observations and forecasts are correctly attributed to the zone boundary valid at the time of the event.',
    `effective_until` DATE COMMENT 'Date on which this weather zone definition ceases to be operationally effective (null for currently active zones). Supports SCD Type 2 versioning in the Silver Layer and ensures historical traceability for crop insurance documentation and regulatory audits.',
    `elevation_m` DECIMAL(18,2) COMMENT 'Mean elevation of the weather zone above sea level in meters. Elevation is a critical input for ET reference calculations (FAO Penman-Monteith), frost risk modeling, and atmospheric pressure adjustments in agronomic decision support.',
    `fema_flood_zone_code` STRING COMMENT 'FEMA National Flood Insurance Program (NFIP) flood zone designation code for this weather zone (e.g., AE, X, VE). Required for crop insurance underwriting, lender compliance, and USDA FSA disaster assistance program documentation.. Valid values are `^[A-Z]{1,3}[0-9]{0,2}$`',
    `fips_county_code` STRING COMMENT 'Five-digit FIPS county code (state FIPS + county FIPS) associated with this weather zone. Required for USDA FSA program reporting, crop insurance documentation under FCIC/RMA, and WASDE regional aggregation.. Valid values are `^[0-9]{5}$`',
    `flood_risk_class` STRING COMMENT 'Categorical flood risk classification for this weather zone based on FEMA flood zone designations and historical precipitation event data. Used for field drainage planning, crop insurance documentation, and USDA FSA disaster program eligibility.. Valid values are `low|moderate|high|extreme`',
    `frost_free_days` STRING COMMENT 'Average number of frost-free days per year for this weather zone, based on historical climate normals. Critical for determining viable planting windows, crop variety selection, and growing season length for annual crop planning.',
    `gdd_base10_annual_avg` DECIMAL(18,2) COMMENT 'Long-term average annual Growing Degree Day (GDD) accumulation for this weather zone using a base temperature of 10°C (50°F), based on historical climate normals. Used for crop maturity modeling, planting window optimization, and pest pressure prediction aligned with IPM programs.',
    `gis_boundary_wkt` STRING COMMENT 'Well-Known Text (WKT) representation of the weather zone polygon boundary, compatible with Esri ArcGIS and standard OGC geometry formats. Enables spatial queries, field-to-zone assignment, and precision agriculture map overlays in the lakehouse.',
    `gis_coordinate_system` STRING COMMENT 'Coordinate reference system (CRS) used for the GIS boundary geometry stored in gis_boundary_wkt. Ensures correct spatial interpretation when integrating with Esri ArcGIS, John Deere Operations Center, and Trimble Ag Software field mapping.. Valid values are `WGS84|NAD83|NAD27`',
    `koppen_climate_class` STRING COMMENT 'Köppen-Geiger climate classification code assigned to this weather zone (e.g., Cfa for humid subtropical, BSk for cold semi-arid). Used for long-range crop planning, seed selection, and agronomic benchmarking aligned with USDA Plant Hardiness Zone mapping.. Valid values are `^[A-E][a-z]{1,2}$`',
    `notes` STRING COMMENT 'Free-text field for agronomists and data stewards to record operational notes about this weather zone, such as boundary revision history, known data quality issues, special irrigation district agreements, or regulatory exceptions relevant to this zone.',
    `nws_zone_code` STRING COMMENT 'Official National Weather Service forecast zone identifier (e.g., ILZ043) used to link this weather zone to NWS Zone Forecast Products, frost/freeze watches, and severe weather alerts. Enables automated ingestion of NWS advisory feeds for spray window and frost alert processing.. Valid values are `^[A-Z]{2}Z[0-9]{3}$`',
    `primary_irrigation_source` STRING COMMENT 'Primary source of irrigation water available within this weather zone. Used for water resource planning, drought risk assessment, and compliance with EPA and state water rights regulations. Informs irrigation scheduling recommendations generated from ET calculations.. Valid values are `groundwater|surface_water|recycled_water|rainwater_harvesting|municipal|none`',
    `state_code` STRING COMMENT 'Two-letter USPS state abbreviation for the state in which this weather zone is primarily located (e.g., IL, IA, CA). Used for regulatory reporting to USDA, EPA, and state departments of agriculture.. Valid values are `^[A-Z]{2}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this weather zone record was most recently modified in the Silver Layer lakehouse. Used for incremental data pipeline processing, change detection, and audit trail compliance.',
    `usda_hardiness_zone` STRING COMMENT 'USDA Plant Hardiness Zone Map designation for this weather zone (e.g., 6b, 7a). Defines the average annual extreme minimum temperature range and is the standard reference for crop variety selection, perennial planting decisions, and seed catalog alignment.. Valid values are `^[0-9]{1,2}[ab]?$`',
    `zone_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the weather zone across operational systems (e.g., NWS forecast zone code, irrigation district code, FMIS zone identifier). Used as the business key for cross-system integration with John Deere Operations Center, Climate FieldView, and Trimble Ag Software.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `zone_name` STRING COMMENT 'Human-readable name of the weather zone (e.g., Central Valley Irrigation District Zone 4, Corn Belt County Zone - McLean IL). Used in reporting dashboards, irrigation scheduling interfaces, and Climate FieldView integrations.',
    `zone_status` STRING COMMENT 'Current lifecycle status of the weather zone master record. Active zones are used in operational irrigation scheduling, spray window calculations, and frost alert routing. Deprecated zones are retained for historical reporting and crop insurance documentation.. Valid values are `active|inactive|deprecated|pending_review`',
    `zone_type` STRING COMMENT 'Classification of the geographic aggregation boundary type used for weather observation and forecast grouping. Determines how the zone boundary is defined and which source systems feed data into it. [ENUM-REF-CANDIDATE: nws_forecast_zone|county|watershed|irrigation_district|farm_unit_polygon|climate_division|custom_polygon — promote to reference product if additional types are needed]. Valid values are `nws_forecast_zone|county|watershed|irrigation_district|farm_unit_polygon|climate_division`',
    CONSTRAINT pk_zone PRIMARY KEY(`zone_id`)
) COMMENT 'Master geographic zone definition used to aggregate weather observations and forecasts for agricultural planning. Stores zone identifier, zone type (NWS forecast zone, county, watershed, irrigation district, farm unit polygon), GIS boundary coordinates (ArcGIS-compatible), climate classification (Köppen), average annual precipitation, frost-free days, and hardiness zone (USDA Plant Hardiness Zone Map). SSOT for weather geographic aggregation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`climate_normal` (
    `climate_normal_id` BIGINT COMMENT 'Primary key for climate_normal',
    `station_id` BIGINT COMMENT 'Reference to the weather station or IoT field sensor network node for which this climate normal record was computed. Links to the station master record.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Climate normals (30-year WMO baselines) are computed for geographic zones. climate_normal already has geographic_zone_code (STRING) which is a denormalized reference to weather_zone.zone_code. Adding ',
    `avg_first_frost_date` DATE COMMENT '30-year average calendar date of the first autumn frost event (temperature ≤0°C) for the station or zone. Critical for determining planting windows, PHI compliance, and crop insurance documentation.',
    `avg_last_frost_date` DATE COMMENT '30-year average calendar date of the last spring frost event (temperature ≤0°C) for the station or zone. Defines the safe planting window start and is used in crop variety selection and GLOBALG.A.P. field records.',
    `climate_zone_classification` STRING COMMENT 'Köppen-Geiger climate classification code for the station or zone (e.g., Cfa = humid subtropical, Dfa = humid continental). Used for crop variety suitability mapping and GLOBALG.A.P. environmental risk assessments. [ENUM-REF-CANDIDATE: Af|Am|Aw|BSh|BSk|BWh|BWk|Cfa|Cfb|Cfc|Csa|Csb|Dfa|Dfb|Dfc|ET|EF — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this climate normal record was first ingested into the Agriculture data lakehouse Silver layer. Supports data lineage, audit trails, and SOX financial reporting controls where climate data informs crop insurance valuations.',
    `data_source` STRING COMMENT 'Primary source system or data feed from which the underlying 30-year observations were aggregated to produce this normal. Supports data lineage and quality auditing. [ENUM-REF-CANDIDATE: NOAA|DTN|Climate_FieldView|IoT_Sensor|USDA_NASS|manual|other — promote to reference product]. Valid values are `NOAA|DTN|Climate_FieldView|IoT_Sensor|USDA_NASS|manual`',
    `drought_index_normal` DECIMAL(18,2) COMMENT '30-year average Palmer Drought Severity Index (PDSI) value for the applicable month or season. Negative values indicate drought conditions; used for irrigation planning, WASDE yield estimation inputs, and crop insurance documentation.',
    `elevation_m` DECIMAL(18,2) COMMENT 'Elevation of the weather station or zone centroid above mean sea level in metres. Influences temperature lapse rate corrections and ET reference calculations.',
    `et_normal_mm` DECIMAL(18,2) COMMENT '30-year average reference evapotranspiration (ET₀) in millimetres for the applicable month or season, calculated using FAO-56 Penman-Monteith method. Baseline for irrigation scheduling and water balance modelling.',
    `extreme_heat_days_normal` DECIMAL(18,2) COMMENT '30-year average number of days per month or season where maximum temperature exceeds the crop-specific heat stress threshold (typically ≥35°C). Used for climate risk scoring and crop insurance actuarial inputs.',
    `extreme_precip_days_normal` DECIMAL(18,2) COMMENT '30-year average number of days per month or season with precipitation exceeding 25 mm (heavy rain threshold). Used for flood risk assessment, field trafficability planning, and crop loss event documentation.',
    `frost_free_days_normal` DECIMAL(18,2) COMMENT '30-year average number of frost-free days in the growing season (between last spring frost and first autumn frost). Determines viable crop maturity window for variety selection.',
    `gdd_base_temp_c` DECIMAL(18,2) COMMENT 'Base temperature threshold in degrees Celsius used for GDD accumulation calculations in this record (e.g., 10°C for corn, 4.4°C for small grains). Ensures comparability across crop types.',
    `gdd_normal` DECIMAL(18,2) COMMENT '30-year average accumulated Growing Degree Days (GDD) for the applicable month or season using the standard base temperature defined in gdd_base_temp_c. Used as baseline for crop phenology prediction and variety selection.',
    `humidity_normal_pct` DECIMAL(18,2) COMMENT '30-year average relative humidity percentage for the applicable month or season. Used for disease pressure modelling, spray window suitability, and ET calculations.',
    `latitude` DECIMAL(18,2) COMMENT 'WGS-84 latitude of the weather station or zone centroid in decimal degrees. Used for GIS spatial analysis in Esri ArcGIS and for ET calculations requiring solar angle.',
    `longitude` DECIMAL(18,2) COMMENT 'WGS-84 longitude of the weather station or zone centroid in decimal degrees. Used for GIS spatial analysis and solar radiation calculations.',
    `month_number` STRING COMMENT 'Calendar month (1=January through 12=December) to which this normal record applies. Null for seasonal or annual normal_type records.',
    `noaa_climate_division` STRING COMMENT 'NOAA-assigned climate division code (state + division number, e.g., IL01) used to aggregate station data to regional climate normals. Supports WASDE regional yield estimation and USDA crop reporting district alignment.',
    `normal_period_end_year` STRING COMMENT 'The last calendar year of the 30-year baseline period used to compute this climate normal (e.g., 2020 for the 1991-2020 WMO normal period).',
    `normal_period_start_year` STRING COMMENT 'The first calendar year of the 30-year baseline period used to compute this climate normal (e.g., 1991 for the 1991-2020 WMO normal period).',
    `normal_status` STRING COMMENT 'Lifecycle status of this climate normal record. Active records are used for operational decisions; superseded records are retained for historical comparison and crop insurance documentation.. Valid values are `active|superseded|draft|under_review`',
    `normal_type` STRING COMMENT 'Temporal granularity of this climate normal record — monthly (one record per calendar month), seasonal (DJF/MAM/JJA/SON), or annual (full-year aggregate).. Valid values are `monthly|seasonal|annual`',
    `precip_days_normal` DECIMAL(18,2) COMMENT '30-year average number of days with measurable precipitation (≥0.25 mm) for the applicable month or season. Used for spray window planning and field operation scheduling.',
    `precip_normal_mm` DECIMAL(18,2) COMMENT '30-year average total precipitation in millimetres for the applicable month or season. Baseline for irrigation scheduling, water resource planning, and crop insurance actuarial calculations.',
    `published_date` DATE COMMENT 'Date on which this climate normal record was officially published or made available for operational use. Used for version control and regulatory audit trails under FSMA and crop insurance documentation requirements.',
    `quality_flag` STRING COMMENT 'Quality control status of the climate normal record indicating whether the underlying 30-year observation series passed automated QC checks, was estimated via interpolation, or contains missing data gaps.. Valid values are `passed|flagged|estimated|missing`',
    `season_code` STRING COMMENT 'WMO meteorological season code: DJF (December-January-February / Winter), MAM (March-April-May / Spring), JJA (June-July-August / Summer), SON (September-October-November / Autumn). Null for monthly or annual normal_type records.. Valid values are `DJF|MAM|JJA|SON`',
    `snowfall_normal_mm` DECIMAL(18,2) COMMENT '30-year average total snowfall expressed as water equivalent in millimetres for the applicable month or season. Relevant for soil moisture recharge estimation and spring planting window forecasting.',
    `solar_radiation_normal_mj_m2` DECIMAL(18,2) COMMENT '30-year average incoming solar radiation in megajoules per square metre per day for the applicable month or season. Required input for FAO-56 Penman-Monteith ET calculations and NDVI baseline modelling.',
    `temp_max_c` DECIMAL(18,2) COMMENT '30-year average of daily maximum temperatures in degrees Celsius for the applicable month or season. Used for heat stress thresholds and GDD upper-cap calculations.',
    `temp_mean_c` DECIMAL(18,2) COMMENT '30-year average mean daily temperature in degrees Celsius for the applicable month or season. Core input for GDD accumulation norms and WASDE yield estimation.',
    `temp_min_c` DECIMAL(18,2) COMMENT '30-year average of daily minimum temperatures in degrees Celsius for the applicable month or season. Critical for frost risk assessment and crop variety selection.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this climate normal record in the data lakehouse. Tracks revisions from reprocessing, QC corrections, or source data updates.',
    `wind_speed_normal_ms` DECIMAL(18,2) COMMENT '30-year average wind speed in metres per second at 2-metre height for the applicable month or season. Used in ET calculations, spray window assessments, and pesticide drift risk modelling per EPA REI guidelines.',
    `wmo_station_number` STRING COMMENT 'Official WMO 5- or 6-digit station identifier assigned by the World Meteorological Organization. Enables cross-referencing with NOAA NCEI, DTN, and international climate databases for data lineage and audit.. Valid values are `^[0-9]{5,6}$`',
    `years_of_record` STRING COMMENT 'Actual number of years of valid observational data used to compute this normal (may be less than 30 if data gaps exist). Values below 25 indicate reduced statistical confidence per WMO guidelines.',
    CONSTRAINT pk_climate_normal PRIMARY KEY(`climate_normal_id`)
) COMMENT 'Long-term climate normal record representing 30-year statistical baselines (WMO standard) for a weather zone or station. Stores monthly and seasonal averages for temperature (min/max/mean), precipitation, ET, frost dates (average first/last), GDD accumulation norms, and extreme event frequencies. Used as baseline for anomaly detection, crop variety selection, and WASDE yield estimation inputs.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`irrigation_schedule` (
    `irrigation_schedule_id` BIGINT COMMENT 'Unique system-generated identifier for the irrigation schedule record. Primary key for the irrigation_schedule data product in the weather domain Silver layer.',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Irrigation schedules are executed by specific irrigation crews. Linking irrigation_schedule to crew enables labor cost allocation, crew utilization reporting, and ensures the right crew is dispatched ',
    `crop_enterprise_budget_id` BIGINT COMMENT 'Foreign key linking to finance.crop_enterprise_budget. Business justification: Irrigation schedules drive water and energy costs that are major line items in crop enterprise budgets. Linking irrigation schedules to the enterprise budget enables actual vs planned irrigation cost ',
    `drought_index_id` BIGINT COMMENT 'Foreign key linking to weather.drought_index. Business justification: Irrigation scheduling is directly driven by drought conditions — drought_index has irrigation_recommended and irrigation_deficit_mm fields that feed directly into irrigation schedule generation. Linki',
    `evapotranspiration_id` BIGINT COMMENT 'Reference to the evapotranspiration calculation record that drove this irrigation schedule recommendation. Links to the weather.evapotranspiration product.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or irrigation zone for which this irrigation schedule was generated. Links to the field master record in the crop management domain.',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to weather.forecast. Business justification: Irrigation schedules are generated using weather forecast data (precipitation probability, ET forecast). Linking irrigation_schedule to the specific forecast record used during schedule generation pro',
    `irrigation_zone_id` BIGINT COMMENT 'Foreign key linking to land.irrigation_zone. Business justification: Every irrigation schedule applies to a specific physical irrigation zone. Replacing the denormalized irrigation_zone_code text with a proper FK to land.irrigation_zone enables water volume tracking ag',
    `soil_temperature_id` BIGINT COMMENT 'Foreign key linking to weather.soil_temperature. Business justification: Irrigation scheduling decisions are influenced by soil temperature (cold soils reduce crop water uptake, affecting irrigation requirements). Linking irrigation_schedule to the specific soil_temperatur',
    `application_rate_mm_hr` DECIMAL(18,2) COMMENT 'The rate at which water is applied during the irrigation event, expressed in millimeters per hour. Determines irrigation duration and must not exceed soil infiltration rate to prevent runoff.',
    `application_volume_acre_in` DECIMAL(18,2) COMMENT 'The recommended volume of water to be applied during this irrigation event, expressed in acre-inches. Derived from the ET deficit calculation and soil moisture target. Standard unit for US agricultural irrigation scheduling.',
    `application_volume_mm` DECIMAL(18,2) COMMENT 'The recommended volume of water to be applied during this irrigation event, expressed in millimeters depth equivalent. Metric unit for international reporting and FAO-aligned ET calculations.',
    `approved_by` STRING COMMENT 'The name or identifier of the agronomist, farm manager, or operator who approved this irrigation schedule for execution. Supports audit trail and accountability requirements under GLOBALG.A.P. and FSMA.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time at which this irrigation schedule was approved for execution. Part of the schedule lifecycle audit trail required for GLOBALG.A.P. and FSMA compliance documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this irrigation schedule record was first created in the system. Supports data lineage, audit trail, and Silver layer ingestion tracking.',
    `crop_coefficient` DECIMAL(18,2) COMMENT 'The dimensionless crop coefficient (Kc) used to convert reference ET (ETo) to crop-specific ET (ETc). Varies by crop type and growth stage per FAO-56 methodology. Critical input to the ET deficit calculation.',
    `crop_growth_stage` STRING COMMENT 'The current phenological growth stage of the crop at the time of scheduling (e.g., V6, R1, R3 for corn; vegetative, flowering, pod fill for soybeans). Influences crop coefficient and irrigation priority.',
    `crop_type` STRING COMMENT 'The type of crop being irrigated (e.g., corn, soybeans, wheat, cotton). Determines crop coefficient (Kc) used in ET calculations and influences soil moisture targets and irrigation timing.',
    `estimated_duration_min` STRING COMMENT 'The estimated duration of the irrigation event in minutes, calculated from the recommended application volume and application rate. Used for equipment scheduling and energy cost estimation.',
    `estimated_water_volume_m3` DECIMAL(18,2) COMMENT 'The total estimated volume of water to be applied during this irrigation event, expressed in cubic meters. Used for water use reporting, permit compliance, and cost accounting.',
    `et_deficit_mm` DECIMAL(18,2) COMMENT 'The cumulative soil water deficit being addressed by this irrigation event, calculated as the difference between crop ET demand and effective precipitation received. Expressed in millimeters. Core driver of the irrigation recommendation.',
    `external_schedule_ref` STRING COMMENT 'The reference identifier from the originating external system (e.g., John Deere Operations Center task ID, Trimble Ag prescription ID, Climate FieldView recommendation ID). Enables bidirectional traceability to source systems.',
    `frost_protection_flag` BOOLEAN COMMENT 'Indicates whether this irrigation event is scheduled for frost/freeze protection purposes rather than crop water demand. When True, the schedule is triggered by frost alert conditions rather than ET deficit.',
    `generation_source` STRING COMMENT 'The system or data source that generated this irrigation schedule recommendation. Supports data lineage, audit, and integration traceability across Climate FieldView, Trimble Ag, John Deere Operations Center, and IoT sensor networks. [ENUM-REF-CANDIDATE: climate_fieldview|trimble_ag|john_deere_ops|granular|manual|iot_sensor|dtn_feed — 7 candidates stripped; promote to reference product]',
    `irrigation_method` STRING COMMENT 'The physical method of water application for this scheduled irrigation event. Determines application efficiency, equipment requirements, and water use calculations. [ENUM-REF-CANDIDATE: drip|center_pivot|flood|sprinkler|subsurface_drip|furrow|lateral_move|micro_sprinkler — promote to reference product if additional methods are needed]. Valid values are `drip|center_pivot|flood|sprinkler|subsurface_drip|furrow`',
    `phi_compliance_flag` BOOLEAN COMMENT 'Indicates whether this irrigation schedule has been reviewed for compliance with Pre-Harvest Interval (PHI) requirements for any recently applied agrochemicals. Relevant for food safety and MRL compliance.',
    `precip_credit_mm` DECIMAL(18,2) COMMENT 'The effective precipitation credit applied to reduce the irrigation requirement, accounting for forecast precipitation probability and soil infiltration capacity. Expressed in millimeters.',
    `precip_forecast_mm` DECIMAL(18,2) COMMENT 'The forecasted precipitation amount in millimeters for the scheduling window, sourced from DTN weather feeds or Climate FieldView. Used to calculate precipitation credit and adjust the recommended application volume.',
    `precip_probability_pct` DECIMAL(18,2) COMMENT 'The probability of precipitation occurring during the scheduled irrigation window, expressed as a percentage. Used to determine whether to proceed with irrigation or defer pending rainfall.',
    `schedule_notes` STRING COMMENT 'Free-text operational notes entered by the agronomist or farm manager regarding this irrigation schedule, such as equipment constraints, field access issues, or special instructions for the irrigation operator.',
    `schedule_number` STRING COMMENT 'Externally-known business identifier for the irrigation schedule, used in operational communications, FMIS records, and integration with John Deere Operations Center and Trimble Ag. Format: IRSCHED-YYYY-NNNNNN.. Valid values are `^IRSCHED-[0-9]{4}-[0-9]{6}$`',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the irrigation schedule. draft indicates pending review; scheduled indicates approved and queued; in_progress indicates irrigation is actively running; completed indicates finished; cancelled indicates voided before execution; skipped indicates bypassed due to precipitation or other conditions.. Valid values are `draft|scheduled|in_progress|completed|cancelled|skipped`',
    `schedule_type` STRING COMMENT 'Classification of the method used to generate this irrigation schedule. et_based uses evapotranspiration deficit calculations; soil_moisture_based uses sensor readings; calendar_based uses fixed intervals; forecast_based uses precipitation forecast adjustments; manual is operator-entered.. Valid values are `et_based|soil_moisture_based|calendar_based|forecast_based|manual`',
    `scheduled_date` DATE COMMENT 'The calendar date on which irrigation is scheduled to occur. Used for operational planning, spray window coordination, and crop insurance documentation.',
    `scheduled_end_timestamp` TIMESTAMP COMMENT 'The projected date and time at which irrigation is scheduled to complete. Used for equipment scheduling, labor planning, and energy cost estimation.',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'The precise date and time at which irrigation is scheduled to begin. Critical for pivot and drip system automation, labor scheduling, and integration with John Deere Operations Center equipment dispatch.',
    `soil_moisture_current_pct` DECIMAL(18,2) COMMENT 'The measured or estimated current volumetric soil moisture content at the time the schedule was generated, expressed as a percentage of field capacity. Sourced from IoT field sensors or modeled estimates.',
    `soil_moisture_target_pct` DECIMAL(18,2) COMMENT 'The target volumetric soil moisture content to be achieved after irrigation, expressed as a percentage of field capacity. Defined by crop type, growth stage, and soil type. Used to calculate required application volume.',
    `spray_window_conflict` BOOLEAN COMMENT 'Indicates whether this irrigation schedule conflicts with an active pesticide or fertilizer spray window. When True, irrigation timing may need to be adjusted to avoid diluting chemical applications or violating Restricted Entry Interval (REI) requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this irrigation schedule record was last modified. Tracks revisions to the schedule including volume adjustments, timing changes, or status updates.',
    `water_source` STRING COMMENT 'The source of water used for this irrigation event. Relevant for water rights compliance, cost accounting, and environmental reporting under EPA and state water authority regulations.. Valid values are `groundwater|surface_water|municipal|recycled|rainwater_harvest`',
    `water_stress_index` DECIMAL(18,2) COMMENT 'A dimensionless index (0.0 to 1.0) quantifying the degree of crop water stress at the time of scheduling. A value of 0 indicates no stress; 1.0 indicates maximum stress. Used to prioritize irrigation scheduling across multiple fields.',
    CONSTRAINT pk_irrigation_schedule PRIMARY KEY(`irrigation_schedule_id`)
) COMMENT 'Weather-driven irrigation scheduling record generated from ET calculations, soil moisture readings, and precipitation forecasts for a specific field or irrigation zone. Stores scheduled irrigation date/time, recommended application volume (acre-inches), irrigation method (drip, pivot, flood), ET deficit being addressed, soil moisture target, and precipitation credit applied. Integrates with John Deere Operations Center and Trimble Ag VRA irrigation prescriptions.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`alert` (
    `alert_id` BIGINT COMMENT 'Unique system-generated identifier for each weather alert record. Primary key for the weather_alert data product in the Databricks Silver Layer.',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Severe weather alerts (lightning, high wind, hail) trigger mandatory crew evacuation and work-stoppage protocols under OSHA and WPS. Safety managers must know which crew is in the affected area to exe',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: Weather alerts (blizzards, tornadoes, ice storms) directly affect specific customer receiving facilities. Agriculture logistics teams associate weather alerts with impacted delivery locations to trigg',
    `field_id` BIGINT COMMENT 'Reference to the specific agricultural field affected by this weather alert. Enables field-level alert routing, crop vulnerability assessment, and precision protective action recommendations within the Farm Management Information System (FMIS).',
    `station_id` BIGINT COMMENT 'Reference to the weather observation station associated with this alert. Links to the station providing the meteorological data underpinning the alert, sourced from IoT field sensors or DTN weather network stations.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Official NWS weather alerts are issued by geographic zone (NWS zone-based alert system). weather_alert has geographic_zone_code (STRING) which is a denormalized reference to weather_zone.zone_code. Ad',
    `acknowledged_by` STRING COMMENT 'Name or system identifier of the farm manager, agronomist, or operator who acknowledged this weather alert. Required for FSMA compliance audit trails and GLOBALG.A.P. certification documentation demonstrating that alerts were acted upon by responsible personnel.',
    `acknowledgement_timestamp` TIMESTAMP COMMENT 'The datetime when the weather alert was acknowledged by a responsible farm manager or operator. Supports audit trail requirements for FSMA compliance, GLOBALG.A.P. certification, and internal Standard Operating Procedure (SOP) adherence.',
    `affected_area_ha` DECIMAL(18,2) COMMENT 'Total agricultural land area affected by this weather alert, expressed in hectares. Used for crop insurance documentation, loss estimation, and resource allocation for protective actions. Supports USDA crop insurance claim substantiation.',
    `alert_number` STRING COMMENT 'Externally-known business identifier for the weather alert, typically assigned by the issuing authority (e.g., NWS event number, DTN alert code, or internal farm management system reference). Used for cross-system traceability and regulatory documentation.',
    `alert_source` STRING COMMENT 'Originating system or authority that issued the weather alert. Identifies whether the alert originated from the National Weather Service (NWS), DTN Data Transmission Network weather feed, Climate FieldView platform, internal Farm Management Information System (FMIS), NOAA, or a state agricultural agency.. Valid values are `NWS|DTN|Climate_FieldView|internal_FMIS|NOAA|state_agency`',
    `alert_status` STRING COMMENT 'Current lifecycle state of the weather alert record. Tracks whether the alert is newly issued, currently active, has been updated with revised information, cancelled by the issuing authority, or has naturally expired past its valid period.. Valid values are `issued|active|updated|cancelled|expired`',
    `alert_type` STRING COMMENT 'Classification of the meteorological hazard represented by this alert. Identifies the specific weather phenomenon such as tornado, severe thunderstorm, flash flood, heat advisory, winter storm, high wind, frost/freeze advisory, or wildfire smoke. [ENUM-REF-CANDIDATE: tornado|severe_thunderstorm|flash_flood|heat_advisory|winter_storm|high_wind|frost_freeze|wildfire_smoke|drought|hail|dense_fog|excessive_heat — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this weather alert record was first created in the Databricks Silver Layer data product. Distinct from the issued_timestamp (business event time). Supports data lineage, FSMA recordkeeping compliance, and SOX audit trail requirements.',
    `critical_threshold_temp_c` DECIMAL(18,2) COMMENT 'The temperature threshold in degrees Celsius below which crop damage is expected for the affected crop type and growth stage. Used to determine alert severity and trigger protective action recommendations. Varies by crop species and phenological stage.',
    `crop_growth_stage` STRING COMMENT 'The phenological growth stage of the affected crop at the time of the alert (e.g., germination, emergence, vegetative, flowering, grain fill, maturity). Growth stage critically determines crop vulnerability to weather hazards and informs protective action urgency.',
    `crop_type` STRING COMMENT 'The primary crop type affected by this weather alert (e.g., corn, soybeans, wheat, cotton, specialty crops). Used to determine crop-specific vulnerability ratings, damage thresholds, and recommended protective actions. Aligns with USDA crop classification codes.',
    `crop_vulnerability_rating` STRING COMMENT 'Assessed vulnerability rating of the affected crop to the specific weather hazard at its current growth stage. Drives prioritization of protective actions and resource allocation. Ratings range from low (minimal expected damage) to critical (severe or total crop loss expected).. Valid values are `low|moderate|high|critical`',
    `dew_point_temp_c` DECIMAL(18,2) COMMENT 'Forecast or observed dew point temperature in degrees Celsius. Critical for frost event characterization — when dew point is below 0°C, frost deposition is expected. Also used for spray window assessment and disease pressure modeling.',
    `end_timestamp` TIMESTAMP COMMENT 'The datetime when the weather alert expires and hazardous conditions are expected to cease. Determines the window during which protective actions must remain in place. Used for irrigation frost protection scheduling and spray window re-opening decisions.',
    `estimated_crop_loss_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of crop yield loss expected if no protective action is taken, based on forecast conditions, crop type, and growth stage. Used for crop insurance pre-loss documentation, financial risk assessment, and USDA WASDE reporting inputs.',
    `external_alert_ref` STRING COMMENT 'Reference identifier from the external source system (DTN, Climate FieldView, or state agency) that originated this alert record. Supports data lineage, deduplication, and reconciliation with upstream weather data providers.',
    `forecast_low_temp_c` DECIMAL(18,2) COMMENT 'Predicted minimum temperature in degrees Celsius for the alert period. Critical for frost/freeze advisory events to assess crop damage risk, determine Growing Degree Day (GDD) impact, and trigger irrigation frost protection systems.',
    `frost_probability_pct` DECIMAL(18,2) COMMENT 'Statistical probability (0-100%) that frost conditions will occur during the alert period, as calculated by the issuing weather service. Used for risk-based decision-making on protective action deployment and crop insurance pre-loss documentation.',
    `frost_type` STRING COMMENT 'Classification of the frost mechanism expected during the alert event. Radiation frost occurs on clear calm nights; advection frost results from cold air mass movement; evaporation frost occurs with rapid moisture loss; freeze indicates temperatures below 0°C causing ice crystal formation in plant tissue.. Valid values are `radiation|advection|evaporation|freeze`',
    `gdd_impact_estimate` DECIMAL(18,2) COMMENT 'Estimated impact on Growing Degree Day (GDD) accumulation resulting from the weather event described in this alert. Negative values indicate GDD loss due to frost or extreme cold; used to recalculate predicted crop maturity dates and adjust harvest scheduling.',
    `insurance_claim_relevant` BOOLEAN COMMENT 'Indicates whether this weather alert event is relevant for crop insurance claim documentation under USDA Risk Management Agency (RMA) programs. When True, the alert record is preserved as supporting evidence for potential indemnity claims.',
    `irrigation_frost_protection` BOOLEAN COMMENT 'Indicates whether overhead irrigation frost protection has been recommended or activated in response to this frost/freeze alert. Irrigation frost protection uses latent heat of freezing water to protect crops from freeze damage. Integrates with irrigation scheduling systems.',
    `issued_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp when the weather alert was officially issued by the originating authority. Represents the business event time distinct from the record audit timestamp. Critical for Pre-Harvest Interval (PHI) and Restricted Entry Interval (REI) compliance tracking and crop insurance documentation.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the alert centroid or point of origin in decimal degrees (WGS84). Used for GIS-based spatial analysis, precision agriculture field mapping, and GPS-referenced alert routing in Esri ArcGIS and John Deere Operations Center.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the alert centroid or point of origin in decimal degrees (WGS84). Used in conjunction with latitude for GIS spatial analysis, field boundary intersection, and precision agriculture alert targeting.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, observations, or context related to this weather alert. May include agronomist commentary, field-specific conditions, or supplementary guidance not captured in structured fields. Supports GLOBALG.A.P. documentation requirements.',
    `nws_event_code` STRING COMMENT 'The official National Weather Service (NWS) event identifier for this alert, used for cross-referencing with NWS public alert feeds, NOAA databases, and regulatory documentation. Enables traceability to the authoritative government weather alert record.',
    `recommended_action` STRING COMMENT 'Prescribed protective action recommended in response to this weather alert, such as deploy frost cloth, activate irrigation frost protection, delay spray application, evacuate field workers, or secure equipment. Sourced from FMIS decision support rules or NWS/DTN advisory guidance.',
    `relative_humidity_pct` DECIMAL(18,2) COMMENT 'Forecast or observed relative humidity percentage at the time of alert issuance. Used in frost risk assessment (high humidity increases frost severity), spray window determination, and disease pressure prediction for Integrated Pest Management (IPM).',
    `severity` STRING COMMENT 'Severity tier of the weather alert following NWS standard classification. Advisory indicates conditions that may cause inconvenience; Watch indicates conditions are favorable for a hazard; Warning indicates a hazard is imminent or occurring; Emergency indicates an extreme, life-threatening event.. Valid values are `advisory|watch|warning|emergency`',
    `spray_window_open` BOOLEAN COMMENT 'Indicates whether pesticide or fertilizer spray application is permissible during the alert period based on wind speed, temperature, humidity, and precipitation conditions. False indicates spray operations should be suspended per EPA application restrictions and Good Agricultural Practices (GAP).',
    `start_timestamp` TIMESTAMP COMMENT 'The datetime when the hazardous weather conditions described in the alert are expected to begin or have begun. Used for scheduling protective actions such as frost cloth deployment, irrigation frost protection activation, and spray window closure.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this weather alert record was last modified in the data product. Tracks alert updates such as severity upgrades, zone expansions, or cancellations. Supports data lineage and FSMA compliance audit trails.',
    `wind_speed_ms` DECIMAL(18,2) COMMENT 'Forecast or observed wind speed in metres per second at the time of alert issuance. Relevant for high wind alerts, spray window assessment, frost risk modification (wind reduces radiation frost risk), and wildfire smoke dispersion modeling.',
    CONSTRAINT pk_alert PRIMARY KEY(`alert_id`)
) COMMENT 'Official weather alert, warning, and frost/freeze advisory record issued by NWS, DTN, or internal farm management systems for a weather zone or field. Stores alert type (tornado, severe thunderstorm, flash flood, heat advisory, winter storm, high wind, frost/freeze advisory, wildfire smoke), alert severity (advisory/watch/warning/emergency), issuance and expiration datetime, affected geographic zone, predicted low temperature for frost events, frost probability, crop-specific vulnerability rating, recommended protective actions (including frost cloth, irrigation frost protection), alert source, and acknowledgment status. SSOT for all weather alert types including frost/freeze events, consolidating all alert lifecycle management in a single product.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`insurance_record` (
    `insurance_record_id` BIGINT COMMENT 'Unique surrogate identifier for the certified weather-based crop insurance record. Primary key for this entity in the Databricks Silver Layer.',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: Official weather alerts (NWS warnings, advisories) serve as certified documentation for crop insurance claims. insurance_record has insurance_claim_relevant fields — linking to the specific weather_al',
    `insurance_claim_id` BIGINT COMMENT 'Reference to the indemnity claim this weather record substantiates. A single claim may be supported by multiple weather records covering different event types or date ranges.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Crop insurance indemnity calculations reference commodity benchmark prices, USDA grade standards, and MRL thresholds. RMA revenue protection policies are commodity-specific (usda_commodity_code, excha',
    `loss_event_id` BIGINT COMMENT 'Foreign key linking to crop.loss_event. Business justification: Weather insurance records document weather-caused crop losses and must reference the crop loss event for RMA indemnity calculation, adjuster verification, and USDA disaster submission. Linking insuran',
    `drought_index_id` BIGINT COMMENT 'Foreign key linking to weather.drought_index. Business justification: Drought-related crop insurance claims require certified drought index values (PDSI, SPI, CMI) for USDA RMA documentation. insurance_record has drought_index_value and drought_index_type — these are de',
    `employee_id` BIGINT COMMENT 'Reference to the licensed loss adjuster who verified and certified the weather observations in this record. Required for FCIC-compliant indemnity processing.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or parcel for which this insurance weather record is compiled. Ties the meteorological data to a specific insured land unit.',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Crop insurance claims are triggered by frost and freeze events. insurance_record has frost_freeze_flag — linking to the specific frost_alert record that triggered the claim provides certified weather ',
    `government_program_id` BIGINT COMMENT 'Foreign key linking to finance.government_program. Business justification: Weather-triggered insurance records and FSA government program payments (ARC/PLC, NAP) co-exist for the same crop/year/field. Linking enables reconciliation of insurance indemnities against program pa',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season during which the insured weather event occurred. Used to align GDD deviation, precipitation totals, and drought indices to the correct crop calendar.',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to land.parcel. Business justification: USDA RMA crop insurance is administered at the CLU/parcel level. Linking insurance_record to land.parcel enables policy-to-parcel traceability required for RMA compliance reporting, adjuster verificat',
    `insurance_policy_id` BIGINT COMMENT 'Reference to the crop insurance policy under which this weather event record is filed. Links to the policy master for coverage terms, insured acres, and premium details.',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Crop insurance claims are frequently triggered by severe precipitation events (hail, flooding, high winds). insurance_record has hail_event_flag and hail_stone_size_cm — linking to the specific precip',
    `seed_variety_id` BIGINT COMMENT 'Foreign key linking to product.seed_variety. Business justification: USDA RMA crop insurance APH (Actual Production History) calculations and indemnity determinations require the specific insured seed variety — variety traits, yield_potential_rating, and disease_resist',
    `station_id` BIGINT COMMENT 'Reference to the certified weather station whose observations underpin this insurance record. Station certification status is critical for FCIC-accepted data.',
    `yield_record_id` BIGINT COMMENT 'Foreign key linking to crop.yield_record. Business justification: Insurance indemnity calculations require actual yield records (APH yield, moisture-adjusted production, grain quality). Linking insurance_record to yield_record supports RMA unit-level yield certifica',
    `adjuster_verification_timestamp` TIMESTAMP COMMENT 'Date and time when the loss adjuster formally verified and certified the weather data in this record. Establishes the official certification date for FCIC compliance.',
    `certification_notes` STRING COMMENT 'Free-text notes entered by the loss adjuster or data certifier documenting any qualifications, data quality issues, or special circumstances relevant to the certified weather record.',
    `certified_precip_mm` DECIMAL(18,2) COMMENT 'Adjuster-verified total precipitation in millimeters recorded during the event window. This is the official certified value used for indemnity claim processing, distinct from raw station observations.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this insurance record was first created in the system. Audit trail field for data lineage and compliance.',
    `crop_year` STRING COMMENT 'The four-digit crop year (e.g., 2024) for which the insurance coverage applies. Used to align weather data with the correct USDA RMA actuarial year and WASDE reporting cycle.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the indemnity_amount (e.g., USD). Supports international operations and IFRS financial reporting.. Valid values are `^[A-Z]{3}$`',
    `data_source` STRING COMMENT 'Identifies the authoritative source of the meteorological data used in this insurance record (e.g., DTN = Data Transmission Network, NOAA_COOP = NOAA Cooperative Observer, ASOS = Automated Surface Observing System). Determines data acceptance under USDA RMA approved provider rules. [ENUM-REF-CANDIDATE: DTN|NOAA_COOP|ASOS|AWOS|IoT_sensor|Climate_FieldView|manual_entry — 7 candidates stripped; promote to reference product]',
    `estimated_crop_loss_pct` DECIMAL(18,2) COMMENT 'Adjuster-estimated percentage of crop yield loss attributable to the documented weather event. Used as the primary input for indemnity payment calculation under FCIC provisions.',
    `event_end_date` DATE COMMENT 'Calendar date on which the insured weather event concluded. Together with event_start_date defines the observation window for all certified meteorological measurements in this record.',
    `event_start_date` DATE COMMENT 'Calendar date on which the insured weather event began. Used to establish the event window for certified precipitation totals, temperature extremes, and GDD deviation calculations.',
    `frost_freeze_flag` BOOLEAN COMMENT 'Indicates whether a frost or freeze event was documented in this record. Activates frost-specific loss adjustment procedures and links to frost_alert records for corroboration.',
    `gdd_actual` DECIMAL(18,2) COMMENT 'Actual GDD accumulation recorded for the event period or season to date. Used to assess crop development stage at time of loss and validate indemnity eligibility.',
    `gdd_deviation` DECIMAL(18,2) COMMENT 'Difference between actual and historical normal GDD accumulation (gdd_actual minus gdd_normal). Quantifies the magnitude of thermal stress for crop insurance indemnity calculations.',
    `gdd_normal` DECIMAL(18,2) COMMENT 'Long-term historical average GDD accumulation for the same period and location. Used to calculate GDD deviation from normal for indemnity assessment.',
    `hail_event_flag` BOOLEAN COMMENT 'Indicates whether a hail event was documented during the event window. Triggers hail-specific loss assessment protocols under FCIC crop insurance provisions.',
    `hail_stone_size_cm` DECIMAL(18,2) COMMENT 'Maximum observed hail stone diameter in centimeters during the documented hail event. Used to assess crop damage severity and validate hail indemnity claims.',
    `indemnity_amount` DECIMAL(18,2) COMMENT 'Calculated indemnity payment amount in USD based on the certified weather data, estimated crop loss percentage, and policy coverage terms. Represents the gross indemnity before any premium offsets.',
    `insured_area_ha` DECIMAL(18,2) COMMENT 'Total insured area in hectares affected by the documented weather event. Used to calculate indemnity amounts and validate against policy coverage limits.',
    `insured_party_name` STRING COMMENT 'Legal name of the insured producer or farming entity associated with this weather record. Required for USDA RMA reporting and adjuster correspondence.',
    `policy_number` STRING COMMENT 'Externally-known policy number assigned by the Approved Insurance Provider (AIP) or FCIC. Used for cross-referencing with insurer systems and USDA RMA submissions.',
    `record_number` STRING COMMENT 'Externally-known business identifier for this certified weather insurance record, used in USDA RMA submissions and adjuster correspondence. Typically assigned by the insurer or FCIC system.',
    `record_status` STRING COMMENT 'Current lifecycle state of the insurance weather record. Progresses from draft through adjuster verification to certified status required for FCIC indemnity processing. [ENUM-REF-CANDIDATE: draft|submitted|adjuster_verified|certified|rejected|withdrawn — promote to reference product if additional states are needed]. Valid values are `draft|submitted|adjuster_verified|certified|rejected|withdrawn`',
    `record_type` STRING COMMENT 'Classification of the primary weather peril documented in this record. Determines which meteorological parameters are most relevant for the indemnity assessment. [ENUM-REF-CANDIDATE: precipitation|temperature_extreme|drought|hail|frost_freeze|wind|flood — promote to reference product]',
    `rma_unit_number` STRING COMMENT 'USDA Risk Management Agency unit number identifying the insured unit (basic, optional, enterprise, or whole-farm) within the policy. Required for RMA reporting and actuarial reconciliation.',
    `submitted_timestamp` TIMESTAMP COMMENT 'Date and time when this insurance weather record was formally submitted to the insurer or USDA RMA system. Establishes the principal business event time for workflow tracking and regulatory deadline compliance.',
    `temp_max_c` DECIMAL(18,2) COMMENT 'Certified maximum air temperature in degrees Celsius recorded during the event window. Used to document heat stress events and temperature extreme claims.',
    `temp_min_c` DECIMAL(18,2) COMMENT 'Certified minimum air temperature in degrees Celsius recorded during the event window. Critical for frost/freeze event documentation and PHI (Pre-Harvest Interval) compliance verification.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this insurance record was most recently modified. Supports audit trail requirements and change tracking for FCIC compliance.',
    CONSTRAINT pk_insurance_record PRIMARY KEY(`insurance_record_id`)
) COMMENT 'Certified weather data record compiled for crop insurance claim substantiation and USDA RMA (Risk Management Agency) reporting. Stores policy-linked weather event documentation, certified precipitation totals, temperature extremes, GDD deviation from normal, drought index values, hail event records, and adjuster-verified observation data. Supports FCIC (Federal Crop Insurance Corporation) compliance and indemnity claim processing.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`sensor_calibration` (
    `sensor_calibration_id` BIGINT COMMENT 'Unique surrogate identifier for each sensor calibration record in the weather domain. Primary key for the sensor_calibration data product.',
    `employee_id` BIGINT COMMENT 'Reference to the employee or contractor who performed the calibration. Required for accountability, regulatory audit trails, and workforce compliance tracking via SAP SuccessFactors.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field where the sensor is deployed. Supports spatial traceability of calibration records to specific crop production areas for irrigation scheduling, spray window, and insurance documentation.',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Sensor calibration records are maintenance activities on capitalized weather station assets. Linking calibration records to the fixed asset enables maintenance cost capitalization vs expensing decisio',
    `calibration_standard_id` BIGINT COMMENT 'Identifier of the NIST-traceable or certified reference standard instrument used during calibration. Required for ISO/IEC 17025 compliance and regulatory audit documentation.',
    `sensor_id` BIGINT COMMENT 'Reference to the IoT field weather sensor or weather station instrument that was calibrated. Links to the sensor master record.',
    `station_id` BIGINT COMMENT 'Reference to the weather station at which the sensor is installed. Supports traceability of calibration records to a specific field location.',
    `adjustment_applied` BOOLEAN COMMENT 'Indicates whether a physical or electronic offset adjustment was applied to the sensor during this calibration event. Distinguishes verification-only calibrations from those requiring corrective adjustment.',
    `adjustment_value` DECIMAL(18,2) COMMENT 'The magnitude of the offset or correction applied to the sensor during calibration. Expressed in the same unit as measurement_unit. Used to retroactively correct historical sensor readings affected by drift.',
    `affected_observation_start_date` DATE COMMENT 'The earliest date from which historical weather observations may have been affected by sensor drift, typically the date of the previous calibration. Used to scope data quality remediation and insurance claim documentation.',
    `ambient_humidity_pct` DECIMAL(18,2) COMMENT 'Relative humidity percentage recorded at the calibration site at the time of the procedure. Environmental conditions are documented per ISO/IEC 17025 to validate calibration validity.',
    `ambient_temperature_c` DECIMAL(18,2) COMMENT 'Ambient air temperature in degrees Celsius recorded at the time and location of calibration. Environmental conditions can affect sensor readings and calibration accuracy; required for ISO/IEC 17025 calibration certificates.',
    `calibration_date` DATE COMMENT 'The date on which the calibration procedure was performed. Principal business event date for this transaction record. Used for scheduling, compliance reporting, and insurance documentation.',
    `calibration_interval_days` STRING COMMENT 'The required frequency of calibration expressed in calendar days. Determined by sensor type, manufacturer specification, and regulatory requirements. Used to calculate next_calibration_date.',
    `calibration_location` STRING COMMENT 'Indicates where the calibration was physically performed. field_in_situ means the sensor was calibrated at its installed location; laboratory means it was removed and bench-tested; manufacturer_depot means returned to the OEM.. Valid values are `field_in_situ|laboratory|manufacturer_depot|mobile_unit`',
    `calibration_method` STRING COMMENT 'The procedure or technique used to perform the calibration. field_comparison compares against a co-located reference sensor; laboratory_bench involves removal and bench testing; reference_standard uses a NIST-traceable reference instrument.. Valid values are `field_comparison|laboratory_bench|automated_self_check|reference_standard|manufacturer_procedure`',
    `calibration_notes` STRING COMMENT 'Free-text field for the calibration technician to record observations, anomalies, corrective actions taken, or any deviations from standard procedure during the calibration event.',
    `calibration_number` STRING COMMENT 'Externally-known unique business identifier for this calibration event, formatted as CAL-YYYY-NNNNNN. Used for regulatory documentation, insurance claims, and audit trail references.. Valid values are `^CAL-[0-9]{4}-[0-9]{6}$`',
    `calibration_result` STRING COMMENT 'Overall outcome of the calibration procedure. pass indicates sensor is within tolerance without adjustment; pass_with_adjustment indicates within tolerance after correction; fail indicates sensor could not be brought within tolerance and must be decommissioned or replaced.. Valid values are `pass|pass_with_adjustment|fail|inconclusive`',
    `calibration_status` STRING COMMENT 'Current lifecycle status of the calibration record. failed indicates the sensor did not meet tolerance after calibration and requires corrective action. overdue indicates the scheduled calibration date has passed without completion.. Valid values are `scheduled|in_progress|completed|failed|cancelled|overdue`',
    `calibration_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the calibration procedure was executed, including timezone offset. Supports audit trail and regulatory documentation requirements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this calibration record was first created in the system. Supports audit trail, data lineage, and regulatory documentation requirements.',
    `data_quality_impact_flag` BOOLEAN COMMENT 'Indicates whether the pre-calibration drift was significant enough to have materially impacted the quality of historical weather observations recorded since the last calibration. True triggers a data quality review and potential retroactive correction of affected records.',
    `insurance_documentation_flag` BOOLEAN COMMENT 'Indicates whether this calibration record is required as supporting documentation for a crop insurance claim. When True, the record must be retained per USDA Risk Management Agency documentation requirements.',
    `measurement_unit` STRING COMMENT 'The unit of measure applicable to the pre-calibration, post-calibration, and reference standard readings. Ensures dimensional consistency across sensor types (e.g., °C for temperature, %RH for humidity, mm for precipitation). [ENUM-REF-CANDIDATE: °C|%RH|mm|m/s|deg|m³/m³|W/m²|hPa|hours — 9 candidates stripped; promote to reference product]',
    `next_calibration_date` DATE COMMENT 'The date by which the next calibration of this sensor must be completed. Drives preventive maintenance scheduling, compliance monitoring, and automated overdue alerts. Calculated based on calibration interval policy.',
    `out_of_tolerance_flag` BOOLEAN COMMENT 'Indicates whether the sensor reading remained outside the acceptable tolerance range after calibration adjustment. True triggers a corrective action workflow, sensor quarantine, and data quality review for affected historical observations. Critical for regulatory and insurance documentation.',
    `post_calibration_error` DECIMAL(18,2) COMMENT 'Calculated difference between the post-calibration sensor reading and the reference standard reading. Confirms whether the calibration adjustment brought the sensor within acceptable tolerance.',
    `post_calibration_reading` DECIMAL(18,2) COMMENT 'The sensor measurement value recorded immediately after the calibration adjustment was applied. Compared against the reference standard to confirm the sensor is within acceptable tolerance.',
    `pre_calibration_error` DECIMAL(18,2) COMMENT 'Calculated difference between the pre-calibration sensor reading and the reference standard reading. Quantifies sensor drift prior to adjustment. Used for data quality assessment of historical weather observations.',
    `pre_calibration_reading` DECIMAL(18,2) COMMENT 'The raw sensor measurement value recorded immediately before the calibration adjustment was applied. Used to quantify drift and assess data quality for historical observations.',
    `reference_standard_reading` DECIMAL(18,2) COMMENT 'The measurement value recorded by the certified reference standard instrument at the time of calibration. Serves as the ground truth against which pre- and post-calibration readings are compared.',
    `sensor_manufacturer` STRING COMMENT 'Name of the manufacturer of the sensor instrument. Used for vendor management, warranty claims, and equipment lifecycle tracking.',
    `sensor_model` STRING COMMENT 'Model designation of the sensor instrument as specified by the manufacturer. Supports calibration procedure selection and spare parts management.',
    `sensor_serial_number` STRING COMMENT 'Manufacturer-assigned serial number of the sensor instrument. Used for equipment traceability, warranty management, and regulatory documentation. Aligns with SAP PM Equipment master serial number.',
    `sensor_type` STRING COMMENT 'Classification of the IoT field sensor or weather station instrument being calibrated. Determines applicable calibration standards, tolerance ranges, and measurement units. [ENUM-REF-CANDIDATE: temperature|humidity|precipitation|wind_speed|wind_direction|soil_moisture|soil_temperature|solar_radiation|barometric_pressure|leaf_wetness — promote to reference product]',
    `technician_certification_number` STRING COMMENT 'Professional certification or qualification number of the calibration technician. Validates that the individual performing calibration meets required competency standards per ISO/IEC 17025.',
    `technician_name` STRING COMMENT 'Full name of the technician who performed the calibration. Retained for regulatory documentation and audit purposes where a named individual must be identified on calibration certificates.',
    `tolerance_lower_limit` DECIMAL(18,2) COMMENT 'The minimum acceptable deviation from the reference standard reading. If the post-calibration reading falls below this limit, the sensor is flagged as out-of-tolerance and requires corrective action.',
    `tolerance_upper_limit` DECIMAL(18,2) COMMENT 'The maximum acceptable deviation from the reference standard reading. If the post-calibration reading exceeds this limit, the sensor is flagged as out-of-tolerance and requires corrective action.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this calibration record was last modified. Supports audit trail and data lineage tracking in the Databricks Silver Layer.',
    `work_order_number` STRING COMMENT 'SAP Plant Maintenance (PM) work order number associated with this calibration event. Provides traceability to the maintenance planning and cost tracking system.',
    CONSTRAINT pk_sensor_calibration PRIMARY KEY(`sensor_calibration_id`)
) COMMENT 'Calibration and maintenance record for IoT field weather sensors and weather station instruments. Stores sensor identifier, calibration date, calibration method, pre/post calibration readings, acceptable tolerance range, calibration technician, next scheduled calibration date, and out-of-tolerance flag. Ensures data quality and traceability for regulatory and insurance documentation purposes.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`insurance_policy` (
    `insurance_policy_id` BIGINT COMMENT 'Primary key for insurance_policy',
    `account_id` BIGINT COMMENT 'Reference to the farmer, grower, or agricultural business entity that holds this insurance policy.',
    `employee_id` BIGINT COMMENT 'Reference to the insurance agent or broker who sold or services this policy.',
    `policyholder_account_id` BIGINT COMMENT 'FK to customer.account',
    `station_id` BIGINT COMMENT 'Reference to the weather station used for monitoring meteorological conditions relevant to this policy. Used for validating weather-related claims (frost, freeze, drought, excessive moisture).',
    `parent_insurance_policy_id` BIGINT COMMENT 'Self-referencing FK on insurance_policy (parent_insurance_policy_id)',
    `acreage_reporting_date` DATE COMMENT 'Deadline by which the policyholder must report planted acreage to the insurance carrier. Failure to report by this date may result in coverage denial.',
    `approved_yield_per_acre` DECIMAL(18,2) COMMENT 'The approved or guaranteed yield per acre established by the insurance carrier based on historical production records. Used as the baseline for calculating coverage and claims.',
    `cancellation_date` DATE COMMENT 'Date on which this policy was cancelled, if applicable. Null if the policy has not been cancelled.',
    `cancellation_reason` STRING COMMENT 'Reason for policy cancellation, if applicable. Includes non-payment of premium, fraud, misrepresentation, policyholder request, carrier decision, or other reasons.',
    `carrier_name` STRING COMMENT 'Name of the insurance company or underwriter providing the coverage (e.g., Rain and Hail, ProAg, Crop Risk Services).',
    `coverage_level_percent` DECIMAL(18,2) COMMENT 'Percentage of the approved yield or revenue that is insured under this policy (e.g., 50%, 65%, 75%, 85%). Higher coverage levels result in higher premiums.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this insurance policy record was first created in the system.',
    `crop_year` STRING COMMENT 'The agricultural crop year for which this insurance policy provides coverage (e.g., 2023, 2024). Aligns with planting and harvest cycles.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code indicating the currency in which premiums, liabilities, and claims are denominated.',
    `deductible_amount` DECIMAL(18,2) COMMENT 'Amount the policyholder must pay out-of-pocket before insurance coverage begins. May be expressed as a dollar amount or percentage of liability.',
    `effective_date` DATE COMMENT 'Date when the insurance policy coverage begins and becomes binding. Typically aligned with planting season or crop year start.',
    `expiration_date` DATE COMMENT 'Date when the insurance policy coverage ends. May be null for open-ended or continuously renewed policies.',
    `harvest_price_per_unit` DECIMAL(18,2) COMMENT 'The actual commodity price per unit at harvest time. Used in revenue protection policies to determine final claim amounts.',
    `insured_acres` DECIMAL(18,2) COMMENT 'Total number of acres covered under this insurance policy. Critical for calculating premiums and claim payouts.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this insurance policy record was last updated or modified.',
    `liability_amount` DECIMAL(18,2) COMMENT 'Maximum amount the insurance carrier is liable to pay under this policy in the event of a covered loss. Calculated as insured acres × approved yield × coverage level × projected price.',
    `policy_number` STRING COMMENT 'Externally-known unique policy number assigned by the insurance carrier or underwriter. Used for claims, renewals, and customer service inquiries.',
    `policy_status` STRING COMMENT 'Current lifecycle status of the insurance policy indicating whether it is active, pending approval, suspended, cancelled, expired, or lapsed.',
    `policy_terms_document_url` STRING COMMENT 'URL or file path to the full policy terms and conditions document. Provides legal reference for coverage details, exclusions, and claim procedures.',
    `policy_type` STRING COMMENT 'Classification of the insurance policy indicating the type of agricultural coverage provided (e.g., crop hail, multi-peril crop insurance, crop revenue, livestock mortality, farm property, equipment).',
    `practice_code` STRING COMMENT 'Code indicating the farming practice covered under this policy (e.g., irrigated, non-irrigated, organic, conventional). Affects risk assessment and premium calculation.',
    `prevented_planting_coverage` BOOLEAN COMMENT 'Indicates whether this policy includes coverage for prevented planting due to adverse weather conditions (e.g., excessive rain, flooding, drought) that make planting impossible.',
    `producer_premium_amount` DECIMAL(18,2) COMMENT 'Net premium amount paid by the producer/policyholder after subsidies and discounts are applied.',
    `production_reporting_date` DATE COMMENT 'Deadline by which the policyholder must report actual production/yield to the insurance carrier for claim settlement purposes.',
    `projected_price_per_unit` DECIMAL(18,2) COMMENT 'The projected commodity price per unit (bushel, ton, cwt) established at the beginning of the crop year. Used for revenue-based policies to calculate guaranteed revenue.',
    `renewal_eligible` BOOLEAN COMMENT 'Indicates whether this policy is eligible for automatic renewal for the next crop year based on claims history and compliance.',
    `replant_coverage` BOOLEAN COMMENT 'Indicates whether this policy includes coverage for replanting costs when crops fail to germinate or are destroyed shortly after planting due to insured causes.',
    `sales_closing_date` DATE COMMENT 'Last date on which a producer can purchase or make changes to this insurance policy for the current crop year.',
    `subsidy_amount` DECIMAL(18,2) COMMENT 'Government subsidy amount applied to reduce the policyholders premium cost. Common in federally-supported crop insurance programs.',
    `total_premium_amount` DECIMAL(18,2) COMMENT 'Total premium amount charged for this insurance policy before any subsidies or discounts.',
    `underwriting_notes` STRING COMMENT 'Free-text notes from the underwriter regarding special conditions, risk factors, or considerations for this policy.',
    `unit_structure` STRING COMMENT 'Defines how insured acreage is grouped for coverage purposes. Basic units are by section, optional units by field, enterprise units combine all acreage of a crop, and whole-farm units cover all crops together.',
    CONSTRAINT pk_insurance_policy PRIMARY KEY(`insurance_policy_id`)
) COMMENT 'Master reference table for insurance_policy. Referenced by policy_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`insurance_claim` (
    `insurance_claim_id` BIGINT COMMENT 'Primary key for insurance_claim',
    `account_id` BIGINT COMMENT 'Reference to the party who holds the insurance policy and is filing or associated with this claim.',
    `alert_id` BIGINT COMMENT 'Reference to the specific weather event that caused or contributed to the loss, linking to meteorological records for validation and documentation.',
    `employee_id` BIGINT COMMENT 'Reference to the insurance adjuster assigned to evaluate and process this claim.',
    `field_id` BIGINT COMMENT 'Reference to the specific agricultural field or location where the loss occurred.',
    `insurance_policy_id` BIGINT COMMENT 'Reference to the insurance policy under which this claim is filed.',
    `parent_insurance_claim_id` BIGINT COMMENT 'Self-referencing FK on insurance_claim (parent_insurance_claim_id)',
    `acres_affected` DECIMAL(18,2) COMMENT 'The total acreage of farmland affected by the loss event. Measured in acres.',
    `approval_date` DATE COMMENT 'The date on which the claim was approved for payout by the underwriting team.',
    `approved_claim_amount` DECIMAL(18,2) COMMENT 'The final approved claim payout amount after underwriting review and policy coverage calculations. Measured in USD.',
    `assessed_loss_amount` DECIMAL(18,2) COMMENT 'The loss amount determined by the insurance adjuster after field inspection and evaluation. Measured in USD.',
    `claim_number` STRING COMMENT 'Externally-known unique claim number assigned by the insurance carrier or internal system for tracking and reference purposes.',
    `claim_status` STRING COMMENT 'Current lifecycle status of the insurance claim indicating its position in the claims processing workflow.',
    `claim_type` STRING COMMENT 'Classification of the insurance claim based on the nature of the loss or damage being claimed.',
    `closed_date` DATE COMMENT 'The date on which the claim was officially closed and no further action is required.',
    `coverage_level` DECIMAL(18,2) COMMENT 'The coverage level percentage selected by the policyholder under the insurance policy (e.g., 50%, 65%, 75%, 85%). Measured as a percentage.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this claim record was first created in the system. Follows format yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `crop_type` STRING COMMENT 'The type of crop affected by the loss event (e.g., corn, soybeans, wheat, cotton). Applicable for crop loss claims.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts in this claim (e.g., USD, CAD, EUR).',
    `deductible_amount` DECIMAL(18,2) COMMENT 'The deductible amount applied to this claim per the policy terms. Measured in USD.',
    `denial_reason` STRING COMMENT 'Explanation provided when a claim is denied, detailing the policy exclusions or conditions that led to the denial.',
    `estimated_loss_amount` DECIMAL(18,2) COMMENT 'The initial estimated monetary value of the loss as reported by the policyholder or agent. Measured in USD.',
    `filed_date` DATE COMMENT 'The date on which the formal claim documentation was filed with the insurance carrier.',
    `fraud_flag` BOOLEAN COMMENT 'Indicates whether this claim has been flagged for potential fraud investigation. True if flagged, False otherwise.',
    `inspection_date` DATE COMMENT 'The date on which the field inspection was conducted by the insurance adjuster.',
    `loss_cause` STRING COMMENT 'Detailed description of the cause of the loss (e.g., hail, drought, flood, frost, wind, disease, pest infestation).',
    `loss_date` DATE COMMENT 'The date on which the insured loss or damage event occurred. This is the principal business event timestamp for the claim.',
    `loss_description` STRING COMMENT 'Detailed narrative description of the loss event, damage sustained, and circumstances surrounding the claim.',
    `net_payout_amount` DECIMAL(18,2) COMMENT 'The net amount paid to the policyholder after deductibles and adjustments. Measured in USD.',
    `notes` STRING COMMENT 'Additional notes, comments, or observations recorded by adjusters, underwriters, or agents during the claim lifecycle.',
    `payment_date` DATE COMMENT 'The date on which the claim payout was issued to the policyholder.',
    `reinsurance_flag` BOOLEAN COMMENT 'Indicates whether this claim is subject to reinsurance arrangements. True if reinsurance applies, False otherwise.',
    `reported_date` DATE COMMENT 'The date on which the claim was first reported to the insurance carrier or agent.',
    `supporting_documentation` STRING COMMENT 'References to supporting documents submitted with the claim (e.g., photos, weather reports, yield records, receipts). Stored as file paths or document identifiers.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this claim record was last modified in the system. Follows format yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `yield_loss_percentage` DECIMAL(18,2) COMMENT 'The percentage of expected crop yield lost due to the insured event. Measured as a percentage (0-100).',
    CONSTRAINT pk_insurance_claim PRIMARY KEY(`insurance_claim_id`)
) COMMENT 'Master reference table for insurance_claim. Referenced by claim_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`sensor` (
    `sensor_id` BIGINT COMMENT 'Primary key for sensor',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or plot where the sensor is installed, linking sensor data to specific crop management zones.',
    `station_id` BIGINT COMMENT 'Reference to the weather station or field location where this sensor is deployed, enabling grouping of sensors by site.',
    `parent_sensor_id` BIGINT COMMENT 'Self-referencing FK on sensor (parent_sensor_id)',
    `accuracy_rating` DECIMAL(18,2) COMMENT 'Manufacturer-specified accuracy rating of the sensor expressed as a percentage or tolerance value, indicating the precision of measurements.',
    `calibration_interval_days` STRING COMMENT 'Number of days between required calibration services as specified by manufacturer recommendations or internal quality standards.',
    `communication_protocol` STRING COMMENT 'Network protocol or technology used by the sensor to transmit data to collection systems or gateways.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this sensor record was first created in the system, supporting audit trail and data lineage requirements.',
    `data_quality_score` DECIMAL(18,2) COMMENT 'Calculated score representing the overall quality and reliability of data produced by this sensor, based on completeness, accuracy, and consistency metrics.',
    `elevation_meters` DECIMAL(18,2) COMMENT 'Height above sea level in meters at which the sensor is installed, important for atmospheric pressure and temperature adjustments.',
    `firmware_version` STRING COMMENT 'Version number of the firmware software running on the sensor device, important for compatibility and security updates.',
    `health_status` STRING COMMENT 'Assessment of the sensors technical health based on diagnostic checks, data quality metrics, and performance indicators.',
    `installation_date` DATE COMMENT 'Date when the sensor was physically installed and deployed in the field or at the weather station location.',
    `installation_height_meters` DECIMAL(18,2) COMMENT 'Height in meters above ground level at which the sensor is mounted, relevant for wind speed, temperature, and other measurements that vary with height.',
    `is_active` BOOLEAN COMMENT 'Boolean flag indicating whether the sensor is currently active and should be included in data collection and monitoring processes.',
    `last_calibration_date` DATE COMMENT 'Date when the sensor was last calibrated to ensure measurement accuracy and compliance with quality standards.',
    `last_maintenance_date` DATE COMMENT 'Date when the sensor last received maintenance service such as cleaning, battery replacement, or physical inspection.',
    `last_reading_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent data reading received from the sensor, used to monitor sensor connectivity and operational status.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the sensor installation location in decimal degrees, used for spatial analysis and weather mapping.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the sensor installation location in decimal degrees, used for spatial analysis and weather mapping.',
    `manufacturer` STRING COMMENT 'Name of the company or organization that manufactured the sensor device.',
    `measurement_range_max` DECIMAL(18,2) COMMENT 'Maximum value that the sensor is capable of measuring within its operational specifications.',
    `measurement_range_min` DECIMAL(18,2) COMMENT 'Minimum value that the sensor is capable of measuring within its operational specifications.',
    `measurement_unit` STRING COMMENT 'Unit of measure in which the sensor reports its readings, such as Celsius for temperature, percent for humidity, or millimeters for precipitation.',
    `model_number` STRING COMMENT 'Manufacturer-assigned model number or designation for the sensor device, used for technical specifications and maintenance reference.',
    `next_calibration_date` DATE COMMENT 'Scheduled date for the next calibration service to maintain sensor accuracy and operational reliability.',
    `next_maintenance_date` DATE COMMENT 'Scheduled date for the next preventive maintenance service to ensure continued sensor reliability and data quality.',
    `notes` STRING COMMENT 'Free-text field for recording additional information about the sensor such as installation conditions, known issues, or special configuration details.',
    `operational_status` STRING COMMENT 'Current operational state of the sensor indicating whether it is actively collecting data, under maintenance, experiencing faults, or has been retired from service.',
    `power_source` STRING COMMENT 'Type of power supply used to operate the sensor device, such as battery, solar panel, or alternating current.',
    `sampling_frequency_seconds` STRING COMMENT 'Interval in seconds at which the sensor collects and reports measurements. Lower values indicate more frequent data collection.',
    `sensor_code` STRING COMMENT 'Externally-known unique alphanumeric code or serial number assigned to the sensor device by the manufacturer or deployment system.',
    `sensor_name` STRING COMMENT 'Human-readable name or label assigned to the sensor for identification purposes in field operations and monitoring dashboards.',
    `sensor_type` STRING COMMENT 'Classification of the sensor based on the meteorological or environmental parameter it measures. Determines the type of data collected and its application in agricultural decision-making.',
    `serial_number` STRING COMMENT 'Unique serial number assigned by the manufacturer to this specific sensor unit for warranty, support, and traceability purposes.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this sensor record was last modified, supporting change tracking and audit requirements.',
    `warranty_expiration_date` DATE COMMENT 'Date when the manufacturer warranty coverage for the sensor device expires.',
    CONSTRAINT pk_sensor PRIMARY KEY(`sensor_id`)
) COMMENT 'Master reference table for sensor. Referenced by sensor_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`calibration_standard` (
    `calibration_standard_id` BIGINT COMMENT 'Primary key for calibration_standard',
    `parent_calibration_standard_id` BIGINT COMMENT 'Self-referencing FK on calibration_standard (parent_calibration_standard_id)',
    `accuracy_tolerance` DECIMAL(18,2) COMMENT 'The maximum permissible deviation from the reference value, expressed in the same unit of measure. Defines the acceptable calibration error range.',
    `acquisition_cost` DECIMAL(18,2) COMMENT 'The purchase price or acquisition cost of the calibration standard in the organizations base currency. Used for asset valuation and budget planning.',
    `acquisition_date` DATE COMMENT 'The date on which the calibration standard was acquired or purchased by the organization. Used for asset management and depreciation tracking.',
    `applicable_sensor_types` STRING COMMENT 'List of sensor types and models that can be calibrated using this standard, such as thermocouples, resistance temperature detectors, capacitive humidity sensors, or tipping bucket rain gauges.',
    `certificate_number` STRING COMMENT 'Unique identifier of the calibration certificate issued by the certifying authority. Used for audit and compliance verification.',
    `certification_date` DATE COMMENT 'The date on which the calibration standard was certified by the certifying authority. Marks the beginning of the standards validity period.',
    `certifying_authority` STRING COMMENT 'The name of the accredited laboratory, national metrology institute, or certification body that issued the calibration certificate for this standard.',
    `compliance_notes` STRING COMMENT 'Additional notes regarding regulatory compliance, special handling requirements, or deviations from standard procedures relevant to this calibration standard.',
    `confidence_level_percent` DECIMAL(18,2) COMMENT 'The statistical confidence level associated with the uncertainty value, typically expressed as a percentage such as 95% or 99%.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this calibration standard record was first created in the system. Used for audit trail and data lineage.',
    `custodian_name` STRING COMMENT 'Name of the person or department responsible for the custody, maintenance, and proper use of this calibration standard.',
    `expiration_date` DATE COMMENT 'The date on which the calibration certificate expires and the standard must be recertified or retired from use. Critical for maintaining calibration validity.',
    `is_primary_standard` BOOLEAN COMMENT 'Boolean flag indicating whether this is a primary calibration standard with direct traceability to national standards, or a secondary/working standard derived from a primary standard.',
    `last_verification_date` DATE COMMENT 'The most recent date on which the calibration standard was verified or checked for continued accuracy and compliance with specifications.',
    `location_code` STRING COMMENT 'Code identifying the physical location where the calibration standard is stored, such as a laboratory, field station, or calibration facility identifier.',
    `manufacturer_name` STRING COMMENT 'The name of the company or organization that manufactured the calibration standard device or reference material.',
    `measurement_parameter` STRING COMMENT 'Specific meteorological or environmental parameter that this standard is designed to measure or calibrate, such as air temperature, relative humidity, barometric pressure, or rainfall intensity.',
    `model_number` STRING COMMENT 'The manufacturers model or part number for the calibration standard. Used for procurement, maintenance, and replacement planning.',
    `modified_timestamp` TIMESTAMP COMMENT 'The date and time when this calibration standard record was last modified. Used for audit trail and change tracking.',
    `next_verification_due_date` DATE COMMENT 'The scheduled date for the next verification or recalibration of the standard. Used for maintenance planning and compliance tracking.',
    `operating_range_max` DECIMAL(18,2) COMMENT 'The maximum value of the measurement range over which this calibration standard is valid and accurate, expressed in the unit of measure.',
    `operating_range_min` DECIMAL(18,2) COMMENT 'The minimum value of the measurement range over which this calibration standard is valid and accurate, expressed in the unit of measure.',
    `recalibration_interval_days` STRING COMMENT 'The recommended number of days between recalibrations to maintain the standards accuracy and traceability. Typically ranges from 180 to 730 days depending on standard type and usage.',
    `reference_value` DECIMAL(18,2) COMMENT 'The certified reference value of the calibration standard. This is the known, traceable value against which field sensors and equipment are calibrated.',
    `serial_number` STRING COMMENT 'Unique serial number assigned by the manufacturer to this specific calibration standard unit. Enables individual asset tracking and history.',
    `standard_code` STRING COMMENT 'Externally-known unique code identifying this calibration standard in laboratory and field systems. Used for traceability and reference in calibration procedures.',
    `standard_name` STRING COMMENT 'Human-readable name of the calibration standard used for sensor and equipment calibration in agricultural weather monitoring systems.',
    `standard_status` STRING COMMENT 'Current lifecycle status of the calibration standard indicating whether it is available for use, expired and awaiting recalibration, retired from service, or temporarily suspended.',
    `standard_type` STRING COMMENT 'Category of calibration standard indicating which meteorological parameter it is designed to calibrate. Determines applicability to specific sensor types.',
    `storage_conditions` STRING COMMENT 'Required environmental conditions for proper storage of the calibration standard when not in use, including temperature range, humidity limits, and protection requirements.',
    `traceability_chain` STRING COMMENT 'Documentation of the unbroken chain of calibrations linking this standard to national or international measurement standards, ensuring metrological traceability.',
    `uncertainty_value` DECIMAL(18,2) COMMENT 'The quantified uncertainty associated with the reference value, representing the range within which the true value is expected to lie with a specified confidence level.',
    `unit_of_measure` STRING COMMENT 'The unit in which the reference value is expressed, such as degrees Celsius, percent relative humidity, millibars, meters per second, or millimeters.',
    `usage_instructions` STRING COMMENT 'Detailed instructions for proper use of the calibration standard in field and laboratory calibration procedures, including setup, stabilization time, and handling precautions.',
    CONSTRAINT pk_calibration_standard PRIMARY KEY(`calibration_standard_id`)
) COMMENT 'Master reference table for calibration_standard. Referenced by reference_standard_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`weather`.`station_network` (
    `station_network_id` BIGINT COMMENT 'Primary key for station_network',
    `parent_station_network_id` BIGINT COMMENT 'Self-referencing FK on station_network (parent_station_network_id)',
    `annual_subscription_cost` DECIMAL(18,2) COMMENT 'Annual cost in USD for accessing data from this commercial weather network. Null for free government or cooperative networks. Used for cost allocation and vendor performance analysis.',
    `api_endpoint_url` STRING COMMENT 'Base URL for the networks data API endpoint. Used by integration services to retrieve weather data programmatically. Confidential to prevent unauthorized access.',
    `authentication_method` STRING COMMENT 'Security authentication mechanism required to access the networks data feed. API Key for token-based access; OAuth for delegated authorization; Basic Auth for username/password; Certificate for mutual TLS; None for public data sources.',
    `calibration_frequency_days` STRING COMMENT 'Standard interval in days between equipment calibration cycles for stations in this network. Critical for maintaining measurement accuracy for precision agriculture applications.',
    `contract_end_date` DATE COMMENT 'Date when the data subscription or partnership agreement with this network provider expires. Null for perpetual or government data sources. Critical for vendor management and budget planning.',
    `contract_start_date` DATE COMMENT 'Date when the data subscription or partnership agreement with this network provider became effective. Applicable for commercial weather data services like DTN.',
    `coverage_region` STRING COMMENT 'Geographic region or territory covered by the station network. May be global, national, state-level, or localized to specific agricultural zones.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this station network record was first created in the system. Used for data lineage and audit trail purposes.',
    `data_feed_protocol` STRING COMMENT 'Technical protocol used to receive weather data from the network. API for RESTful services; FTP for batch file transfers; MQTT for IoT sensor streams; HTTP for web services; WebSocket for real-time streaming; proprietary for vendor-specific formats.',
    `data_format` STRING COMMENT 'File or message format used by the network to deliver weather data. JSON and XML for web services; CSV for tabular data; GRIB and NetCDF for gridded meteorological data; Proprietary for vendor-specific formats requiring custom parsers.',
    `data_latency_minutes` STRING COMMENT 'Average time delay between observation collection at the station and data availability in the feed, measured in minutes. Critical for time-sensitive agricultural decisions like spray window timing.',
    `data_parameters_available` STRING COMMENT 'Comma-separated list of weather parameters provided by this network (e.g., temperature,precipitation,humidity,wind_speed,solar_radiation,soil_moisture,evapotranspiration). Defines the analytical capabilities supported by this network.',
    `data_update_frequency_minutes` STRING COMMENT 'Frequency at which the network publishes updated weather observations, measured in minutes. Typical values: 5 minutes for real-time IoT sensors, 15 minutes for automated stations, 60 minutes for manual observations.',
    `documentation_url` STRING COMMENT 'Web URL pointing to the networks technical documentation, API specifications, and data dictionaries. Essential reference for data integration and interpretation.',
    `forecast_horizon_days` STRING COMMENT 'Maximum number of days into the future for which forecast data is available from this network. Typical values: 7-10 days for operational forecasts, 14-16 days for extended outlooks. Null if network does not provide forecasts.',
    `historical_data_start_date` DATE COMMENT 'Earliest date for which historical weather observations are available from this network. Important for climate analysis, growing degree day (GDD) calculations, and multi-year trend analysis.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this station network record was last updated. Used for change tracking and data synchronization across systems.',
    `measurement_units_system` STRING COMMENT 'Standard system of measurement used by the network for reporting weather data. Metric uses Celsius, millimeters, meters per second; Imperial uses Fahrenheit, inches, miles per hour; Mixed uses combination based on parameter type.',
    `network_code` STRING COMMENT 'Unique alphanumeric code identifying the weather station network. Used for external references and integrations with DTN, Climate FieldView, and other weather data providers.',
    `network_name` STRING COMMENT 'Full business name of the weather station network (e.g., National Weather Service ASOS, DTN Agricultural Network, Climate FieldView Station Grid).',
    `network_status` STRING COMMENT 'Current operational status of the weather station network. Active networks provide real-time data feeds; inactive networks are temporarily offline; suspended networks have data quality issues; decommissioned networks are permanently retired; pilot networks are in testing phase.',
    `network_type` STRING COMMENT 'Classification of the station network by ownership and operational model. Government networks include NWS, NOAA; commercial includes DTN, Weather Underground; cooperative includes CoCoRaHS; private includes on-farm IoT sensor networks; research includes university agricultural research stations.',
    `notes` STRING COMMENT 'Free-text field for additional information about the network, including special configuration details, known data quality issues, integration challenges, or operational notes for data engineering teams.',
    `operator_organization` STRING COMMENT 'Name of the organization that owns and operates the weather station network (e.g., National Oceanic and Atmospheric Administration, DTN LLC, Climate Corporation, Iowa State University).',
    `primary_contact_email` STRING COMMENT 'Email address of the primary contact at the network operator organization. Used for technical support requests and service notifications.',
    `primary_contact_name` STRING COMMENT 'Name of the primary technical or account contact at the network operator organization. Used for issue escalation, contract renewals, and technical support.',
    `primary_contact_phone` STRING COMMENT 'Phone number of the primary contact at the network operator organization. Used for urgent technical issues and service outages.',
    `primary_country_code` STRING COMMENT 'Three-letter ISO country code representing the primary country of operation for the network (e.g., USA, CAN, BRA, ARG).',
    `quality_assurance_level` STRING COMMENT 'Level of data quality control and validation applied by the network. Basic includes automated range checks; Standard adds cross-validation with nearby stations; Enhanced includes manual review and correction; Research Grade meets scientific publication standards.',
    `reliability_score` DECIMAL(18,2) COMMENT 'Calculated reliability metric (0-100) based on data availability, uptime, and quality over the past 12 months. Used for vendor performance evaluation and data source prioritization in multi-network environments.',
    `spatial_resolution_km` DECIMAL(18,2) COMMENT 'Average distance in kilometers between stations in the network, representing the spatial granularity of coverage. Lower values indicate denser station placement and more localized weather data. Critical for field-level precision agriculture.',
    `station_count` STRING COMMENT 'Total number of active weather stations currently operating within this network. Updated periodically as stations are added or decommissioned.',
    `supports_alerts` BOOLEAN COMMENT 'Indicates whether the network provides automated weather alerts and warnings (e.g., frost alerts, severe weather warnings, spray window notifications). Critical for risk management and operational decision support.',
    `supports_forecast_data` BOOLEAN COMMENT 'Indicates whether the network provides forecast data in addition to historical and real-time observations. True for networks like DTN and NOAA that include predictive models; False for observation-only networks.',
    `terms_of_use_url` STRING COMMENT 'Web URL pointing to the legal terms of use, licensing restrictions, and data redistribution policies for the networks data. Critical for compliance with data usage agreements.',
    CONSTRAINT pk_station_network PRIMARY KEY(`station_network_id`)
